INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure環境を管理しています。デプロイしたAzureリソースに部門名を追加して、リソースの管理を容易にしたいと考えています。どの機能を使用すべきですか？', '["A. タグ", "B. 管理グループ", "C. リソースグループ", "D. サブスクリプション"]'::jsonb, '0'::jsonb, 'タグはAzureリソースにメタデータ（キーと値のペア）を付与し、部門名やコストセンターなどの情報を追加できます。管理グループはサブスクリプションの階層管理に使用され、リソース単位の情報付与には適しません。リソースグループはリソースの論理的なグループ化であり、部門名のような柔軟なメタデータの付与はできません。サブスクリプションは課金単位であり、個別リソースへの情報付与には使用しません。', 'governance', ARRAY['resource-hierarchy','management-groups','subscription-design','tagging'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは300台のWindows Server 2022のシステムログを一元的に監視する必要があります。Azure Monitorエージェントをインストールすることで、この要件を満たすことができますか？', '["A. はい", "B. いいえ"]'::jsonb, '0'::jsonb, 'Azure Monitorエージェント（AMA）は、Windows/Linuxサーバーからログやパフォーマンスデータを収集し、Log Analyticsワークスペースに送信できます。データ収集ルール（DCR）を使用して、収集するログの種類を柔軟に設定でき、300台のサーバーのシステムログを一元監視する要件を満たせます。', 'monitoring', ARRAY['azure-monitor','log-analytics'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Monitor ログを使用してLinuxサーバーのログを分析しています。1日あたり約120GBのログが取り込まれており、コストを最小限に抑える必要があります。どのような変更を行うべきですか？', '["A. 基本ログに変更する", "B. 分析ログのままにする", "C. ログの保持期間を短縮する", "D. ワークスペースを分割する"]'::jsonb, '0'::jsonb, '基本ログ（Basic Logs）は、分析ログ（Analytics Logs）と比較して取り込みコストが大幅に安くなります（約半額）。大量のログデータを取り込むが高度な分析が不要な場合、基本ログに変更することでコストを最小限に抑えられます。ただし、基本ログはKQLクエリの機能が一部制限され、クエリ実行時に追加料金が発生します。保持期間の短縮やワークスペース分割はコスト削減効果が限定的です。', 'monitoring', ARRAY['azure-monitor','log-analytics'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure VM内のデータをLog Analyticsに転送し、転送時にログを変換する必要があります。ログの転送先とログの変換方法として正しい組み合わせはどれですか？', '["A. ログ転送: データ収集エンドポイント、ログ変換: KQLクエリ", "B. ログ転送: Azure Event Hubs、ログ変換: Azure Functions", "C. ログ転送: ストレージアカウント、ログ変換: Logic Apps", "D. ログ転送: Azure Monitor API、ログ変換: PowerShellスクリプト"]'::jsonb, '0'::jsonb, 'データ収集ルール（DCR）ではデータ収集エンドポイント（DCE）を使用してログを転送し、KQLクエリによるインジェスト時変換が可能です。これにより、Log Analyticsに取り込む前にデータのフィルタリングや変換を行えます。Event HubsやストレージアカウントはLog Analyticsへの直接転送には使用しません。Azure FunctionsやLogic Appsはログ変換には過剰な構成です。', 'monitoring', ARRAY['azure-monitor','log-analytics','azure-storage','azure-functions','event-driven','api-management'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Monitor ログにおいて、WindowsイベントログとLinux Syslogのデータが格納されるテーブル名の組み合わせとして正しいものはどれですか？', '["A. WindowsイベントログのテーブルはEvent、Linux SyslogのテーブルはSyslog", "B. WindowsイベントログのテーブルはWindowsEvent、Linux SyslogのテーブルはLinuxSyslog", "C. WindowsイベントログのテーブルはSecurityEvent、Linux SyslogのテーブルはSyslogData", "D. WindowsイベントログのテーブルはEventLog、Linux SyslogのテーブルはSyslogMessages"]'::jsonb, '0'::jsonb, 'Log Analyticsワークスペースにおいて、WindowsイベントログはEventテーブルに、Linux SyslogはSyslogテーブルに格納されます。SecurityEventはセキュリティイベント専用のテーブルです。WindowsEventやLinuxSyslogなどのテーブル名は存在しません。', 'monitoring', ARRAY['azure-monitor','log-analytics','event-driven'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzureサブスクリプションを監視しています。Network Insights、Application Insights、VM Insightsのすべてを使用する場合、必要なLog Analyticsワークスペースの最小数はいくつですか？', '["A. 1", "B. 2", "C. 3", "D. 4"]'::jsonb, '0'::jsonb, 'Network Insights、Application Insights、VM Insightsはすべて同じLog Analyticsワークスペースを共有できます。そのため、必要なワークスペースの最小数は1つです。複数のInsightsソリューションを1つのワークスペースに統合することで、データの相関分析が容易になり、管理コストも削減できます。', 'monitoring', ARRAY['subscription-design','azure-monitor','log-analytics','app-insights','monitor-insights'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzureサブスクリプション内のリソース一覧を月次レポートとして作成する必要があります。どのサービスの組み合わせを使用すべきですか？', '["A. Azure Resource Graph、Azure Functions", "B. アクティビティログ、Log Analyticsワークスペース", "C. Azure Advisor、ストレージアカウント", "D. Azure Monitor メトリック、Azure Dashboard"]'::jsonb, '1'::jsonb, 'アクティビティログはサブスクリプション内のリソース操作（作成・変更・削除）を記録します。Log Analyticsワークスペースにアクティビティログを送信することで、KQLクエリを使用して月次レポートに必要なデータを集計・分析できます。Resource Graphはリアルタイムのリソース照会に適していますが、履歴データの分析には向きません。Azure Advisorは推奨事項の提供であり、リソース一覧の作成には適しません。', 'monitoring', ARRAY['subscription-design','azure-monitor','log-analytics','activity-log','azure-storage','azure-functions'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Cost Managementを使用して、部門ごとのコストを監視したいと考えています。どの機能を使用すべきですか？', '["A. 管理グループ", "B. リソースグループ", "C. リソースのタグ", "D. サブスクリプション"]'::jsonb, '2'::jsonb, 'リソースのタグ（例：Department: Sales）を使用することで、Cost Managementでタグごとにコストをフィルタリング・分析できます。部門ごとのコスト配分を柔軟に実現できます。管理グループやサブスクリプションは組織階層の管理には使えますが、部門横断的なリソースがある場合は柔軟性に欠けます。リソースグループは論理的なグループ化ですが、1つのリソースは1つのRGにしか属せないため、部門ごとのコスト配分には不十分です。', 'governance', ARRAY['resource-hierarchy','management-groups','subscription-design','tagging','azure-monitor','cost-management'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはNSG（ネットワークセキュリティグループ）の診断データを収集する設定を行っています。ストレージアカウントに保持される期間とLog Analyticsに保持される最大期間の組み合わせとして正しいものはどれですか？', '["A. ストレージアカウント: 30日、Log Analytics: 365日", "B. ストレージアカウント: 90日、Log Analytics: 730日", "C. ストレージアカウント: 180日、Log Analytics: 365日", "D. ストレージアカウント: 365日、Log Analytics: 730日"]'::jsonb, '1'::jsonb, 'NSGフローログの診断データは、ストレージアカウントにデフォルトで最大90日間保持されます。Log Analyticsワークスペースでは最大730日（2年）間データを保持できます。これらの保持期間を理解することは、コンプライアンス要件やコスト管理において重要です。', 'monitoring', ARRAY['purview','log-analytics','cost-management','azure-storage','network-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは社員向けアプリケーションにSSOを実装する必要があります。アプリケーションは独自のHTMLログインページを持ち、パスワードによる認証を使用しています。どのSSO方式を使用すべきですか？', '["A. SAML", "B. パスワードベース", "C. リンクされたSSO", "D. 統合Windows認証"]'::jsonb, '1'::jsonb, 'パスワードベースSSOは、独自のHTMLログインページを持つアプリケーションに適しています。Microsoft Entra IDがユーザーの資格情報を安全に保存し、ログインページに自動的に入力します。SAMLはSAMLプロトコルをサポートするアプリケーション向けであり、独自HTMLページには対応しません。リンクされたSSOは既存のSSO実装がある場合に使用します。統合Windows認証はオンプレミスのKerberos認証環境向けです。', 'identity', ARRAY['entra-id','sso'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはオンプレミスのWebアプリケーションを外部ユーザーに公開する必要があります。VPN接続は不要で、DMZ（非武装地帯）の構築も避けたいと考えています。どのサービスを使用すべきですか？', '["A. Azure Front Door", "B. Azure Application Gateway", "C. Azure VPN Gateway", "D. Microsoft Entra アプリケーションプロキシ"]'::jsonb, '3'::jsonb, 'Microsoft Entraアプリケーションプロキシは、オンプレミスのWebアプリケーションをVPNやDMZなしで外部に安全に公開できます。軽量なコネクタをオンプレミスにインストールするだけで、Microsoft Entra IDによる認証と条件付きアクセスを適用できます。Front DoorやApplication Gatewayはクラウド上のアプリケーション向けです。VPN Gatewayは外部公開ではなくプライベート接続に使用します。', 'identity', ARRAY['entra-id','external-users','app-proxy','conditional-access','load-balancers','on-premises-connectivity'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Microsoft Entra IDのアクセスレビューに関して、以下の記述のうち正しいものの組み合わせはどれですか？
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure RBACのロール継承に関して、管理グループにOwnerロールを割り当てた場合、その配下のサブスクリプションとリソースグループにも同じロールが継承されますか？', '["A. はい、サブスクリプションとリソースグループの両方に継承される", "B. サブスクリプションのみに継承され、リソースグループには継承されない", "C. リソースグループのみに継承され、サブスクリプションには継承されない", "D. どちらにも継承されない"]'::jsonb, '0'::jsonb, 'Azure RBACでは、上位スコープで割り当てたロールは下位のすべてのスコープに継承されます。管理グループにOwnerロールを割り当てると、その配下のすべてのサブスクリプション、リソースグループ、および個々のリソースにOwner権限が継承されます。これはRBACの基本的な継承モデルです。', 'governance', ARRAY['rbac','resource-hierarchy','management-groups','subscription-design'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzureサブスクリプションとMicrosoft Entraテナントの関連付けを変更する必要があります。この操作を実行するために必要な最小権限のロールはどれですか？', '["A. 所有者（Owner）", "B. 共同作成者（Contributor）", "C. ユーザーアクセス管理者", "D. 全体管理者"]'::jsonb, '0'::jsonb, 'サブスクリプションのディレクトリ（Entraテナント）変更には、サブスクリプションの所有者（Owner）ロールが必要です。共同作成者はリソースの管理はできますが、サブスクリプション自体のディレクトリ変更はできません。ユーザーアクセス管理者はロール割り当ての管理のみです。全体管理者はEntra IDの管理者であり、サブスクリプションレベルの操作には直接的な権限を持ちません。', 'governance', ARRAY['entra-id','rbac','subscription-design'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは経理部のユーザーのパスワードリセットを管理するため、管理単位「Accounting」を作成しました。User1に最小権限でAccountingのパスワードリセット権限を付与するには、どの操作を行うべきですか？', '["A. テナント全体のヘルプデスク管理者ロールにUser1を追加する", "B. テナント全体のパスワード管理者ロールにUser1を追加する", "C. Accounting管理単位のパスワード管理者ロールにUser1を追加する", "D. Accounting管理単位のヘルプデスク管理者ロールにUser1を追加する"]'::jsonb, '3'::jsonb, '管理単位（Administrative Unit）を使用すると、特定のユーザーグループに対してのみ管理権限を付与できます。ヘルプデスク管理者ロールにはパスワードリセットの権限が含まれており、Accounting管理単位に限定して割り当てることで最小権限の原則を満たせます。テナント全体のロールは権限が広すぎます。パスワード管理者もパスワードリセットは可能ですが、ヘルプデスク管理者の方がより制限された権限であり、最小権限の原則に合致します。', 'identity', ARRAY['entra-id','rbac','admin-units'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは2つのAzureサブスクリプションを管理しています。Sub1はcontoso.comテナント、Sub2はfabrikam.comテナントに関連付けられています。fabrikam.comのユーザーにSub1のApp Serviceへのアクセスを許可するには、どうすべきですか？', '["A. fabrikam.comのユーザーをcontoso.comに同期する", "B. fabrikam.comのユーザーをcontoso.comにゲストユーザーとして招待する", "C. Sub2をcontoso.comテナントに移動する", "D. 両テナント間にVNet ピアリングを構成する"]'::jsonb, '1'::jsonb, 'Microsoft Entra B2Bコラボレーションを使用して、fabrikam.comのユーザーをcontoso.comテナントにゲストユーザーとして招待できます。招待されたユーザーは自身の資格情報でサインインし、contoso.comのリソースにアクセスできます。同期は異なるテナント間では直接できません。サブスクリプションの移動は大規模な変更であり、最小限の変更ではありません。VNetピアリングはネットワーク接続であり、認証・認可の問題は解決しません。', 'identity', ARRAY['entra-id','external-users','entra-connect','subscription-design','app-service','vnet'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは5つのAzureサブスクリプション（それぞれ異なるEntraテナントに関連付け）のWindows VMからイベントログを収集する必要があります。データ収集ルール（DCR）を使用します。イベントログの転送、DCRの実行、複数テナントのデータ収集に適したサービスの組み合わせはどれですか？', '["A. イベントログ: Azure Storage、DCR: Log Analytics エージェント、複数テナント: Azure Arc", "B. イベントログ: Azure Event Hubs、DCR: Azure Monitorエージェント、複数テナント: Azure Lighthouse", "C. イベントログ: Log Analytics直接取込、DCR: Azure Functions、複数テナント: Azure AD B2B", "D. イベントログ: Azure Storage、DCR: Azure Monitorエージェント、複数テナント: 管理グループ"]'::jsonb, '1'::jsonb, 'Azure Event Hubsは大規模なイベントログの転送に適しています。Azure Monitorエージェント（AMA）はDCRを使用してデータ収集を実行する新しいエージェントです。Azure Lighthouseは複数テナントのリソースを一元管理でき、異なるテナントのサブスクリプションを横断してデータ収集が可能です。Log AnalyticsエージェントはレガシーでありDCRをサポートしません。管理グループは単一テナント内の管理階層です。', 'monitoring', ARRAY['entra-id','external-users','lighthouse','resource-hierarchy','management-groups','subscription-design','azure-monitor','log-analytics','azure-functions','event-driven'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは全体管理者がAzureポータルにアクセスする際にMFA（多要素認証）を必須にする必要があります。どの機能を使用すべきですか？', '["A. セキュリティの既定値群", "B. 条件付きアクセス", "C. Microsoft Entra ID Protection", "D. ユーザーごとのMFA"]'::jsonb, '1'::jsonb, '条件付きアクセスポリシーを使用すると、特定のロール（全体管理者）がAzureポータルにアクセスする際にMFAを要求する条件を設定できます。セキュリティの既定値群はすべてのユーザーにMFAを要求しますが、全体管理者のみに限定できません。ID Protectionはリスクベースの条件付きアクセスであり、常にMFAを要求する設定には適しません。ユーザーごとのMFAは旧式の方法であり、条件（ポータルアクセス時のみ）の設定ができません。', 'identity', ARRAY['entra-id','auth-methods','rbac','conditional-access'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Key Vaultを管理しています。開発者に一時的なKey Vaultへのアクセス権を付与し、使用後に自動的に権限を失効させたいと考えています。どの機能を使用すべきですか？', '["A. アクセスレビュー", "B. 条件付きアクセス", "C. マネージドID", "D. Microsoft Entra PIM（Privileged Identity Management）"]'::jsonb, '3'::jsonb, 'Microsoft Entra PIM（Privileged Identity Management）を使用すると、ジャストインタイム（JIT）アクセスとして、一時的な権限の付与と自動失効を実現できます。開発者は必要な時にアクセス権をアクティブ化し、設定された期間後に自動的に失効します。アクセスレビューは定期的なレビューであり、一時的なアクセス管理には適しません。条件付きアクセスはアクセス条件の制御であり、一時的な権限付与ではありません。マネージドIDはアプリケーション向けの機能です。', 'identity', ARRAY['entra-governance','conditional-access','pim','managed-identity','key-vault'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure BlobストレージにアクセスするアプリケーションにSAS（Shared Access Signature）を使用しています。共有キーの使用を禁止し、時間制限を設け、最大のセキュリティを確保する必要があります。どの種類のSASを使用すべきですか？', '["A. サービスSAS", "B. アカウントSAS", "C. ユーザー委任SAS", "D. ストレージアクセスキー"]'::jsonb, '2'::jsonb, 'ユーザー委任SASは、Microsoft Entra IDの資格情報で署名されるため、ストレージアカウントの共有キーを使用しません。時間制限の設定が可能で、最も安全なSASの種類です。サービスSASとアカウントSASはストレージアカウントキーで署名されるため、共有キー禁止の要件を満たしません。ストレージアクセスキーは直接的なアクセス方法であり、SASではありません。', 'identity', ARRAY['entra-id','access-keys','sas','azure-storage'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたのアプリケーションはAzure VM上で実行され、Azure SQL Databaseにアクセスする必要があります。コード内にIDや資格情報を保存せず、VMの増加時に管理を最小限にしたいと考えています。どの認証方式を使用すべきですか？', '["A. サービスプリンシパル", "B. 接続文字列", "C. ユーザー割り当てマネージドID", "D. システム割り当てマネージドID"]'::jsonb, '3'::jsonb, 'システム割り当てマネージドIDは、VMに自動的にIDが付与され、コード内に資格情報を保存する必要がありません。VMのライフサイクルに連動して自動的に作成・削除されるため、管理が最小限で済みます。サービスプリンシパルは資格情報の管理が必要です。接続文字列はコード内に記述する必要があります。ユーザー割り当てマネージドIDも資格情報不要ですが、VMが増加する際にシステム割り当ての方が個別管理の手間が少なくなります。', 'identity', ARRAY['auth-methods','app-registration','managed-identity','blob-storage','sql-database'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは複数のAzure VM上でアプリケーションを実行しており、すべてのVMからAzure SQL Databaseにアクセスする必要があります。コード内にIDを記述せず、効率的に管理したいと考えています。どの認証方式を使用すべきですか？', '["A. サービスプリンシパル", "B. 接続文字列", "C. ユーザー割り当てマネージドID", "D. システム割り当てマネージドID"]'::jsonb, '2'::jsonb, 'ユーザー割り当てマネージドIDは、複数のVMで共有できるスタンドアロンのIDです。1つのIDを作成して複数のVMに割り当てることで、SQL Databaseへのアクセス権を一元管理できます。システム割り当てマネージドIDはVM個別に付与されるため、複数VMでの共有管理にはユーザー割り当ての方が効率的です。サービスプリンシパルは資格情報の管理が必要で、接続文字列はコード内に記述が必要です。', 'identity', ARRAY['auth-methods','app-registration','managed-identity','sql-database'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Policyを割り当てることができるスコープはどれですか？（3つ選択）', '["A. サブスクリプション", "B. 管理グループ", "C. リソースグループ", "D. テナント", "E. 可用性ゾーン"]'::jsonb, '[0, 1, 2]'::jsonb, 'Azure Policyは、管理グループ、サブスクリプション、リソースグループの3つのスコープに割り当てることができます。テナントレベルでの直接的なPolicy割り当てはできません（管理グループを通じて間接的に適用）。可用性ゾーンはインフラストラクチャの概念であり、Policyのスコープではありません。', 'governance', ARRAY['entra-id','resource-hierarchy','management-groups','subscription-design','azure-policy','availability-zones'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは開発者がAzure VMを作成する際に、特定のリージョンとVMサイズに制限したいと考えています。複数のポリシーをまとめて適用するには、どの機能を使用すべきですか？', '["A. Azure Policy定義", "B. Azure Blueprint", "C. 管理グループ", "D. Azure Policyのイニシアチブ定義"]'::jsonb, '3'::jsonb, 'Azure Policyのイニシアチブ定義（ポリシーセット定義）を使用すると、複数のポリシー定義をグループ化して一括で割り当てることができます。リージョン制限とVMサイズ制限の2つのポリシーを1つのイニシアチブにまとめることで、効率的な管理が可能です。個別のPolicy定義では複数のポリシーをまとめられません。Blueprintは環境全体のテンプレートであり、この要件には過剰です。管理グループはスコープの管理であり、ポリシーのグループ化はできません。', 'governance', ARRAY['resource-hierarchy','management-groups','azure-policy','blueprints'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Policyを使用してタグ管理を自動化したいと考えています。新規リソースにリソースグループのタグを継承させ、既存リソースのタグも修正する必要があります。どの効果（effect）を使用すべきですか？', '["A. Deny", "B. Audit", "C. Append", "D. Modify"]'::jsonb, '3'::jsonb, 'Modify効果は、リソースの作成時または更新時にプロパティ（タグを含む）を追加・変更・削除できます。既存のリソースに対しても修復タスクを実行してタグを修正できます。Denyはリソースの作成を拒否するだけでタグの継承はできません。Auditは非準拠リソースの記録のみで修正はしません。AppendはIPルールなどの配列フィールドの追加に使用され、タグの管理にはModifyが推奨されます。', 'governance', ARRAY['azure-policy','tagging','automation-deploy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはアプリケーションで使用するAPIキーをAzure Key Vaultに安全に保管したいと考えています。どのKey Vaultオブジェクトの種類を使用すべきですか？', '["A. シークレット", "B. キー", "C. 証明書", "D. ストレージアカウントキー"]'::jsonb, '0'::jsonb, 'Key Vaultのシークレットは、APIキー、パスワード、接続文字列などのテキストベースの機密情報を安全に保存するために使用します。キー（Key）は暗号化操作（暗号化・復号化・署名・検証）に使用する暗号化キーです。証明書はTLS/SSL証明書の管理に使用します。ストレージアカウントキーはKey Vaultオブジェクトの種類ではなく、ストレージアカウントのアクセスキーです。', 'identity', ARRAY['access-keys','key-vault','azure-storage'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはPremiumアクセス層で最高のパフォーマンスと最高の冗長性を持つストレージアカウントを構成する必要があります。どのストレージアカウントの種類と冗長性オプションを選択すべきですか？', '["A. Premium BlockBlobStorage、LRS", "B. Premium BlockBlobStorage、ZRS", "C. Premium BlockBlobStorage、GRS", "D. General Purpose v2 Premium、RA-GRS"]'::jsonb, '1'::jsonb, 'Premiumストレージアカウントでは、冗長性オプションはLRSとZRSのみがサポートされます。GRSやRA-GRSはPremiumでは使用できません。最高の冗長性を実現するには、ZRS（ゾーン冗長ストレージ）を選択します。ZRSは3つの可用性ゾーンにデータをレプリケートし、LRS（単一データセンター内の3コピー）よりも高い冗長性を提供します。', 'data', ARRAY['azure-storage','blob-storage','availability-zones'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは10GBのデータを保存し、読み取りパフォーマンスを向上させながら、ストレージコストを最小化する必要があります。どのAzureサービスを使用すべきですか？', '["A. Azure Files Premium", "B. Azure Blob Storage", "C. Azure Managed Disks", "D. Azure Table Storage"]'::jsonb, '1'::jsonb, 'Azure Blob Storageは、非構造化データの保存に最適で、アクセス層（Hot/Cool/Cold/Archive）を選択することでストレージコストを最小化できます。10GBという比較的小さなデータ量に対して、読み取りパフォーマンスはHotアクセス層で十分に高速です。Azure Files Premiumはファイル共有向けでコストが高くなります。Managed Disksは仮想マシン用です。Table Storageは構造化データ向けです。', 'data', ARRAY['blob-storage','virtual-machines'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはグローバルに分散されたアプリケーションを構築しています。マルチリージョン書き込みと99.999%の可用性SLAが必要です。どのAzureサービスを使用すべきですか？', '["A. Azure SQL Database geo レプリケーション", "B. Azure Cosmos DB", "C. Azure Database for PostgreSQL Hyperscale", "D. Azure Cache for Redis"]'::jsonb, '1'::jsonb, 'Azure Cosmos DBは、マルチリージョン書き込み（マルチマスター）をサポートし、マルチリージョン構成で99.999%の可用性SLAを提供します。これはAzureサービスの中で最も高い可用性SLAです。Azure SQL Databaseのgeoレプリケーションは読み取りレプリカであり、マルチリージョン書き込みはサポートしません。PostgreSQL HyperscaleはCitusベースの分散DBですが、99.999%のSLAは提供しません。Redis Cacheはキャッシュサービスであり、永続データストアではありません。', 'data', ARRAY['sql-database','cosmosdb','bcdr-fundamentals','sql-ha','caching'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Cosmos DBでクエリのスケーリングを最適化する必要があります。クロスパーティションクエリを避け、効率的なデータアクセスを実現するために最も重要な設計要素はどれですか？', '["A. インデックスポリシー", "B. 整合性レベル", "C. パーティションキー", "D. スループット（RU/s）"]'::jsonb, '2'::jsonb, 'パーティションキーの適切な選択は、Cosmos DBのスケーリングにおいて最も重要な設計要素です。適切なパーティションキーを選択することで、データが均等に分散され、クロスパーティションクエリを避けることができます。インデックスポリシーはクエリパフォーマンスに影響しますが、スケーリングの基本ではありません。整合性レベルはデータの一貫性に関する設定です。スループットはパフォーマンスの割り当てであり、データ分散の設計ではありません。', 'data', ARRAY['cosmosdb','cosmosdb-params'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure SQLの展開オプションを検討しています。複数のデータベース間でクエリを実行する必要がある場合、どのオプションを選択すべきですか？', '["A. Azure SQL Database 単一データベース", "B. Azure SQL Database エラスティックプール", "C. Azure SQL Managed Instance", "D. Azure SQL Database サーバーレス"]'::jsonb, '2'::jsonb, 'Azure SQL Managed Instance（MI）は、クロスデータベースクエリをサポートしています。複数のデータベース間でJOINやトランザクションを実行できます。Azure SQL Database（単一DB、エラスティックプール、サーバーレス）ではクロスデータベースクエリはサポートされていません（エラスティッククエリという機能で限定的な読み取りは可能）。MIはSQL Serverとの高い互換性を持ち、オンプレミスからの移行にも適しています。', 'data', ARRAY['sql-database','azure-functions','data-migration'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはデータウェアハウスとOLAP（オンライン分析処理）を実装する必要があります。大量の構造化データに対して複雑な分析クエリを実行します。どのサービスを使用すべきですか？', '["A. Azure SQL Database", "B. Azure Synapse Analytics 専用SQLプール", "C. Azure Cosmos DB", "D. Azure Database for PostgreSQL"]'::jsonb, '1'::jsonb, 'Azure Synapse Analytics 専用SQLプールは、超並列処理（MPP）アーキテクチャを使用したエンタープライズデータウェアハウスです。大量のデータに対するOLAPクエリに最適化されており、列ストア圧縮やパーティション分割によって高速な分析を実現します。Azure SQL DatabaseはOLTPに適しており、大規模なOLAPには向きません。Cosmos DBはNoSQLデータベースです。PostgreSQLは汎用RDBMSですが、大規模DWHには専用SQLプールの方が適切です。', 'data', ARRAY['data-fundamentals','sql-database','cosmosdb','data-analytics'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは複数のデータソースからデータを抽出・変換・読み込み（ETL）するパイプラインを構築する必要があります。どのAzureサービスを使用すべきですか？', '["A. Azure Stream Analytics", "B. Azure Data Factory", "C. Azure Event Hubs", "D. Azure Logic Apps"]'::jsonb, '1'::jsonb, 'Azure Data Factoryは、ETL/ELTパイプラインの構築に特化したマネージドサービスです。90以上のデータソースに対応するコネクタを備え、コードなしでデータフローを設計できます。Stream Analyticsはリアルタイムストリーム処理向けです。Event Hubsはイベントの取り込みサービスであり、データ変換機能はありません。Logic Appsはワークフロー自動化ですが、大規模なETLパイプラインには適していません。', 'data', ARRAY['data-sources','data-analytics','event-driven','api-management','automation-deploy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはIoTデバイスからのリアルタイムデータストリームを処理する必要があります。毎秒数百万件のイベントを取り込めるサービスはどれですか？', '["A. Azure Service Bus", "B. Azure Event Hubs", "C. Azure Queue Storage", "D. Azure Notification Hubs"]'::jsonb, '1'::jsonb, 'Azure Event Hubsは、毎秒数百万件のイベントを取り込めるビッグデータストリーミングプラットフォームです。IoTデバイスやアプリケーションからの大量のテレメトリデータのリアルタイム取り込みに最適です。Service Busはエンタープライズメッセージングに適していますが、大規模ストリーム処理向けではありません。Queue Storageは単純なキューイングです。Notification Hubsはプッシュ通知サービスです。', 'data', ARRAY['messaging','event-driven'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは構造化データを保存し、ACID準拠のトランザクション処理が必要なアプリケーションを構築しています。どのAzureサービスを使用すべきですか？', '["A. Azure Cosmos DB", "B. Azure SQL Database", "C. Azure Blob Storage", "D. Azure Table Storage"]'::jsonb, '1'::jsonb, 'Azure SQL Databaseは、完全マネージドのリレーショナルデータベースであり、ACID準拠のトランザクション処理をサポートします。構造化データの保存とSQLクエリに最適です。Cosmos DBもトランザクションをサポートしますが、主にNoSQLワークロード向けです。Blob Storageは非構造化データ向けでトランザクション処理には対応しません。Table StorageはNoSQLキー/バリューストアであり、完全なACIDトランザクションはサポートしません。', 'data', ARRAY['data-fundamentals','blob-storage','sql-database','cosmosdb','containers'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは大量の非構造化データを長期間保存する必要があります。データへのアクセス頻度は非常に低く、コストを最小化したいと考えています。どのストレージオプションを使用すべきですか？', '["A. Azure Blob Storage Hotアクセス層", "B. Azure Blob Storage Coolアクセス層", "C. Azure Blob Storage Archiveアクセス層", "D. Azure Files Premium"]'::jsonb, '2'::jsonb, 'Azure Blob Storage Archiveアクセス層は、ストレージコストが最も低く、アクセス頻度が非常に低い長期保存データに最適です。ただし、データの取得にはリハイドレーション（数時間）が必要です。Hotアクセス層はアクセスコストが低いがストレージコストが高く、Coolアクセス層はArchiveよりストレージコストが高くなります。Files Premiumはファイル共有向けで最もコストが高いオプションです。', 'data', ARRAY['blob-storage'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure SQL Databaseの保存データをサーバー側で暗号化する必要があります。どの機能を使用すべきですか？', '["A. Always Encrypted", "B. Transparent Data Encryption（TDE）", "C. 動的データマスキング", "D. Azure Information Protection"]'::jsonb, '1'::jsonb, 'Transparent Data Encryption（TDE）は、Azure SQL Databaseの保存データ（Data at Rest）をサーバー側で自動的に暗号化します。データベースファイル、ログファイル、バックアップが暗号化されます。Azure SQL Databaseではデフォルトで有効になっています。Always Encryptedはクライアント側の暗号化です。動的データマスキングはデータの表示を制限する機能であり、暗号化ではありません。Azure Information Protectionはドキュメント保護サービスです。', 'data', ARRAY['sql-database','sql-security','bcdr-fundamentals','azure-backup'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure SQL Database内の機密データをクライアント側で暗号化し、データベース管理者でさえ平文データを参照できないようにする必要があります。どの機能を使用すべきですか？', '["A. Transparent Data Encryption（TDE）", "B. Always Encrypted", "C. 行レベルセキュリティ", "D. 列レベルの暗号化"]'::jsonb, '1'::jsonb, 'Always Encryptedは、クライアント側でデータを暗号化し、暗号化キーはデータベースエンジンに公開されません。そのため、データベース管理者（DBA）でさえ平文データを参照できません。TDEはサーバー側の暗号化であり、DBAはデータを参照できます。行レベルセキュリティはアクセス制御であり暗号化ではありません。列レベルの暗号化はT-SQLの機能ですが、Always Encryptedほどの保護レベルはありません。', 'data', ARRAY['sql-database','sql-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは既存のMongoDBアプリケーションをAzureに移行する必要があります。コードの変更を最小限にしたいと考えています。Azure Cosmos DBのどのAPIを使用すべきですか？', '["A. NoSQL API", "B. MongoDB API", "C. Cassandra API", "D. Table API"]'::jsonb, '1'::jsonb, 'Azure Cosmos DB for MongoDB（MongoDB API）を使用すると、既存のMongoDBアプリケーションのコードをほぼ変更せずにCosmos DBに移行できます。MongoDBのドライバーやツールをそのまま使用でき、MongoDBのクエリ構文も互換性があります。NoSQL APIはCosmos DBネイティブのAPIです。Cassandra APIはApache Cassandraワークロード向けです。Table APIはAzure Table Storage互換のAPIです。', 'data', ARRAY['data-fundamentals','cosmosdb','data-migration'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Cosmos DBで予約済みスループットのSLAを確保する必要があります。どのスループットモデルと単位を使用すべきですか？', '["A. サーバーレススループット、DTU", "B. プロビジョニングスループット、RU（要求ユニット）", "C. 自動スケールスループット、IOPS", "D. サーバーレススループット、RU（要求ユニット）"]'::jsonb, '1'::jsonb, 'プロビジョニングスループットは、RU/s（要求ユニット/秒）で指定した固定のスループットを予約し、SLAで保証されたパフォーマンスを提供します。RU（Request Unit）はCosmos DBの課金・パフォーマンス単位です。サーバーレスは使用量ベースでSLAの保証レベルが異なります。DTUはAzure SQL Databaseの単位であり、Cosmos DBでは使用しません。IOPSはストレージの単位です。', 'data', ARRAY['sql-database','cosmosdb','cosmosdb-params','azure-functions'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Data Lake Storage Gen2の特徴として正しいものはどれですか？（2つ選択）', '["A. 階層型名前空間をサポートする", "B. ACL（アクセス制御リスト）によるきめ細かなアクセス制御が可能", "C. ページBlobのみをサポートする", "D. Standard Storageアカウントでは使用できない", "E. Azure Blob Storage APIとは互換性がない"]'::jsonb, '[0, 1]'::jsonb, 'ADLS Gen2は階層型名前空間（Hierarchical Namespace: HNS）をサポートし、ディレクトリレベルでの操作が高速に行えます。また、POSIX互換のACLによるきめ細かなファイル・ディレクトリレベルのアクセス制御が可能です。ブロックBlobをサポートします。Standard StorageアカウントでもHNSを有効化してADLS Gen2として使用できます。Blob Storage APIとの互換性も維持されています。', 'data', ARRAY['resource-locks','blob-storage','data-analytics'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Blob Storageのライフサイクル管理ポリシーが適用されるBlobの種類はどれですか？', '["A. ブロックBlobのみ", "B. ページBlobのみ", "C. 追加Blobのみ", "D. すべてのBlobの種類"]'::jsonb, '0'::jsonb, 'Azure Blob Storageのライフサイクル管理ポリシーは、ブロックBlobにのみ適用されます。ライフサイクル管理を使用すると、ブロックBlobのアクセス層の変更（Hot→Cool→Cold→Archive）や削除を自動化できます。ページBlob（VMディスクなど）や追加Blob（ログデータなど）には適用されません。', 'data', ARRAY['resource-locks','blob-storage','automation-deploy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはオンプレミスのHadoop環境で使用しているHDFS（Hadoop Distributed File System）をAzureに移行する必要があります。HDFSの代替として最適なAzureサービスはどれですか？', '["A. Azure Blob Storage", "B. Azure Data Lake Storage Gen2", "C. Azure Files", "D. Azure Managed Disks"]'::jsonb, '1'::jsonb, 'Azure Data Lake Storage Gen2（ADLS Gen2）は、HDFS互換のファイルシステムインターフェースを提供し、Hadoopエコシステム（Spark、Hiveなど）からシームレスにアクセスできます。階層型名前空間によりディレクトリ操作が高速で、ビッグデータ分析に最適化されています。Blob StorageもHDFSドライバー経由でアクセスできますが、ADLS Gen2の方がパフォーマンスと機能で優れています。Azure FilesはSMB/NFSファイル共有、Managed DisksはVM用ストレージです。', 'data', ARRAY['blob-storage','data-analytics','data-migration'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは規制要件により、Azure Blob Storage内のデータを一定期間変更・削除できないようにする必要があります。どの機能を使用すべきですか？', '["A. 論理的な削除", "B. 時間ベースの保持ポリシー（不変ストレージ）", "C. Blobのバージョン管理", "D. ストレージアカウントのロック"]'::jsonb, '1'::jsonb, '時間ベースの保持ポリシー（不変ストレージ）を使用すると、指定した期間中はBlobの変更・削除が不可能になります。WORM（Write Once, Read Many）ストレージとして機能し、金融・医療などの規制要件に対応できます。論理的な削除は削除後の復元を可能にしますが、変更の防止はしません。バージョン管理は変更履歴の保持ですが、変更自体は許可されます。ストレージアカウントのロックはリソース自体の削除防止です。', 'data', ARRAY['resource-locks','azure-storage','blob-storage'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Synapse Analyticsに関する以下の記述のうち、正しい組み合わせはどれですか？
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure DatabricksでAzure Active Directoryの資格情報パススルーを使用したいと考えています。どのDatabricksの価格レベルが必要ですか？', '["A. Standard", "B. Premium", "C. Trial", "D. StandardまたはPremium"]'::jsonb, '1'::jsonb, 'Azure Active Directory（Microsoft Entra ID）の資格情報パススルーは、Azure Databricks Premiumプランでのみ利用可能な機能です。この機能により、ユーザーのEntra ID資格情報を使用してAzure Data Lake Storageなどのリソースにアクセスできます。Standardプランではこの機能は使用できません。Trialプランは評価用であり、本番利用には適しません。', 'data', ARRAY['entra-id','data-analytics'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Synapse Analyticsにおいて、Azure Cosmos DBのデータをETLなしでリアルタイムに分析するために使用する機能はどれですか？', '["A. Azure Data Factory統合", "B. Synapse Link", "C. PolyBase", "D. COPY INTO ステートメント"]'::jsonb, '1'::jsonb, 'Synapse Linkは、Azure Cosmos DBのデータをETLパイプラインなしでSynapse Analyticsにリアルタイムで同期する機能です。Cosmos DBの分析ストア（列ストア）を活用し、OLTPワークロードに影響を与えずに分析クエリを実行できます。Data FactoryはETLパイプラインであり、リアルタイムではありません。PolyBaseとCOPY INTOは外部データの読み込み方法ですが、Cosmos DBとのリアルタイム統合ではありません。', 'data', ARRAY['entra-connect','cosmosdb','data-analytics'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Cosmos DB for PostgreSQLに関する記述として正しいものはどれですか？', '["A. マルチリージョン分散とマルチマスター書き込みの両方をサポートする", "B. マルチリージョン分散をサポートするが、マルチマスター書き込みはサポートしない", "C. マルチマスター書き込みをサポートするが、マルチリージョン分散はサポートしない", "D. マルチリージョン分散もマルチマスター書き込みもサポートしない"]'::jsonb, '1'::jsonb, 'Azure Cosmos DB for PostgreSQL（旧Hyperscale (Citus)）は、PostgreSQL互換の分散データベースであり、マルチリージョンへのデータ分散をサポートしますが、マルチマスター書き込み（マルチリージョン書き込み）はサポートしていません。書き込みはコーディネーターノードを通じて行われます。マルチマスター書き込みはCosmos DB（NoSQL APIなど）の機能です。', 'data', ARRAY['data-fundamentals','sql-database','cosmosdb'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは3つのワークロードの災害対策を計画しています。
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたのオンプレミス環境にあるファイルサーバーが障害を起こした場合に、迅速にファイルアクセスを復旧させたいと考えています。クラウドとの同期も必要です。どのサービスの組み合わせを使用すべきですか？', '["A. Azure Blob Storage + Azure CDN", "B. Azure Files + Azure File Sync", "C. Azure Managed Disks + Azure Site Recovery", "D. Azure NetApp Files + VPN Gateway"]'::jsonb, '1'::jsonb, 'Azure FilesはSMBプロトコルでアクセスできるクラウドファイル共有を提供し、Azure File Syncはオンプレミスのファイルサーバーとクラウド間でファイルを同期します。障害時にはクラウド上のファイル共有に直接アクセスでき、迅速な復旧が可能です。クラウド階層化により頻繁にアクセスされるファイルをローカルにキャッシュし、パフォーマンスも確保できます。', 'bcdr', ARRAY['entra-connect','blob-storage','site-recovery','file-sync','caching','on-premises-connectivity'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは80TBのデータを格納するAzure SQL Databaseを構築する必要があります。どのサービスティアを選択すべきですか？', '["A. General Purpose", "B. Business Critical", "C. Hyperscale", "D. Basic"]'::jsonb, '2'::jsonb, 'Azure SQL Database Hyperscaleティアは、最大100TBまでのデータベースサイズをサポートします。80TBのデータを格納するにはHyperscaleが必要です。General PurposeとBusiness Criticalは最大4TBまで（vCoreモデル、仮想コアの構成によっては最大16TB）のデータベースサイズをサポートします。BasicはDTUモデルの最小ティアで、データサイズの制限が非常に小さくなります。', 'bcdr', ARRAY['sql-database'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure SQL Databaseを可用性ゾーンの障害時にも使用可能にする必要があります。コストを最小限に抑えたい場合、どのサービスティアとモデルを選択すべきですか？', '["A. DTU Basic", "B. 仮想コア General Purpose（ゾーン冗長構成）", "C. 仮想コア Business Critical", "D. DTU Premium"]'::jsonb, '1'::jsonb, '仮想コアモデルのGeneral Purposeティアはゾーン冗長構成をサポートしており、可用性ゾーン障害に対する保護を提供します。Business Criticalもゾーン冗長をサポートしますが、コストがGeneral Purposeより高くなります。DTUモデルのBasicやStandardはゾーン冗長をサポートしません。コスト最小の要件から、General Purposeのゾーン冗長が最適です。', 'bcdr', ARRAY['sql-database','availability-zones'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure SQL Databaseのバックアップを5年間保持する必要があります。Premiumティアの自動バックアップだけでこの要件を満たすことができますか？', '["A. はい", "B. いいえ"]'::jsonb, '1'::jsonb, 'Azure SQL Databaseの自動バックアップ（PITR: Point-In-Time Restore）の保持期間は最大35日間です。5年間のバックアップ保持には、長期保持（LTR: Long-Term Retention）ポリシーを別途構成する必要があります。LTRを使用すると、完全バックアップをAzure Blob Storageに最大10年間保持できます。Premiumティアの自動バックアップだけでは5年間の保持要件を満たせません。', 'bcdr', ARRAY['blob-storage','sql-database','bcdr-fundamentals','azure-backup'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzureストレージアカウントをリージョン障害に対応させる必要があります。どの冗長性オプションを選択すべきですか？', '["A. LRS（ローカル冗長ストレージ）", "B. ZRS（ゾーン冗長ストレージ）", "C. GRS（geo冗長ストレージ）またはGZRS（geoゾーン冗長ストレージ）", "D. Premium LRS"]'::jsonb, '2'::jsonb, 'リージョン障害に対応するには、データを別のリージョンにレプリケートする必要があります。GRS（geo冗長ストレージ）はプライマリリージョンのLRSとセカンダリリージョンのLRSを組み合わせます。GZRS（geoゾーン冗長ストレージ）はプライマリリージョンのZRSとセカンダリリージョンのLRSを組み合わせます。LRSは単一データセンター内、ZRSは単一リージョン内の冗長性であり、リージョン障害には対応できません。', 'bcdr', ARRAY['azure-storage'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure BackupのバックアップポリシーにおけるStandardとEnhancedの違いとして正しいものはどれですか？', '["A. Enhancedは1日に複数回のバックアップをサポートするが、Standardは1日1回のみ", "B. StandardはAzure VMのバックアップをサポートするが、Enhancedはサポートしない", "C. Enhancedはインスタントリストアのスナップショット保持期間が最大30日だが、Standardは最大5日", "D. AとCの両方"]'::jsonb, '3'::jsonb, 'Enhancedバックアップポリシーは、1日に複数回のバックアップ（4時間ごとなど）をサポートし、インスタントリストアのスナップショット保持期間が最大30日です。Standardポリシーは1日1回のバックアップで、スナップショット保持は最大5日です。両方ともAzure VMのバックアップをサポートしています。Enhancedはより低いRPOとRTOを実現できます。', 'bcdr', ARRAY['bcdr-fundamentals','azure-backup'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Site RecoveryでAzure VMをレプリケートする場合のレプリケーション方式として正しいものはどれですか？', '["A. 同期レプリケーション", "B. 非同期レプリケーション", "C. スナップショットベースのレプリケーション", "D. バックアップベースのレプリケーション"]'::jsonb, '1'::jsonb, 'Azure Site Recoveryは非同期レプリケーションを使用してAzure VMをセカンダリリージョンにレプリケートします。非同期レプリケーションにより、プライマリVMのパフォーマンスへの影響を最小限に抑えながら、継続的にデータを複製します。RPO（目標復旧時点）は通常数分程度です。同期レプリケーションはパフォーマンスへの影響が大きく、長距離レプリケーションには適しません。', 'bcdr', ARRAY['entra-connect','bcdr-fundamentals','azure-backup','site-recovery'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは以下の要件に基づいて負荷分散サービスを選択する必要があります。グローバルなHTTP/HTTPSトラフィックの分散、WAF機能、SSL終端をサポートするサービスはどれですか？', '["A. Azure Load Balancer", "B. Azure Application Gateway", "C. Azure Traffic Manager", "D. Azure Front Door"]'::jsonb, '3'::jsonb, 'Azure Front Doorは、グローバルなHTTP/HTTPSトラフィックの負荷分散を提供し、WAF（Web Application Firewall）機能とSSL終端をサポートします。Application Gatewayはリージョナルなレイヤー7ロードバランサーでWAFをサポートしますが、グローバル分散には対応しません。Load Balancerはレイヤー4（TCP/UDP）でHTTP/HTTPS固有の機能はありません。Traffic ManagerはDNSベースのグローバル分散ですが、WAFやSSL終端はサポートしません。', 'bcdr', ARRAY['load-balancers','network-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Key Vaultでリージョン障害が発生した場合、フェールオーバー先はどこになりますか？', '["A. 最も近いリージョン", "B. ペアリージョン", "C. ユーザーが指定したリージョン", "D. フェールオーバーはサポートされていない"]'::jsonb, '1'::jsonb, 'Azure Key Vaultは、リージョン障害が発生した場合、自動的にペアリージョンにフェールオーバーします。ペアリージョンはAzureが事前に定義した地理的に近いリージョンのペアです（例：東日本と西日本）。フェールオーバーは自動的に行われ、ユーザーによる操作は不要です。フェールオーバー先をユーザーが選択することはできません。', 'bcdr', ARRAY['key-vault','site-recovery','storage-redundancy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Key Vaultのフェールオーバー中に使用できない操作はどれですか？', '["A. シークレットの読み取り", "B. キーを使用した暗号化操作", "C. シークレットの作成・更新・削除", "D. 証明書の参照"]'::jsonb, '2'::jsonb, 'Key Vaultのフェールオーバー中は、読み取り操作（シークレットの読み取り、キーの使用、証明書の参照など）は引き続き利用可能ですが、書き込み操作（作成・更新・削除）は使用できません。フェールオーバー中のKey Vaultは読み取り専用モードで動作します。フェールバック後に書き込み操作が再び可能になります。', 'bcdr', ARRAY['key-vault','site-recovery','storage-redundancy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Database for MySQLで高可用性を実現するために必要な最小のサービスティアとオプションはどれですか？', '["A. Burstable + 単一ゾーン", "B. General Purpose以上 + ゾーン冗長高可用性", "C. Business Critical + geo冗長バックアップ", "D. Burstable + ゾーン冗長高可用性"]'::jsonb, '1'::jsonb, 'Azure Database for MySQL フレキシブルサーバーでゾーン冗長の高可用性を有効にするには、General Purpose以上のサービスティアが必要です。Burstableティアではゾーン冗長高可用性はサポートされません。Business Criticalでも対応可能ですが、最小のティアとしてはGeneral Purposeが適切です。geo冗長バックアップは災害復旧には有効ですが、高可用性（自動フェールオーバー）とは異なります。', 'bcdr', ARRAY['bcdr-fundamentals','azure-backup','site-recovery','storage-redundancy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure SQL Databaseで、読み取りワークロードをセカンダリリージョンにオフロードしたい場合に使用する機能はどれですか？', '["A. 読み取りレプリカ", "B. geoバックアップ", "C. アクティブgeoレプリケーション", "D. ポイントインタイムリストア"]'::jsonb, '2'::jsonb, 'アクティブgeoレプリケーションは、Azure SQL Databaseのデータを別リージョンに非同期でレプリケートし、読み取り可能なセカンダリデータベースを提供します。読み取りワークロードをセカンダリにオフロードできます。geoバックアップは災害復旧用のバックアップであり、読み取りオフロードはできません。読み取りレプリカはMySQL/PostgreSQL向けの用語です。ポイントインタイムリストアは特定時点への復元機能です。', 'bcdr', ARRAY['entra-connect','sql-database','bcdr-fundamentals','azure-backup','site-recovery'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure SQL Databaseで、自動フェールオーバーとフェールオーバー後の接続エンドポイント変更なしを実現するために使用する機能はどれですか？', '["A. アクティブgeoレプリケーション", "B. 自動フェールオーバーグループ", "C. geoバックアップ", "D. ゾーン冗長構成"]'::jsonb, '1'::jsonb, '自動フェールオーバーグループは、自動フェールオーバー機能を提供し、読み書き用と読み取り専用のリスナーエンドポイントを提供します。フェールオーバー後もエンドポイントが変更されないため、アプリケーションの接続文字列を変更する必要がありません。アクティブgeoレプリケーションは手動フェールオーバーが必要で、接続先の変更も必要です。geoバックアップは復元操作であり自動フェールオーバーではありません。ゾーン冗長はリージョン内の冗長性です。', 'bcdr', ARRAY['azure-storage','sql-database','bcdr-fundamentals','azure-backup','site-recovery','storage-redundancy','sql-ha'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Backupにおいて、バックアップの削除操作を保護するために使用するリソースはどれですか？', '["A. Azure Policy", "B. Azure Resource Guard", "C. Azure Key Vault", "D. Microsoft Defender for Cloud"]'::jsonb, '1'::jsonb, 'Azure Resource Guardは、Azure Backupの重要な操作（バックアップの削除、バックアップポリシーの変更、論理削除の無効化など）に対する追加の保護レイヤーを提供します。Resource Guardを使用すると、これらの操作には別のサブスクリプションに存在するResource Guardリソースへのアクセス権が必要になります。Azure Policyはコンプライアンスの監査・強制ですが、バックアップ操作の直接的な保護ではありません。Key Vaultは暗号化キーの管理です。', 'bcdr', ARRAY['subscription-design','azure-policy','purview','key-vault','bcdr-fundamentals','azure-backup'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはSQL Serverをホストするための Azure VMを選択する必要があります。要件はSR-IOV対応、15,000 IOPSのサポート、コスト最小化です。適切なVMシリーズとディスクの種類の組み合わせはどれですか？', '["A. NCシリーズ + Ultra Disk", "B. DSシリーズ + Premium SSD", "C. NVシリーズ + Standard SSD", "D. Fシリーズ + Premium SSD"]'::jsonb, '1'::jsonb, 'DSシリーズはPremium Storageをサポートする汎用VMであり、SR-IOVに対応しています。Premium SSDは最大20,000 IOPSをサポートし、15,000 IOPSの要件を満たしながらUltra Diskよりもコストが低くなります。NCシリーズはGPUコンピューティング向け、NVシリーズはGPUビジュアライゼーション向けで、SQL Serverには過剰です。Fシリーズはコンピューティング最適化ですが、Premium Storageのサポートが限定的です。', 'compute', ARRAY['virtual-machines'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure VMでSQL Serverを実行する場合、ログファイルとデータファイルに推奨されるホストキャッシュの設定はどれですか？', '["A. ログ: Read-only、データ: Read/Write", "B. ログ: None、データ: Read-only", "C. ログ: Read-only、データ: None", "D. ログ: None、データ: None"]'::jsonb, '1'::jsonb, 'SQL Server VMのベストプラクティスでは、ログファイルのディスクにはホストキャッシュをNoneに設定します。ログファイルは順次書き込みが中心であり、読み取りキャッシュは不要です。データファイルのディスクにはRead-onlyキャッシュを設定します。データファイルはランダム読み取りが頻繁に発生するため、キャッシュによりパフォーマンスが向上します。Read/Writeキャッシュはデータ破損のリスクがあるため推奨されません。', 'compute', ARRAY['caching'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure App Serviceでデプロイスロットを使用するために必要な最小のサービスプランはどれですか？', '["A. Free", "B. Basic", "C. Standard", "D. Premium"]'::jsonb, '2'::jsonb, 'デプロイスロットはAzure App ServiceのStandard以上のプランで利用可能です。デプロイスロットを使用すると、本番環境に影響を与えずにアプリケーションをテストし、スワップ操作で即座にデプロイできます。FreeおよびBasicプランではデプロイスロットはサポートされていません。Standardでは5つ、Premiumでは20のデプロイスロットが利用可能です。', 'compute', ARRAY['entra-license','app-service'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKS（Azure Kubernetes Service）でWindowsコンテナーワークロードのオートスケーリングを行う必要があります。どのスケーリング方式を使用すべきですか？', '["A. 仮想ノード", "B. クラスターオートスケーラー", "C. 水平ポッドオートスケーラー（HPA）のみ", "D. KEDA"]'::jsonb, '1'::jsonb, 'クラスターオートスケーラーは、ノードプールのノード数を自動的に増減させます。Windowsノードプールにも対応しています。仮想ノード（Virtual Nodes）はAzure Container Instancesと連携してスケーリングしますが、Linuxコンテナーのみサポートしており、Windowsコンテナーには対応していません。HPAはポッドレベルのスケーリングであり、ノードの追加は行いません。KEDAはイベントドリブンスケーリングですが、ノードの自動追加にはクラスターオートスケーラーが必要です。', 'compute', ARRAY['containers','event-driven'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure Functionsで5分から20分かかる処理を実行する必要があります。どのプランを使用すべきですか？', '["A. 従量課金プラン", "B. Premium プラン", "C. App Service プラン（Free）", "D. 従量課金プラン（タイムアウト延長）"]'::jsonb, '1'::jsonb, 'Azure Functions Premiumプランは、実行時間の制限がなく（既定は30分、最大で無制限に設定可能）、5〜20分の処理に対応できます。従量課金プランはデフォルトで5分、最大10分のタイムアウト制限があり、20分の処理には対応できません。App Service プランのFreeティアもタイムアウト制限があります。Premiumプランはさらに、VNET統合やウォームアップインスタンスなどの機能も提供します。', 'compute', ARRAY['entra-license','app-service','azure-functions'], true, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは大規模な並列バッチ処理を実行する必要があります。ジョブの種類ごとに異なるVM構成を使用したいと考えています。どのAzureサービスを使用すべきですか？', '["A. Azure Functions", "B. Azure Batch", "C. Azure Container Instances", "D. Azure Logic Apps"]'::jsonb, '1'::jsonb, 'Azure Batchは大規模な並列バッチ処理に特化したサービスで、ジョブの種類ごとに異なるプール（VM構成）を作成できます。CPU集中型、GPU対応、メモリ最適化など、ジョブに最適なVM構成を選択できます。Azure Functionsはイベントドリブンの短時間処理向けです。Container Instancesは単一のコンテナー実行向けです。Logic Appsはワークフロー自動化サービスです。', 'compute', ARRAY['containers','azure-functions','batch','event-driven','api-management','automation-deploy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはメッセージングシステムを設計しており、FIFO（先入先出）の順序保証が必要です。どのAzureサービスと機能を使用すべきですか？', '["A. Azure Queue Storage", "B. Azure Event Hubs パーティション", "C. Azure Service Bus セッション", "D. Azure Event Grid"]'::jsonb, '2'::jsonb, 'Azure Service Busのセッション機能は、メッセージのFIFO順序保証を提供します。セッションIDに基づいてメッセージの順序を保証し、関連するメッセージを順番に処理できます。Queue Storageは基本的なキューイングサービスですが、厳密なFIFO保証はありません。Event Hubsはパーティション内で順序を保証しますが、メッセージングのFIFO保証にはService Busのセッションがより適切です。Event Gridはイベント配信サービスであり、順序保証はありません。', 'compute', ARRAY['messaging','event-driven'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはイベントドリブンアーキテクチャを設計しています。リソースの状態変更を検知して、複数のサブスクライバーに通知する必要があります。Azure Event GridとAzure Event Hubsのどちらを選択すべきですか？', '["A. Event Grid（イベントの反応・ルーティングに特化）", "B. Event Hubs（イベントの反応・ルーティングに特化）", "C. Event Grid（大規模ストリーム取り込みに特化）", "D. Event Hubs（リソース状態変更の通知に特化）"]'::jsonb, '0'::jsonb, 'Azure Event Gridは、イベントベースのアーキテクチャ向けに設計されており、Azureリソースの状態変更などのイベントを検知して、複数のサブスクライバー（Azure Functions、Logic Appsなど）にルーティングします。Event Hubsは大規模なデータストリームの取り込みに特化しており、IoTデータやログの大量取り込みに適しています。リソース状態変更の通知にはEvent Gridが適切です。', 'compute', ARRAY['azure-functions','event-driven','api-management'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure API Managementで、仮想ネットワーク（VNet）統合を使用してバックエンドAPIをプライベートネットワーク内に配置する必要があります。どの価格レベルが必要ですか？', '["A. Developer", "B. Basic", "C. Standard", "D. Premium"]'::jsonb, '3'::jsonb, 'Azure API ManagementのVNet統合（内部モードおよび外部モード）は、Premiumティアでのみサポートされます。Developer ティアもVNet統合をサポートしますが、SLAがなく本番環境には適しません。BasicおよびStandardティアはVNet統合をサポートしていません。PremiumティアはさらにマルチリージョンデプロイやAvailability Zonesもサポートします。', 'network', ARRAY['availability-zones','api-management','vnet'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはWebアプリケーションのパフォーマンスを向上させたいと考えています。静的コンテンツ（画像、CSS、JavaScript）のグローバル配信にはどのサービスを使用し、動的データ（セッション情報、データベースクエリ結果）のキャッシュにはどのサービスを使用すべきですか？', '["A. 静的コンテンツ: Azure CDN、動的データ: Azure CDN", "B. 静的コンテンツ: Azure Cache for Redis、動的データ: Azure CDN", "C. 静的コンテンツ: Azure CDN、動的データ: Azure Cache for Redis", "D. 静的コンテンツ: Azure Front Door、動的データ: Azure Table Storage"]'::jsonb, '2'::jsonb, 'Azure CDNはエッジサーバーのグローバルネットワークを使用して静的コンテンツを配信し、レイテンシを低減します。Azure Cache for Redisはインメモリデータストアであり、セッション情報やデータベースクエリ結果などの動的データのキャッシュに最適です。CDNは動的データのキャッシュには適していません。Redis Cacheは静的ファイルの配信には使用しません。', 'compute', ARRAY['load-balancers','caching'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはインフラストラクチャのデプロイを自動化する必要があります。宣言的なテンプレートでリソースを定義し、冪等性のあるデプロイを行いたいと考えています。どのサービスを使用すべきですか？', '["A. Azure Automation Runbook", "B. ARM テンプレート / Bicep", "C. Azure CLI スクリプト", "D. Azure PowerShell スクリプト"]'::jsonb, '1'::jsonb, 'ARMテンプレート（およびBicep）は、Azureリソースを宣言的に定義するIaC（Infrastructure as Code）ツールです。冪等性があり、同じテンプレートを何度デプロイしても同じ結果になります。Azure Automation Runbookは手続き的なスクリプト実行であり、宣言的ではありません。Azure CLIやPowerShellスクリプトも手続き的なアプローチです。', 'compute', ARRAY['automation-deploy'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはオンプレミスネットワークとAzure VNetをインターネット経由で暗号化された接続で結ぶ必要があります。常時接続で複数のオンプレミスサイトを接続します。どのVPN接続方式を使用すべきですか？', '["A. ポイント対サイト（P2S）VPN", "B. サイト間（S2S）VPN", "C. VNet ピアリング", "D. ExpressRoute"]'::jsonb, '1'::jsonb, 'サイト間（S2S）VPNは、オンプレミスのVPNデバイスとAzure VPN Gatewayの間にIPsecトンネルを確立し、常時接続の暗号化通信を提供します。複数のオンプレミスサイトを接続できます。ポイント対サイト（P2S）VPNは個々のクライアントPCからの接続用であり、サイト全体の接続には適しません。VNetピアリングはAzure VNet間の接続です。ExpressRouteはインターネットを経由しないプライベート接続です。', 'network', ARRAY['vnet','on-premises-connectivity'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはオンプレミスとAzure間で高帯域幅・低レイテンシの専用接続が必要です。インターネットを経由しない接続を要求されています。どのサービスを使用すべきですか？', '["A. VPN Gateway（S2S）", "B. ExpressRoute", "C. Azure Front Door", "D. VPN Gateway（P2S）"]'::jsonb, '1'::jsonb, 'ExpressRouteは、接続プロバイダーを通じてオンプレミスネットワークとAzureの間にプライベートな専用接続を提供します。インターネットを経由せず、高帯域幅（最大100Gbps）と低レイテンシを実現します。VPN GatewayはIPsecトンネルを使用しますが、インターネット経由の接続です。Front DoorはグローバルHTTPロードバランサーです。', 'network', ARRAY['load-balancers','on-premises-connectivity'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Virtual WANにおけるBasic SKUとStandard SKUの違いとして正しいものはどれですか？', '["A. BasicはS2S VPNのみサポートし、StandardはS2S VPN、P2S VPN、ExpressRoute、VNet間接続をサポートする", "B. BasicはExpressRouteのみサポートし、StandardはVPNのみサポートする", "C. BasicとStandardは同じ機能を持つ", "D. BasicはP2S VPNのみサポートし、StandardはすべてのVPN種類をサポートする"]'::jsonb, '0'::jsonb, 'Virtual WAN Basic SKUはサイト間（S2S）VPN接続のみをサポートします。Standard SKUはS2S VPN、ポイント対サイト（P2S）VPN、ExpressRoute、仮想ネットワーク間接続、ハブ間接続など、すべての接続タイプをサポートします。複数の接続タイプが必要な場合はStandard SKUを選択する必要があります。', 'network', ARRAY['vnet','on-premises-connectivity'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Private Linkにおけるサービスエンドポイントとプライベートエンドポイントの違いとして正しいものはどれですか？', '["A. サービスエンドポイントはVNet内のプライベートIPを割り当て、プライベートエンドポイントはパブリックIPを使用する", "B. プライベートエンドポイントはVNet内のプライベートIPを割り当て、サービスエンドポイントはサービスへのルートを最適化する", "C. 両方ともプライベートIPを割り当てる", "D. 両方ともパブリックIPを使用する"]'::jsonb, '1'::jsonb, 'プライベートエンドポイントは、VNet内のサブネットにプライベートIPアドレスを割り当て、Azureサービスにプライベート接続します。トラフィックはMicrosoftバックボーンネットワーク内に留まります。サービスエンドポイントは、VNetからAzureサービスへのルートを最適化し、トラフィックをAzureバックボーン経由で送信しますが、サービスのパブリックIPアドレスは保持されます。プライベートエンドポイントの方がセキュリティが高く、オンプレミスやピアリングVNetからのアクセスもサポートします。', 'network', ARRAY['vnet','private-link'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure環境のネットワークセキュリティを設計しています。サブネットレベルでのトラフィックフィルタリングにはNSGを使用し、集中型のネットワークセキュリティ管理にはどのサービスを使用すべきですか？', '["A. Azure DDoS Protection", "B. Azure Firewall", "C. Azure WAF", "D. Azure Front Door"]'::jsonb, '1'::jsonb, 'Azure Firewallは、集中型のネットワークセキュリティ管理を提供するマネージドファイアウォールサービスです。L3-L7のフィルタリング、脅威インテリジェンス、FQDN フィルタリング、URLフィルタリングなどの機能を提供します。NSGはサブネット/NICレベルの基本的なフィルタリングに適していますが、高度なセキュリティ機能は限定的です。DDoS ProtectionはDDoS攻撃への防御に特化しています。WAFはWebアプリケーション層の保護です。', 'network', ARRAY['load-balancers','vnet','network-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはAzure環境をDDoS攻撃から保護する必要があります。Azure DDoS Protectionのプランとして正しいものはどれですか？', '["A. DDoS Protectionは無料で全リソースに自動適用される", "B. DDoS Network Protection（有料）はVNetに対して適用され、テレメトリとアラートを提供する", "C. DDoS Protectionは個別のVMに対してのみ適用される", "D. DDoS ProtectionはApplication Gatewayでのみ使用可能"]'::jsonb, '1'::jsonb, 'Azure DDoS Network Protection（旧Standard）は、有料プランであり、仮想ネットワーク内のリソースに対して高度なDDoS軽減機能を提供します。DDoS攻撃のテレメトリ、診断ログ、アラート、コスト保護保証が含まれます。Azureプラットフォーム自体に基本的なDDoS保護（Infrastructure Protection）は無料で含まれていますが、高度な保護にはNetwork Protectionが必要です。', 'network', ARRAY['diagnostic-settings','alerts','load-balancers','vnet','network-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure WAF（Web Application Firewall）をデプロイできるサービスはどれですか？（3つ選択）', '["A. Azure Application Gateway", "B. Azure Front Door", "C. Azure CDN", "D. Azure Load Balancer", "E. Azure Traffic Manager"]'::jsonb, '[0, 1, 2]'::jsonb, 'Azure WAFは、Application Gateway、Front Door、CDN（Azure CDN from Microsoft）の3つのサービスにデプロイできます。WAFはOWASP Top 10の脆弱性（SQLインジェクション、XSSなど）からWebアプリケーションを保護します。Load BalancerはL4のロードバランサーでありWAFをサポートしません。Traffic ManagerはDNSベースの負荷分散でありWAFをサポートしません。', 'network', ARRAY['load-balancers','caching','network-security'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはオンプレミスのサーバーとアプリケーションをAzureに移行する計画を立てています。移行の評価・計画・実行を一元的に管理するために使用すべきサービスはどれですか？', '["A. Azure Site Recovery", "B. Azure Migrate", "C. Azure Resource Mover", "D. Azure Advisor"]'::jsonb, '1'::jsonb, 'Azure Migrateは、オンプレミスからAzureへの移行を一元的に管理するためのハブサービスです。サーバー、データベース、Webアプリケーションの検出・評価・移行を統合的に行えます。Site Recoveryは災害復旧と移行の実行ツールですが、評価機能はありません。Resource MoverはAzureリージョン間のリソース移動です。Advisorは推奨事項の提供であり、移行管理ではありません。', 'compute', ARRAY['site-recovery','data-migration'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはデータベースの移行を計画しています。DMS（Database Migration Service）、DMA（Data Migration Assistant）、SSMA（SQL Server Migration Assistant）の用途の違いとして正しいものはどれですか？', '["A. DMSはオンライン移行（最小ダウンタイム）をサポートし、DMAはSQL Serverの互換性評価を行い、SSMAは非SQL Server DBからSQL Serverへの移行を支援する", "B. DMAはオンライン移行をサポートし、DMSは互換性評価を行い、SSMAはSQL Server間の移行を支援する", "C. SSMAはオンライン移行をサポートし、DMSは非SQL Server DBからの移行を支援し、DMAは互換性評価を行う", "D. 3つとも同じ機能を提供する"]'::jsonb, '0'::jsonb, 'DMS（Azure Database Migration Service）は、オンライン移行（最小ダウンタイム）をサポートし、SQL Server、MySQL、PostgreSQLなどのデータベースをAzureに移行します。DMA（Data Migration Assistant）は、SQL ServerからAzure SQL Database/MIへの移行前に互換性の評価と推奨事項を提供するツールです。SSMA（SQL Server Migration Assistant）は、Oracle、MySQL、AccessなどのNon-SQL ServerデータベースからSQL Serverへのスキーマとデータの移行を支援します。', 'data', ARRAY['sql-database','data-migration','db-migration'], false, 'book');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたはデータウェアハウス（DWH）を実装するためのAzureサービスを選択する必要があります。大量のデータの並列読み込みに対応し、DWHとして最適なサービスはどれですか？', '["A. Azure Data Lake Analytics", "B. Azure Synapse Analytics Sparkプール", "C. Azure Synapse Analytics 専用SQLプール"]'::jsonb, '2'::jsonb, 'Azure Synapse Analytics 専用SQLプールは、エンタープライズデータウェアハウスに最適化されたサービスです。超並列処理（MPP）アーキテクチャを採用しており、大量のデータの並列読み込みと高速クエリ処理が可能です。Azure Data Lake Analyticsはビッグデータ分析用のオンデマンドジョブサービスであり、DWHとしての用途には適していません。Synapse Sparkプールはビッグデータ処理やMLに適していますが、構造化データのDWHとしては専用SQLプールの方が適切です。', 'data', ARRAY['data-fundamentals','data-analytics'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '数千人のユーザーに対してOLAP（オンライン分析処理）のサービング レイヤーを実装する必要があります。どのサービスを使用すべきですか？', '["A. Azure Synapse Analytics Sparkプール", "B. Azure Synapse Analytics 専用SQLプール", "C. Azure Analysis Services"]'::jsonb, '2'::jsonb, 'Azure Analysis Servicesは、エンタープライズグレードのOLAPエンジンであり、数千人のユーザーへのサービングレイヤーとして設計されています。セマンティックモデルを作成し、高速なクエリ応答を提供します。Synapse Sparkプールはビッグデータ処理向けであり、サービングレイヤーとしては適していません。Synapse専用SQLプールはDWHとしては優秀ですが、多数のユーザーへのOLAPサービングレイヤーとしてはAnalysis Servicesの方がコスト効率が高く適切です。', 'data', ARRAY['data-analytics'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Resource Managerのデプロイメントに関する月次レポートを作成する必要があります。リソースのデプロイ履歴を確認するために使用すべきサービスはどれですか？', '["A. Azure Analysis Services", "B. Azure Monitor アクション グループ", "C. Azure Monitor アクティビティ ログ", "D. Azure Arc"]'::jsonb, '2'::jsonb, 'Azure Monitorアクティビティログは、サブスクリプションレベルのイベント（リソースの作成、更新、削除などのARMデプロイメント操作）を記録します。月次レポートに必要なデプロイ履歴を確認できます。Analysis Servicesはデータ分析サービスでありデプロイ追跡には関係ありません。アクショングループはアラート発生時の通知/アクション設定であり、履歴の記録ではありません。Azure Arcはハイブリッド環境のリソース管理サービスであり、デプロイ履歴の記録には使用しません。', 'monitoring', ARRAY['subscription-design','azure-monitor','alerts','activity-log','data-analytics','event-driven'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'SQL Serverをホストするために最適なAzure仮想マシンシリーズを選択してください。要件は15,000 IOPSのサポート、SR-IOV対応、およびコスト最小化です。', '["A. NCシリーズ", "B. NVシリーズ", "C. DSシリーズ"]'::jsonb, '2'::jsonb, 'DSシリーズは汎用VMであり、Premium Storageをサポートし、15,000 IOPSの要件を満たすことができます。SR-IOV（Single Root I/O Virtualization）にも対応しており、SQL Serverのホスティングに適しています。NCシリーズはGPUコンピューティング（AI/ML）向けであり、SQL Serverには過剰でコストが高くなります。NVシリーズはGPUによるビジュアライゼーション/リモートデスクトップ向けであり、データベースワークロードには適していません。', 'compute', ARRAY['virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'SQL Server VMに使用するディスクの種類を選択してください。要件は15,000 IOPSのサポートで、コストを最小化する必要があります。', '["A. Ultra Disk", "B. Premium SSD", "C. Standard SSD"]'::jsonb, '1'::jsonb, 'Premium SSDは最大20,000 IOPSをサポートし、15,000 IOPSの要件を満たすことができます。コスト面でもUltra Diskより安価です。Ultra Diskは最大160,000 IOPSをサポートしますが、この要件に対しては過剰でコストが高くなります。Standard SSDは最大6,000 IOPS程度であり、15,000 IOPSの要件を満たせません。', 'compute', ARRAY['virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Blob Storageでポイントインタイムリストアを使用する場合、対応しているBlobの種類はどれですか？', '["A. ブロックBlob", "B. ページBlob", "C. 追加Blob"]'::jsonb, '0'::jsonb, 'ポイントインタイムリストアは、ブロックBlobのみをサポートしています。ブロックBlobのデータを特定の時点の状態に復元することができます。ページBlobは仮想マシンのディスクなどに使用されますが、ポイントインタイムリストアには対応していません。追加Blobはログデータなどの追記専用シナリオに使用されますが、同様にポイントインタイムリストアには対応していません。', 'data', ARRAY['resource-locks','blob-storage','virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ポイントインタイムリストアを有効にするために、事前に有効化が必要な機能はどれですか？', '["A. アクセスポリシー", "B. 変更フィード", "C. 不変ストレージ", "D. オブジェクトレプリケーション"]'::jsonb, '1'::jsonb, 'ポイントインタイムリストアを使用するには、変更フィード（Change Feed）を有効にする必要があります。変更フィードはBlobに対する作成、変更、削除の操作ログを提供し、これによりポイントインタイムリストアが特定時点の状態を再構築できます。また、Blobのバージョン管理と論理的な削除も同時に有効化が必要です。アクセスポリシーはアクセス制御に関する機能です。不変ストレージはデータの変更・削除を防ぐ機能です。オブジェクトレプリケーションはBlob間の非同期コピーの機能であり、ポイントインタイムリストアの前提条件ではありません。', 'data', ARRAY['entra-connect','blob-storage','bcdr-fundamentals','storage-redundancy'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKSでホストされるマイクロサービスを外部に公開する必要があります。要件はプライベートIPアドレスでの接続、MTLS（相互TLS）認証、レート制限です。どの構成を使用すべきですか？', '["A. Application Gateway + WAF", "B. API Management Standard + セルフホステッドゲートウェイ", "C. Azure Front Door + WAF", "D. API Management Premium + VNet統合"]'::jsonb, '3'::jsonb, 'API Management PremiumティアはVNet統合をサポートし、プライベートIPアドレスでの接続が可能です。また、MTLS（相互TLS認証）とレート制限（スロットリング）の機能を標準で提供しています。Application Gateway + WAFはL7ロードバランシングとWAF保護を提供しますが、MTLSやレート制限の高度な管理はAPI Managementの方が適しています。API Management StandardティアはVNet統合をサポートしていないため、プライベートIPの要件を満たせません。Front Door + WAFはグローバルなL7ロードバランシングですが、プライベートIP接続やMTLSの要件には適していません。', 'network', ARRAY['load-balancers','containers','api-management','vnet','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ExpressRoute Global Reachを使用する場合、動的ルーティングを実現し、障害時の自動再ルーティングを可能にするプロトコルはどれですか？', '["A. BGP", "B. デフォルトルート", "C. ユーザー定義ルート"]'::jsonb, '0'::jsonb, 'BGP（Border Gateway Protocol）は、ExpressRouteで使用される動的ルーティングプロトコルです。BGPによりルート情報が自動的に交換され、障害発生時には自動的に経路の再計算と再ルーティングが行われます。デフォルトルートは静的な設定であり、動的なルーティングや障害時の自動再ルーティングはできません。ユーザー定義ルート（UDR）も静的なルーティング設定であり、動的な経路変更には対応していません。', 'network', ARRAY['on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'フェールオーバー後にトラフィックを自動的にルーティングするために使用すべきプロトコルはどれですか？', '["A. HSRP", "B. VRRP", "C. BGP"]'::jsonb, '2'::jsonb, 'BGP（Border Gateway Protocol）は、Azureのネットワーク環境でフェールオーバー後のトラフィック自動ルーティングに使用されるプロトコルです。ExpressRouteやVPN Gatewayで使用され、ネットワーク障害時に代替経路を自動的に検出して切り替えます。HSRP（Hot Standby Router Protocol）はCisco独自のプロトコルであり、Azureでは使用されません。VRRP（Virtual Router Redundancy Protocol）はオンプレミスのルーター冗長化プロトコルであり、Azureのクラウド環境では直接使用されません。', 'network', ARRAY['bcdr-fundamentals','site-recovery','storage-redundancy','on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'contoso.com と fabrikam.com という名前の 2 つの Microsoft Entra IDD テナントがあります。各テナントは 50 の Azure サブスクリプションにリンクされています。 Contoso.com には、User1 と User2 という名前の 2 人のユーザーが含まれています。 次の要件を満たす必要があります。 ソリューションでは、最小特権の原則を使用する必要があります。 各ユーザーにどの役割を割り当てる必要がありますか。 User1:・ User1 は、特定の Azure サブスクリプションにリンクされた Microsoft Entra テナントを変更できることを確認する。・ Azure サブスクリプションが新しい Microsoft Entra テナントに関連付けられており、そのサブスクリプションに対する完全なサブスクリプション レベルのアクセス許可を持つ使用可能な Microsoft Entra ID アカウントがない場合は、User2 のアクセスをサブスクリプションに昇格させる。', '["サービス管理者", "共同管理者", "所有者"]'::jsonb, '2'::jsonb, '特定の Azure サブスクリプションにリンクされた Microsoft Entra テナントを変更する必要がある User1 には、「所有者」のロールを割り当てる必要があります。サブスクリプションにリンクされている Microsoft Entra テナントを変更するには、ユーザーが所有者レベルで使用できる十分なアクセス許可を持っている必要があるためです。https://learn.microsoft.com/ja-jp/entra/fundamentals/how-subscriptions-associated-directory#before-you-begin', '', ARRAY['entra-id','rbac','pim','subscription-design'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'contoso.com と fabrikam.com という名前の 2 つの Microsoft Entra IDD テナントがあります。各テナントは 50 の Azure サブスクリプションにリンクされています。 Contoso.com には、User1 と User2 という名前の 2 人のユーザーが含まれています。 次の要件を満たす必要があります。 ソリューションでは、最小特権の原則を使用する必要があります。 各ユーザーにどの役割を割り当てる必要がありますか。 User2:・ User1 は、特定の Azure サブスクリプションにリンクされた Microsoft Entra テナントを変更できることを確認する。・ Azure サブスクリプションが新しい Microsoft Entra テナントに関連付けられており、そのサブスクリプションに対する完全なサブスクリプション レベルのアクセス許可を持つ使用可能な Microsoft Entra ID アカウントがない場合は、User2 のアクセスをサブスクリプションに昇格させる。', '["サービス管理者", "共同管理者", "所有者"]'::jsonb, '2'::jsonb, '利用可能な Microsoft Entra ID アカウントにサブスクリプションに対する完全なサブスクリプション レベルのアクセス許可がない場合に、サブスクリプションに昇格されたアクセス権が必要な User2 には、「所有者」ロールも割り当てる必要があります。この役割は、他のリソースにアクセスを委任する権利を含む、すべてのリソースへの完全なアクセスを提供します。このシナリオでは、「所有者」ロールにより、完全な権限を持つ他のアカウントが存在しない場合でも、User2 がサブスクリプションにアクセスできるようになります。https://learn.microsoft.com/ja-jp/entra/fundamentals/how-subscriptions-associated-directory#before-you-begin', '', ARRAY['entra-id','rbac','pim','subscription-design'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Windows Server を実行するオンプレミス サーバーが 10 台あります。 Recovery Services コンテナーへのサーバーのバックアップを毎日実行する必要があります。ソリューションは次の要件を満たす必要があります。 何を設定すればよいでしょうか。 サーバー:・ サーバー上のすべてのファイルとフォルダーをバックアップする。・ Azure にバックアップのコピーを 3 つ保持する。・ コストを最小限に抑える。', '["Azure Site Recovery モビリティ サービス", "ボリューム シャドウ コピー サービス (VSS)", "Microsoft Azure Recovery Service (MARS) エージェント"]'::jsonb, '2'::jsonb, '・ サーバー上のすべてのファイルとフォルダーをバックアップする。・ Azure にバックアップのコピーを 3 つ保持する。・ コストを最小限に抑える。', '', ARRAY['bcdr-fundamentals','azure-backup','site-recovery','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Windows Server を実行するオンプレミス サーバーが 10 台あります。 Recovery Services コンテナーへのサーバーのバックアップを毎日実行する必要があります。ソリューションは次の要件を満たす必要があります。 何を設定すればよいでしょうか。 ストレージ:・ サーバー上のすべてのファイルとフォルダーをバックアップする。・ Azure にバックアップのコピーを 3 つ保持する。・ コストを最小限に抑える。', '["ローカル冗長ストレージ (LRS)", "Geo 冗長ストレージ (GRS)", "ゾーン冗長ストレージ (ZRS)"]'::jsonb, '0'::jsonb, 'ローカル冗長ストレージ (LRS)LRS は、Azure Backup にとって最もコスト効率の高いストレージ オプションです。プライマリ リージョンの単一データ センター内でデータを 3 回レプリケートするため、ほとんどのワークロードに対して十分な耐久性が提供されます。', '', ARRAY['azure-storage','bcdr-fundamentals','azure-backup','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の要件を満たすデータ ストレージ ソリューションを推奨する必要があります。 何を勧めるべきですか。・ アプリケーションが REST 接続を使用してデータにアクセスできることを保証します。・ さまざまなサイズと使用パターンの 20 の独立したテーブルをホスト・ データを 2 番目の Azure リージョンに自動的にレプリケートします・ コストを最小限に抑える', '["geo 冗長ストレージ (GRS) を使用する Azure ストレージ アカウント内のテーブル", "アクティブな geo レプリケーションを使用する Azure SQL Database エラスティック プール", "アクティブ geo レプリケーションを使用する Azure SQL データベース", "読み取りアクセス geo 冗長ストレージ (RA-GRS) を使用する Azure ストレージ アカウント内のテーブル"]'::jsonb, '0'::jsonb, 'geo 冗長ストレージ (GRS) を使用する Azure ストレージ アカウント内のテーブルAzure Table Storage は NoSQL 機能を提供し、スキーマレス設計のキー属性ストアを提供します。そのため、さまざまなサイズや使用パターンの独立したテーブルをホストするのに適しています。 Table Storage データには REST API 経由でアクセスでき、GRS はデータをセカンダリ リージョンに自動的にレプリケートして、リージョンの停止から保護します。コスト最小化の要件に従って、GRS は RA-GRS よりも安価であり、一般に Azure Table Storage は Azure SQL Database オプションよりもコスト効率が高くなります。https://learn.microsoft.com/ja-jp/azure/storage/common/geo-redundant-design', '', ARRAY['data-fundamentals','azure-storage','sql-database','bcdr-fundamentals','sql-ha'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の要件を満たす Azure Storage ソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。・ ストレージは 1 PB のデータをサポートする必要がある。・ データは BLOB ストレージに保存する必要がある。・ ストレージは 3 レベルのサブフォルダーをサポートする必要がある。・ ストレージはアクセス制御リスト (ACL) をサポートする必要がある。', '["ページ BLOB 用に構成された Premium ストレージ アカウント", "ブロック BLOB 用に構成された Premium ストレージ アカウント", "ファイル共有用に構成され、大規模なファイル共有をサポートする Premium ストレージ アカウント", "階層名前空間が有効になっている汎用 v2 ストレージ アカウント"]'::jsonb, '3'::jsonb, 'Azure Blob Storage は、テキスト データやバイナリ データなどの大量の非構造化オブジェクト データを保存するように設計されており、ペタバイト規模のデータを保存できます。汎用 v2 アカウントは、Azure Storage のギガバイトあたりの容量料金が最も低く、業界競争力のあるトランザクション価格を提供します。階層名前空間を使用すると、BLOB ストレージで複数のレベルのディレクトリとサブフォルダーをサポートできます。さらに、階層名前空間を有効にすると、アカウント内のデータは、きめ細かいアクセス許可のアクセス制御リスト (ACL) をサポートする Azure Data Lake Storage Gen2 を通じてアクセスできるようになります。https://learn.microsoft.com/ja-jp/azure/azure-resource-manager/management/azure-subscription-service-limits#storage-limits', '', ARRAY['resource-locks','azure-storage','blob-storage','data-analytics'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '2 TB のデータ ファイルを保存するオンプレミスのファイル サーバーがあります。 データ ファイルを西ヨーロッパ Azure リージョンの Azure Blob Storage に移動する予定です。 データ ファイルを保存するためのストレージ アカウントの種類と、ストレージ アカウントのレプリケーション ソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 何を勧めるべきですか。 ストレージ アカウントの種類:・ 単一の Azure データセンターに障害が発生した場合でも利用できるようにする。・ ストレージ階層をサポートする。・ コストを最小限に抑える。', '["Standard 汎用 v2", "Premium ブロック BLOB", "Standard 汎用 v1"]'::jsonb, '0'::jsonb, 'Standard 汎用 v2BLOB、ファイル共有、キュー、テーブル用の Standard タイプのストレージ アカウント。 Azure Storage を使用するほとんどのシナリオにお勧めします。 Azure Files の ネットワーク ファイル システム (NFS) のサポートが必要な場合は、Premium ファイル共有タイプのアカウントを使用してください。https://learn.microsoft.com/ja-jp/azure/storage/common/storage-account-overview', '', ARRAY['resource-locks','azure-storage','blob-storage','bcdr-fundamentals','messaging'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '2 TB のデータ ファイルを保存するオンプレミスのファイル サーバーがあります。 データ ファイルを西ヨーロッパ Azure リージョンの Azure Blob Storage に移動する予定です。 データ ファイルを保存するためのストレージ アカウントの種類と、ストレージ アカウントのレプリケーション ソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 何を勧めるべきですか。 冗長性:・ 単一の Azure データセンターに障害が発生した場合でも利用できるようにする。・ ストレージ階層をサポートする。・ コストを最小限に抑える。', '["ゾーン冗長ストレージ (ZRS)", "Geo 冗長ストレージ (GRS)", "読み取りアクセス geo 冗長ストレージ (RA-GRS)", "ローカル冗長ストレージ (LRS)"]'::jsonb, '0'::jsonb, 'ゾーン冗長ストレージ (ZRS) は、プライマリ リージョンの 3 つの Azure 可用性ゾーン間でストレージ アカウントを同期的にレプリケートします。 各可用性ゾーンは、独立した電源、冷却装置、ネットワークを備えた独立した物理的な場所です。 ZRS は、ストレージ リソースに年間 99.9999999999% (トゥエルブ ナイン) 以上の持続性を実現します。ZRS はコストを最小限に抑えながら、データセンターの障害から保護します。https://docs.microsoft.com/ja-jp/azure/storage/common/storage-redundancy', '', ARRAY['entra-connect','azure-storage','blob-storage','bcdr-fundamentals','availability-zones'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '"オンプレミスの Microsoft SQL Server データベースを Azure に移行することを計画しています。 次の要件を満たす展開および復元ソリューションを推奨する必要があります。 何を勧めるべきですか。 デプロイメント ソリューション:"・ ユーザー開始のバックアップをサポートする。・ Azure リージョン間で自動的にレプリケートされる複数のインスタンスをサポートする。・ ビジネス継続性を実装および維持するための管理労力を最小限に抑える。', '["Azure SQL Managed Instance", "Azure SQL Database の単一データベース", "Azure Virtual Machines 上の SQL Server"]'::jsonb, '0'::jsonb, 'キーワードが「複数の自動的にレプリケートされたインスタンスをサポート」です。また、ユーザーが開始したバックアップもサポートする唯一の選択肢はAzure SQL Managed Instanceになります。https://learn.microsoft.com/ja-jp/azure/azure-sql/managed-instance/sql-managed-instance-paas-overview?view=azuresql', '', ARRAY['sql-database','bcdr-fundamentals','azure-backup','virtual-machines','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミスの Microsoft SQL Server データベースを Azure に移行することを計画しています。 次の要件を満たす展開および復元ソリューションを推奨する必要があります。 何を勧めるべきですか。 回復力 ソリューション:・ ユーザー開始のバックアップをサポートする。・ Azure リージョン間で自動的にレプリケートされる複数のインスタンスをサポートする。・ ビジネス継続性を実装および維持するための管理労力を最小限に抑える。', '["自動フェールオーバー グループ", "アクティブ geo レプリケーション", "ゾーン冗長デプロイメント"]'::jsonb, '0'::jsonb, 'Azure SQL Managed Instanceがアクティブな geo レプリケーションをサポートしていないため、自動フェールオーバーが正解です。https://learn.microsoft.com/ja-jp/azure/well-architected/service-guides/azure-sql-managed-instance/reliability', '', ARRAY['sql-database','bcdr-fundamentals','azure-backup','site-recovery','storage-redundancy','sql-ha','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'SAML SSOを実装し、不明な場所からのサインインに対してMFA（多要素認証）を要求する必要があります。どの2つのサービスを使用すべきですか？（2つ選択）', '["A. エンタープライズ アプリケーション", "B. Application Gateway", "C. Privileged Identity Management (PIM)", "D. 条件付きアクセス", "E. Identity Protection"]'::jsonb, '[0, 3]'::jsonb, 'エンタープライズアプリケーションでSAML SSOを構成し、条件付きアクセスポリシーで「不明な場所からのサインイン」に対してMFAを要求する条件を設定します。エンタープライズアプリケーションはSAML SSOの設定に必要であり、条件付きアクセスは場所ベースの条件でMFAを要求できます。Application GatewayはL7ロードバランサーであり、SSO/MFAの設定には使用しません。PIMは特権ロールの管理サービスです。Identity Protectionはリスクベースのポリシーを提供しますが、「不明な場所」という条件には条件付きアクセスの方が直接的に対応できます。', 'identity', ARRAY['auth-methods','sso','rbac','conditional-access','pim','load-balancers'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKSで使用するコンテナイメージを複数のリージョンに自動的にレプリケーションする必要があります。どのサービスを使用すべきですか？', '["A. Azure Cache for Redis", "B. GRS（Geo冗長ストレージ）", "C. Azure CDN", "D. Azure Container Registry Premium"]'::jsonb, '3'::jsonb, 'Azure Container Registry（ACR）Premiumティアは、Geoレプリケーション機能を提供し、コンテナイメージを複数のリージョンに自動的にレプリケートできます。これにより、各リージョンのAKSクラスターが最寄りのレジストリからイメージをプルでき、デプロイの高速化が可能です。Azure Cache for Redisはキャッシュサービスでありコンテナイメージの管理には使用しません。GRSはストレージアカウントの冗長化であり、コンテナレジストリには直接適用できません。CDNは静的コンテンツの配信であり、コンテナイメージのレプリケーションには適していません。', 'compute', ARRAY['azure-storage','bcdr-fundamentals','containers','caching'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'XMLメッセージを使用した非同期通信を実装する必要があります。どのサービスを使用すべきですか？', '["A. Azure Traffic Manager", "B. Azure Notification Hubs", "C. Azure Queue Storage", "D. Azure Service Fabric"]'::jsonb, '2'::jsonb, 'Azure Queue Storageは、大量のメッセージを格納できるシンプルなキューサービスであり、XMLメッセージを含む非同期通信に適しています。メッセージの最大サイズは64KBで、キューには数百万のメッセージを格納できます。Traffic Managerはトラフィック分散のDNSベースのサービスであり、メッセージングには使用しません。Notification Hubsはプッシュ通知サービスであり、一般的な非同期メッセージングには適していません。Service Fabricはマイクロサービスプラットフォームであり、メッセージキューではありません。', 'compute', ARRAY['entra-connect','load-balancers','containers','messaging'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミスネットワーク（172.16.0.0/16）と接続するAzure仮想ネットワークのサブネット設計を行います。30台のVMを収容するSubnet1のアドレス範囲として適切なものはどれですか？', '["A. 192.168.0.0/24", "B. 172.16.0.0/16", "C. 172.16.1.0/27", "D. 192.168.1.0/27"]'::jsonb, '0'::jsonb, '192.168.0.0/24が正解です。オンプレミスネットワークが172.16.0.0/16を使用しているため、172.16.x.xのアドレス範囲は重複するため使用できません（選択肢BとCは不可）。30台のVMを収容するには、Azureの各サブネットで予約される5つのIPアドレスを考慮し、最低35個のIPアドレスが必要です。192.168.1.0/27は32個のIPアドレス（利用可能は27個）しか提供できず、30台のVMを収容できません。192.168.0.0/24は256個のIPアドレス（利用可能は251個）を提供し、30台のVMを十分に収容できます。', 'network', ARRAY['vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '同じ仮想ネットワークのゲートウェイサブネットのアドレス範囲として適切なものはどれですか？', '["A. 192.168.0.0/24", "B. 172.16.0.0/16", "C. 172.16.1.0/27", "D. 192.168.1.0/27"]'::jsonb, '3'::jsonb, '192.168.1.0/27がゲートウェイサブネットに適切です。ゲートウェイサブネットにはMicrosoftが/27以上のサイズを推奨しています。172.16.x.xのアドレス範囲はオンプレミス（172.16.0.0/16）と重複するため使用できません。192.168.0.0/24はSubnet1で使用されているため重複します。192.168.1.0/27は/27のサイズ（Microsoftの推奨最小サイズ）で、オンプレミスやSubnet1とも重複せず、ゲートウェイサブネットとして適切です。', 'network', ARRAY['vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '複数のデータベースを使用するアプリケーションをAzureに移行する必要があります。アプリケーションは「サーバー名.データベース名.テーブル名」の形式でデータにアクセスしています。どのサービスの組み合わせを使用すべきですか？', '["A. SQL Server on Azure VM", "B. SQL Server Stretch Database", "C. Azure SQL Database", "D. Azure SQL Managed Instance"]'::jsonb, '[0, 3]'::jsonb, '「サーバー名.データベース名.テーブル名」の3パート名でアクセスするには、SQL Serverのインスタンスレベルの機能が必要です。Azure SQL Managed Instance（MI）はSQL Serverとほぼ100%の互換性を持ち、クロスデータベースクエリをサポートします。SQL Server on Azure VMも完全なSQL Serverインスタンスを提供するため、この形式のアクセスが可能です。Azure SQL Databaseは単一データベースのサービスであり、クロスデータベースクエリ（3パート名）をネイティブにサポートしていません。Stretch Databaseはオンプレミスのデータをクラウドに拡張する機能であり、移行シナリオには適していません。', 'data', ARRAY['sql-database','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKSとAPI Management Standardを使用しています。MTLS（相互TLS）認証を実装し、コストを最小化する必要があります。どうすべきですか？', '["A. ExternalNameサービスを構成する", "B. 外部ロードバランサーを使用する", "C. イングレスコントローラーを使用する", "D. API Managementを再デプロイする"]'::jsonb, '2'::jsonb, 'イングレスコントローラー（例: NGINX Ingress Controller）をAKSに導入することで、MTLS認証を実装できます。これはコスト最小化の要件も満たします。API ManagementをPremiumティアに再デプロイすればVNet統合でMTLSも可能ですが、コストが大幅に増加します。ExternalNameサービスは外部DNSへのマッピングであり、MTLS認証は提供しません。外部ロードバランサーはL4レベルであり、MTLS認証の機能は提供しません。', 'network', ARRAY['load-balancers','containers','api-management','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure SQL Managed InstanceでTDE（透過的データ暗号化）を使用する場合、暗号化の強度を最大化するためのTDEプロテクターのキーサイズはどれですか？', '["A. RSA 4096", "B. RSA 3072", "C. AES 256", "D. RSA 2048"]'::jsonb, '1'::jsonb, 'Azure SQL Managed InstanceのTDEプロテクター（カスタマーマネージドキー）は、RSA 3072ビットが最大サポートサイズです。RSA 4096はAzure SQL MIのTDEプロテクターとしてはサポートされていません。AES 256はデータ暗号化キー（DEK）として使用されますが、TDEプロテクターのキータイプとしてはRSAが使用されます。RSA 2048もサポートされていますが、暗号化強度の最大化の要件にはRSA 3072が適切です。', 'security', ARRAY['sql-database','sql-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Database for MySQLでデータセンター障害に備える必要があります。コストを最小化するサービスティアはどれですか？', '["A. メモリ最適化", "B. バースト可能（Burstable）", "C. 汎用（General Purpose）"]'::jsonb, '2'::jsonb, '汎用（General Purpose）ティアは、ゾーン冗長高可用性（HA）をサポートしており、データセンター障害に備えることができます。メモリ最適化ティアもゾーン冗長HAをサポートしていますが、汎用より高コストです。バースト可能（Burstable）ティアはゾーン冗長HAをサポートしていないため、データセンター障害に対する保護ができません。コスト最小化の要件を考慮すると、ゾーン冗長HAをサポートする最も安価なティアである汎用が正解です。', 'data', ARRAY['sql-database'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Blobストレージ内の重複ファイルを検出し、管理者の承認メールを送信してから削除するサーバーレスソリューションを設計する必要があります。どのサービスの組み合わせを使用すべきですか？', '["A. Azure Logic Apps + Azure Functions", "B. Azure Functions + Azure Batch", "C. Azure Pipelines + Service Fabric", "D. Azure Logic Apps + Azure Event Grid"]'::jsonb, '0'::jsonb, 'Azure Logic Appsはスケジュール実行と承認メールのワークフローをノーコードで構築でき、Azure Functionsは重複ファイルの検出と削除のカスタムスクリプトを実行できます。両方ともサーバーレスです。Azure Batchはバッチ処理サービスですがサーバーレスではありません。Azure PipelinesはCI/CDツールであり、このシナリオには適していません。Service Fabricはマイクロサービスプラットフォームでありサーバーレスではありません。Event Gridはイベントルーティングサービスですが、承認メールのワークフローには対応していません。', 'compute', ARRAY['containers','azure-functions','batch','event-driven','api-management'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure サブスクリプションでステートレス Web アプリをホストするには、リソースをデプロイする必要があります。ソリューションは次の要件を満たす必要があります。 解決策: Web アプリを Isolated App Service プランにデプロイします。 これは目標を達成していますか。・ 完全な .NET Frameworkへのアクセスを提供する。・ Azure リージョンに障害が発生した場合に冗長性を提供する。・ カスタム アプリケーションの依存関係をインストールするためのオペレーティング システムへのアクセスを管理者に許可する。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, '解決策の代わりに、2 つの Azure 仮想マシンを 2 つの Azure リージョンにデプロイし、Azure Traffic Manager プロファイルを作成します。https://docs.microsoft.com/ja-jp/azure/traffic-manager/traffic-manager-overview', '', ARRAY['subscription-design','azure-storage','load-balancers','virtual-machines','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の表に示すリソースを含む Azure サブスクリプションを持っています。 VNet1 と VNet2 の間、および VNet1 と VNet3 の間にピアリングを作成します。 仮想マシンは HTTPS ベースのクライアント/サーバー アプリケーションをホストし、各仮想マシンのプライベート IP アドレスを介してのみアクセスできます。 VM2 と VM3 の負荷分散ソリューションを実装する必要があります。ソリューションでは、VM2 に障害が発生した場合にはリクエストが自動的に VM3 にルーティングされ、VM3 に障害が発生した場合にはリクエストが自動的に VM2 にルーティングされるようにする必要があります。 ソリューションには何を含めるべきでしょうか。名前 | タイプ | 説明------------------------------VM1 | 仮想マシン | 米国中部 Azure リージョンのフロントエンド コンポーネントVM2 | 仮想マシン | 米国東部 Azure リージョンのバックエンド コンポーネントVM3 | 仮想マシン | 米国西部 2 Azure リージョンのバックエンド コンポーネントVNet1 |仮想ネットワーク | VM1にホストVNet2 |仮想ネットワーク | VM2にホストVNet3 | 仮想ネットワーク | VM3にホスト', '["リージョン間のロード バランサー", "Azure Firewall Premium", "Azure Application Gateway v2", "Azure Front Door Premium"]'::jsonb, '3'::jsonb, 'Azure Front Door Premium は、仮想ネットワークから Azure で実行されているサービスへのプライベート接続を可能にする Private Link をサポートします。この機能を使用すると、リージョン間のサービスにプライベートに接続できるため、VM2 が米国東部にあり、VM3 が米国西部にあるユースケースで機能します。Azure Front Door Premium は、Private Link を使用してセットアップして、地域ネットワーク内にプライベート エンドポイントを作成できます。このネットワークは、パブリック インターネットに公開することなく、Microsoft バックボーン ネットワーク上のプライベート リンクを介して VM2 および VM3 にトラフィックをルーティングできます。 1 つの VM に障害が発生した場合、Azure Front Door は自動的にトラフィックを他の VM にルーティングし、アプリケーションの可用性を維持します。https://learn.microsoft.com/ja-jp/azure/frontdoor/front-door-faq#azure-front-door---azure-application-gateway----------', '', ARRAY['subscription-design','load-balancers','virtual-machines','vnet','private-link','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、Azure SQL データベースを使用するさまざまな Azure App Service インスタンスをデプロイすることを計画しています。 App Service インスタンスは、Azure SQL データベースと同時にデプロイされます。 同社には、App Service インスタンスを特定の Azure リージョンにのみデプロイするという規制要件があります。 App Service インスタンスのリソースは同じリージョンに存在する必要があります。 規制要件を満たすソリューションを推奨する必要があります。 解決策: Azure Policy イニシアチブを使用して、リソース グループの場所を強制することをお勧めします。 これは目標を達成していますか。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, 'リソースグループ の場所は、リソースグループ 内のリソースの場所とは関係ありません。リソース グループは、「許可された場所」ポリシーから除外されます。 リソース グループを作成できる場所を制限する場合は、「リソース グループに許可された場所」ポリシーを使用してください。参考として、許可された場所のポリシー定義の説明を以下に示します。このポリシーを使用すると、リソースを展開するときに組織が指定できる場所を制限できます。 地理的コンプライアンス要件を強制するために使用します。 リソース グループ、Microsoft.AzureActiveDirectory/b2cDirectories、および「グローバル」リージョンを使用するリソースは除外されます。', '', ARRAY['azure-policy','purview','sql-database','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'サードパーティのスケジューラを使用するハイ パフォーマンス コンピューティング (HPC) クラスターを Azure にプロビジョニングする予定です。 HPC クラスター ノードをプロビジョニングおよび管理するためのソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["Azure Purview", "Azure Automation", "Azure Lighthouse", "Azure CycleCloud"]'::jsonb, '3'::jsonb, 'Azure CycleCloud を使用して Azure HPC クラスターを動的にプロビジョニングできます。Azure CycleCloud は、Azure 上のハイ パフォーマンス コンピューティング (HPC) 環境を調整および管理するためのエンタープライズ向けツールです。 CycleCloud を使用すると、ユーザーは HPC システムのインフラストラクチャをプロビジョニングし、使い慣れた HPC スケジューラをデプロイし、インフラストラクチャを自動的にスケーリングして、任意の規模でジョブを効率的に実行できます。 CycleCloud を使用して、ユーザーはさまざまな種類のファイル システムを作成し、コンピューティング クラスター ノードにマウントして HPC ワークロードをサポートできます。https://learn.microsoft.com/ja-jp/azure/cyclecloud/overview?view=cyclecloud-8', '', ARRAY['lighthouse','purview','batch','automation-deploy'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、ニューヨーク市、シドニー、パリ、ヨハネスブルグにオフィスを構えています。 会社は Azure サブスクリプションを持っています。 次の要件を満たす新しい Azure ネットワーク ソリューションをデプロイする予定です。 デプロイする必要がある Azure 仮想 WAN ハブの最小数と、使用する仮想 WAN SKU を特定する必要があります。 次のうちどれを選択しますか。 仮想 WAN ハブの数:・ 米国東部、東南アジア、北ヨーロッパ、南アフリカの Azure リージョンの ExpressRoute 回線に接続する。・ 3 つのリージョンでの接続をサポートすることで遅延を最小限に抑える。・ サイト間 VPN 接続をサポートする。・ コストを最小限に抑える。', '["1", "2", "3", "4"]'::jsonb, '3'::jsonb, '「3 つのリージョンでの接続をサポートすることで遅延を最小限に抑える」という要件は、3 つのリージョン間で接続を最適化する必要があることを示唆しています。ただし、ソリューションは、米国東部、東南アジア、北ヨーロッパ、南アフリカの 4 つの特定の Azure リージョンの ExpressRoute 回線にも接続する必要があります。これらすべての要件を満たすには、これら 4 つのリージョンのそれぞれにハブをデプロイする必要があります。これにより、各リージョンにローカル接続ポイントが確保され、待ち時間が短縮されます。接続は 3 つのリージョンにわたって最適化されていますが、4 つのリージョンにローカル接続ポイントを提供するには 4 つのハブが必要です。1 つの要件に基づくと 3 つのハブで十分であるように考えられますが、すべての要件を考慮すると 4 つのハブが必要です。', '', ARRAY['subscription-design','on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、ニューヨーク市、シドニー、パリ、ヨハネスブルグにオフィスを構えています。 会社は Azure サブスクリプションを持っています。 次の要件を満たす新しい Azure ネットワーク ソリューションをデプロイする予定です。 デプロイする必要がある Azure 仮想 WAN ハブの最小数と、使用する仮想 WAN SKU を特定する必要があります。 次のうちどれを選択しますか。 仮想 WAN SKU:・ 米国東部、東南アジア、北ヨーロッパ、南アフリカの Azure リージョンの ExpressRoute 回線に接続する。・ 3 つのリージョンでの接続をサポートすることで遅延を最小限に抑える。・ サイト間 VPN 接続をサポートする。・ コストを最小限に抑える。', '["Standard", "Basic"]'::jsonb, '0'::jsonb, 'Basic: サイト間 VPN のみサポートします。Standard: 以下をサポートします。ExpressRouteユーザー VPN (P2S)VPN (サイト対サイト)仮想ハブを経由したハブ間および VNet 対 VNet トランジットAzure Firewall仮想 WAN の NVAhttps://learn.microsoft.com/ja-jp/azure/virtual-wan/virtual-wan-about#basicstandard', '', ARRAY['subscription-design','vnet','on-premises-connectivity','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure サブスクリプションを持っています。 Linux ノードを使用する Azure Kubernetes Service (AKS) ソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 どのスケーリング オプションをお勧めしますか。・ スケールアウト操作中にコンピューティング リソースをプロビジョニングするのにかかる時間を最小限に抑える。・ Linux コンテナの自動スケーリングをサポートする。・ 管理労力を最小限に抑える。', '["クラスターオートスケーラー", "Virtual Kubelet", "水平 Pod オートスケーラー", "仮想ノード"]'::jsonb, '3'::jsonb, 'AKS クラスターでアプリケーション ワークロードをすばやくスケーリングするには、仮想ノードを使用します。 仮想ノードを使用すると、ポッドを短時間でプロビジョニングできるため、ポッドの実行時間に対して秒単位の支払いだけで済みます。 Kubernetes クラスターのオートスケーラーが VM コンピューティング ノードをデプロイしてより多くのポッドを実行するのを待つ必要はありません。 仮想ノードは、Linux のポッドとノードでのみサポートされます。https://learn.microsoft.com/ja-jp/azure/aks/virtual-nodes', '', ARRAY['subscription-design','vmss','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Microsoft Entra ID ユーザーがオンライン アンケートを作成して公開できるようにする、サービスとしてのソフトウェア (SaaS) アプリケーションを設計しています。 SaaS アプリケーションにはフロントエンド Web アプリとバックエンド Web API があります。 Web アプリは、Web API を利用して顧客調査の更新を処理します。 SaaS アプリケーションの認証フローを設計する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 アクセス トークンは次によって生成される。・ バックエンド Web API にアクセスするには、Web アプリは OAuth 2.0ベアラートークンを使用して認証する必要がある。・ Web アプリは、個々のユーザーの ID を使用して認証する必要がある。', '["ウェブアプリ", "Web API", "Microsoft Entra ID"]'::jsonb, '2'::jsonb, 'Auth 2.0 は、認可用の業界プロトコルです。 ユーザーは保護されたリソースへの制限付きアクセスを許可できます。 OAuth は、特にハイパーテキスト転送プロトコル (HTTP) を使用するように設計されているため、クライアントの役割がリソース所有者から分離されます。 クライアントでは、リソース所有者によって制御され、リソース サーバーでホストされるリソースへのアクセスが要求されます。 リソース サーバーでは、リソース所有者の承認を使用してアクセス トークンが発行されます。 クライアントはアクセス トークンを使用して、リソース サーバーでホストされる保護されたリソースにアクセスします。OAuth 2.0 は、OpenID Connect (OIDC) に直接関連しています。 OIDC は OAuth 2.0 上に構築された認証と認可の層であるため、OAuth 1.0 との下位互換性がありません。 Microsoft Entra ID では、すべての OAuth 2.0 フローがサポートされています。https://learn.microsoft.com/ja-jp/entra/architecture/auth-oauth2', '', ARRAY['entra-id','alerts','app-service'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Microsoft Entra ID ユーザーがオンライン アンケートを作成して公開できるようにする、サービスとしてのソフトウェア (SaaS) アプリケーションを設計しています。 SaaS アプリケーションにはフロントエンド Web アプリとバックエンド Web API があります。 Web アプリは、Web API を利用して顧客調査の更新を処理します。 SaaS アプリケーションの認証フローを設計する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 認可の決定は以下によって実行される。・ バックエンド Web API にアクセスするには、Web アプリは OAuth 2.0ベアラートークンを使用して認証する必要がある。・ Web アプリは、個々のユーザーの ID を使用して認証する必要がある。', '["ウェブアプリ", "Web API", "Microsoft Entra ID"]'::jsonb, '1'::jsonb, '委任されたアクセスが使用されます。Web API に送信されるベアラー トークンには、ユーザー ID が含まれています。Web API は、ユーザー ID に基づいて認可を決定します。https://learn.microsoft.com/ja-jp/azure/architecture/guide/multitenant/considerations/identity', '', ARRAY['entra-id','alerts','app-service'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の要件を満たす高可用性 Azure SQL データベースを設計する必要があります。 どのデプロイ オプションを使用する必要がありますか。・ データベースのレプリカ間のフェイルオーバーは、データを失わずに実行する必要がある。・ ゾーンが停止した場合でも、データベースは利用可能な状態を維持する必要がある。・ コストは最小限に抑える必要がある。', '["Azure SQL Database Business Critical", "Azure SQL Database Basic", "Azure SQL Managed Instance General Purpose", "Azure SQL Database Standard"]'::jsonb, '0'::jsonb, 'Azure SQL Database Business Critical レベルは、フェールオーバー中にデータ損失がゼロで高可用性を提供するように設計されており、シナリオの主な要件の 1 つを満たします。さらに、Azure SQL Database Business Critical レベルではゾーン冗長構成が提供されます。これは、データのレプリカが異なる可用性ゾーンに保存されることを意味します。これは、ゾーンが停止した場合でもデータベースが利用可能な状態を維持し、シナリオの別の要件を満たしていることを意味します。Azure SQL Managed Instance General Purpose は、単一リージョン内で自動バックアップと高可用性を提供しますが、必要なゾーン冗長性はサポートしていません。Business Critical レベルは高価に見えるかもしれませんが、要件はコストを最小限に抑えることであり、最も安価なオプションを選択することではないことに注意してください。高可用性とデータ損失ゼロの要件を考慮すると、Business Critical 層が最もコスト効率の高い選択肢となります。https://learn.microsoft.com/ja-jp/azure/azure-sql/database/sql-database-paas-overview?view=azuresql#service-tiers', '', ARRAY['azure-storage','sql-database','bcdr-fundamentals','availability-zones','azure-backup','site-recovery','storage-redundancy'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Contoso, Ltd. という名前の Microsoft ボリューム ライセンスのお客様の、データベース環境を管理しています。Contoso はソフトウェア アシュアランスによるライセンス モビリティを使用しています。 50 個のデータベースをデプロイする必要があります。 ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 購入ケースモデル:・ 自動スケーリングをサポートする。・ Microsoft SQL Server のライセンス コストを最小限に抑える。', '["仮想コア", "DTU", "Azure 予約仮想マシン インスタンス"]'::jsonb, '0'::jsonb, 'Azure ハイブリッド ライセンス モデルを適用できるのは、Azure SQL Database に対して、仮想コア ベースの購入モデルとプロビジョニングされたコンピューティング レベルを選択した場合に限られます。 Azure ハイブリッド特典は、DTU ベースの購入モデル下のサービス レベル、またはサーバーレス コンピューティング レベルでは利用できません。https://docs.microsoft.com/ja-jp/azure/azure-sql/azure-hybrid-benefit', '', ARRAY['entra-license','sql-database','vmss','virtual-machines','azure-functions'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Contoso, Ltd. という名前の Microsoft ボリューム ライセンスのお客様の、データベース環境を管理しています。Contoso はソフトウェア アシュアランスによるライセンス モビリティを使用しています。 50 個のデータベースをデプロイする必要があります。 ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 デプロイメント オプション:・ 自動スケーリングをサポートする。・ Microsoft SQL Server のライセンス コストを最小限に抑える。', '["Azure SQL Managed Instance", "SQL Server Always On 可用性グループ", "Azure SQL Database エラスティック プール"]'::jsonb, '2'::jsonb, 'Azure SQL Database のエラスティック プールは、使用ニーズが多様で予測不可能な複数のデータベースを管理およびスケーリングするための、シンプルでコスト効率に優れたソリューションです。 エラスティック プール内のデータベースは、単一のサーバー上にあり、設定された数のリソースを設定価格で共有します。 SQL Database のエラスティック プールを使用すると、サービスとしてのソフトウェア (SaaS) の開発者は、各データベースのパフォーマンスに弾力性を持たせながら、データベース グループの価格に対するパフォーマンスを所定の予算内で最適化できます。https://learn.microsoft.com/ja-jp/azure/azure-sql/database/elastic-pool-overview?view=azuresql', '', ARRAY['entra-license','cost-management','sql-database','vmss','sql-ha'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Contoso, Ltd. という名前の会社は、※1のリソースを含む Azure サブスクリプションを持っています。 Contoso の製品データが contososql1 から contosolake1 にコピーされました。 Contoso には、Fabrikam Inc. というパートナー会社があります。Fabrikam には、※2のリソースを含む Azure サブスクリプションがあります。 Contoso は、FabrikamVM1 の研究データを contosolake1 にアップロードする予定です。アップロード中に、研究データを Contoso が使用するデータ形式に変換する必要があります。 contosolake1 のデータは contosoworkspace1 を使用して分析されます。 このとき、※3の要件を満たすソリューションを推奨する必要があります。 それぞれの要件に対して何を推奨する必要がありますか。 データをアップロードして変換する:※1・ contosoworkspace1 という名前の Azure Synapse Analytics ワークスペース・ contosolake1 という名前の Azure Data Lake Storage アカウント・ contososql1 という名前の Azure SQL データベース※2・ Microsoft SQL Server 2019 を実行する FabrikamVM1 という名前の仮想マシン・ fabrikamsa1 という名前の Azure ストレージ アカウント※3・ FabrikamVM1 研究データをアップロードして変換する。・ contosoworkspace1 内のデータのスナップショットへの制限付きアクセスを Fabrikam に提供する。', '["Azure Data Box Gateway", "Azure Data Share", "Azure Synapse パイプライン"]'::jsonb, '2'::jsonb, 'ETL 操作を実現するには Azure Data Factory を使用する必要があります。Azure Synapse Analytics の Synapse パイプラインやデータ フローなどのデータ統合機能は、Azure Data Factory の機能に基づいています。https://learn.microsoft.com/ja-jp/azure/synapse-analytics/data-integration/concepts-data-factory-differences', '', ARRAY['subscription-design','log-analytics','azure-storage','sql-database','data-analytics','virtual-machines','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Contoso, Ltd. という名前の会社は、※1のリソースを含む Azure サブスクリプションを持っています。 Contoso の製品データが contososql1 から contosolake1 にコピーされました。 Contoso には、Fabrikam Inc. というパートナー会社があります。Fabrikam には、※2のリソースを含む Azure サブスクリプションがあります。 Contoso は、FabrikamVM1 の研究データを contosolake1 にアップロードする予定です。アップロード中に、研究データを Contoso が使用するデータ形式に変換する必要があります。 contosolake1 のデータは contosoworkspace1 を使用して分析されます。 このとき、※3の要件を満たすソリューションを推奨する必要があります。 それぞれの要件に対して何を推奨する必要がありますか。 制限付きアクセスを提供する:※1・ contosoworkspace1 という名前の Azure Synapse Analytics ワークスペース・ contosolake1 という名前の Azure Data Lake Storage アカウント・ contososql1 という名前の Azure SQL データベース※2・ Microsoft SQL Server 2019 を実行する FabrikamVM1 という名前の仮想マシン・ fabrikamsa1 という名前の Azure ストレージ アカウント※3・ FabrikamVM1 研究データをアップロードして変換する。・ contosoworkspace1 内のデータのスナップショットへの制限付きアクセスを Fabrikam に提供する。', '["Azure Data Box Gateway", "Azure Synapse パイプライン", "Azure Data Share"]'::jsonb, '2'::jsonb, 'Azure Data Share を使用すると、組織は複数のお客様やパートナーとデータを安全に共有できます。 データ プロバイダーでは共有したデータが常に管理下に置かれるため、Azure Data Share を使用すると、どのデータが、いつ、誰によって共有されたかを簡単に管理し、監視することができます。この場合、スナップショットベースの共有を使用する必要があります。https://learn.microsoft.com/ja-jp/azure/data-share/overview', '', ARRAY['subscription-design','azure-monitor','log-analytics','azure-storage','sql-database','data-analytics','virtual-machines','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ミッションクリティカルなアプリケーションの記録用のストレージ ソリューションを推奨する必要があります。ソリューションでは、書き込み操作の待ち時間とスループットに関するサービス レベル アグリーメント (SLA) を提供する必要があります。 推奨事項には何を含めるべきですか。', '["Azure Data Lake Storage Gen2", "Azure Cosmos DB", "Azure SQL", "Azure Blob Storage"]'::jsonb, '1'::jsonb, 'Azure Cosmos DB は、グローバルに分散されたマルチモデル データベース サービスです。スループット、遅延、可用性、一貫性をカバーする包括的なサービス レベル アグリーメント (SLA) を提供します。他の選択肢では、レイテンシーとスループットの両方に対する SLA は提供されません。https://learn.microsoft.com/ja-jp/azure/cosmos-db/introduction', '', ARRAY['blob-storage','cosmosdb','data-analytics'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社には、次の表に示す部門があります。 Sub1 には、App1 という名前の Azure App Service Web アプリが含まれています。 App1 は、シングルテナントのユーザー認証に Microsoft Entra ID を使用します。 contoso.com のユーザーは App1 に対して認証できます。 fabrikam.com テナント内のユーザーが App1 に対して認証できるようにするソリューションを推奨する必要があります。 何を勧めるべきですか。部門 | Azure サブスクリプション | Microsoft Entra テナント-------------------------------------------------- -------------East | Sub1 | Contoso.comWest | Sub2 | Fabrikam.com', '["Microsoft Entra ID Protection を構成する。", "条件付きアクセス ポリシーを構成する。", "Microsoft Entra ID エンタイトルメント管理を使用して外部ユーザーを管理する。", "Microsoft Entra ID プロビジョニング サービスを構成する。"]'::jsonb, '2'::jsonb, 'エンタイトルメント管理接続先の組織を選択して、その組織のユーザーがアクセス権を要求できるようにすることができます。 ディレクトリにまだ存在しないユーザーがアクセス権を要求し、それが承認されると、そのユーザーは自動的にディレクトリに招待され、アクセス権を割り当てられます。 アクセス権の有効期限が切れ、かつ他のアクセス パッケージが割り当てられていない場合には、ディレクトリ内の B2B アカウントを自動的に削除できます。https://learn.microsoft.com/ja-jp/entra/id-governance/entitlement-management-overview', '', ARRAY['entra-id','external-users','entra-governance','conditional-access','subscription-design','app-service'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミス ネットワークと Azure サブスクリプションがあります。オンプレミス ネットワークには複数のブランチ オフィスがあります。 トロント支社のオフィスには、ファイル サーバーとして構成された VM1 という名前の仮想マシンがあります。ユーザーはすべてのオフィスから VM1 上の共有ファイルにアクセスします。 トロント支社にアクセスできない場合に、ユーザーが共有ファイルにできるだけ早くアクセスできるようにするソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["Azure File 共有 と Azure File Sync", "Recovery Services コンテナーと Windows Server バックアップ", "Recovery Services コンテナーと Azure Backup", "Azure BLOB コンテナーと Azure File Sync"]'::jsonb, '0'::jsonb, 'オンプレミス ネットワークと Azure サブスクリプションがあります。オンプレミス ネットワークには複数のブランチ オフィスがあります。 トロント支社のオフィスには、ファイル サーバーとして構成された VM1 という名前の仮想マシンがあります。ユーザーはすべてのオフィスから VM1 上の共有ファイルにアクセスします。 トロント支社にアクセスできない場合に、ユーザーが共有ファイルにできるだけ早くアクセスできるようにするソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '', ARRAY['subscription-design','bcdr-fundamentals','azure-backup','file-sync','virtual-machines','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ある企業は、Web アプリをサポートするために HTTP ベースの API を実装することを計画しています。 Web アプリを使用すると、顧客は注文のステータスを確認できます。 API は次の要件を満たす必要があります。 どの HTTP メソッドと認証レベルを構成するかを推奨する必要があります。 何を勧めるべきですか。 HTTP メソッド:・ Azure Functions を実装する。・ パブリック (読み取り専用)を提供する。・ 書き込み操作を禁止する。', '["GET と POST のみ", "GET、POST、OPTIONSのみ", "APIメソッド", "GETのみ"]'::jsonb, '3'::jsonb, 'GET API はパブリック読み取り専用操作を提供するだけであるため、データを取得するには GET メソッドで十分です。', '', ARRAY['app-service','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ある企業は、Web アプリをサポートするために HTTP ベースの API を実装することを計画しています。 Web アプリを使用すると、顧客は注文のステータスを確認できます。 API は次の要件を満たす必要があります。 どの HTTP メソッドと認証レベルを構成するかを推奨する必要があります。 何を勧めるべきですか。 認証レベル:・ Azure Functions を実装する。・ パブリック (読み取り専用)を提供する。・ 書き込み操作を禁止する。', '["匿名", "管理者", "関数"]'::jsonb, '0'::jsonb, '認証レベル: 匿名API は読み取り専用操作のためにパブリックにアクセスできる必要があるため、認証や承認を必要とせずに無制限のアクセスを許可するには、匿名承認レベルを使用する必要があります。', '', ARRAY['app-service','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Application1 と Application2 という 2 つのアプリケーションに対して Azure ストレージ アカウント構成を推奨する必要があります。構成は次の要件を満たす必要があります。 このとき、何を勧めるべきですか。 Application1:・ Application1 のストレージは、可能な限り高いトランザクション レートと可能な限り低い遅延を提供する必要がある。・ Application2 のストレージは、GB あたりのストレージ コストを可能な限り低くする必要がある。・ データセンターに障害が発生した場合でも、両方のアプリケーションのストレージが利用可能でなければならない。・ 両方のアプリケーションのストレージは、アップロードとダウンロード用に最適化する必要がある。', '["Premium パフォーマンスとゾーン冗長ストレージ (ZRS) レプリケーションを備えた ブロックBLOB ストレージ", "Standard パフォーマンス、ホット アクセス層、ローカル冗長ストレージ (LRS) レプリケーションを備えた汎用 v2", "Standard パフォーマンス、ホット アクセス層、読み取りアクセス地理冗長ストレージ (RA-GRS) レプリケーションを備えた BLOB ストレージ", "Premium パフォーマンスとローカル冗長ストレージ (LRS) レプリケーションを備えた汎用 v1"]'::jsonb, '0'::jsonb, 'Premium パフォーマンスとゾーン冗長ストレージ (ZRS) レプリケーションを備えた ブロックBLOB ストレージApplication1 は、高いトランザクション レートと可能な限り低い遅延を必要とします。 Standard ではなく、Premium を使用する必要があります。https://docs.microsoft.com/ja-jp/azure/storage/common/storage-account-upgrade', '', ARRAY['resource-locks','azure-storage','blob-storage','bcdr-fundamentals'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Application1 と Application2 という 2 つのアプリケーションに対して Azure ストレージ アカウント構成を推奨する必要があります。構成は次の要件を満たす必要があります。 このとき、何を勧めるべきですか。 Application2:・ Application1 のストレージは、可能な限り高いトランザクション レートと可能な限り低い遅延を提供する必要がある。・ Application2 のストレージは、GB あたりのストレージ コストを可能な限り低くする必要がある。・ データセンターに障害が発生した場合でも、両方のアプリケーションのストレージが利用可能でなければならない。・ 両方のアプリケーションのストレージは、アップロードとダウンロード用に最適化する必要がある。', '["Standard パフォーマンス、ホット アクセス層、読み取りアクセス geo 冗長ストレージ (RA-GRS) レプリケーションを備えた BLOB ストレージ", "Standard パフォーマンス、ホット アクセス層、読み取りアクセス geo 冗長ソストレージ (RA-GRS) レプリケーションを備えた BLOBストレージ", "Standard パフォーマンス、クール アクセス層、読み取りアクセス geo 冗長ストレージ (RA-GRS) レプリケーションを備えた汎用 v2", "Premium パフォーマンスとゾーン冗長ストレージ (ZRS) レプリケーションを備えた ブロックBLOB ストレージ"]'::jsonb, '2'::jsonb, 'Standard パフォーマンスの汎用 v2、..汎用 v2 ストレージ アカウントは、最新の Azure Storage の機能をサポートし、汎用 v1 と BLOB ストレージ アカウントのすべての機能が組み込まれています。 ほとんどのストレージ シナリオに汎用 v2 アカウントをお勧めします。 汎用 v2 アカウントは、業界内の他社に引けを取らないトランザクション料金で、Azure Storage に対してギガバイトあたり容量の最低価格を提供しています。 汎用 v2 アカウントでは、ホットまたはクールの既定のアカウント アクセス層と、ホット、クール、またはアーカイブ間の BLOB レベル階層がサポートされます。https://docs.microsoft.com/ja-jp/azure/storage/common/storage-account-upgrade', '', ARRAY['resource-locks','azure-storage','blob-storage','bcdr-fundamentals'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ファイル共有をホストする Azure ストレージ アカウントを作成する予定です。共有には、トランザクション集中型のオンプレミス アプリケーションからアクセスします。 ファイル共有にアクセスする際の遅延を最小限に抑えるソリューションを推奨する必要があります。ソリューションは、選択したストレージ層に最高レベルの復元力を提供する必要があります。 推奨事項には何を含めるべきですか。 ストレージ層:', '["Premium", "ホット", "トランザクション 最適化"]'::jsonb, '0'::jsonb, 'Premium:Premium ファイル共有は、ソリッド ステート ドライブ (SSD) によってサポートされており、IO 集中型ワークロードで一貫した優れたパフォーマンスと待機時間 (ほとんどの IO 操作で 1 桁のミリ秒以内の低待機時間) を提供します。 Premium ファイル共有は、データベース、Web サイトのホスティング、開発環境など、幅広い種類のワークロードに適しています。 Premium ファイル共有は、サーバー メッセージ ブロック (SMB) プロトコルとネットワーク ファイル システム (NFS) プロトコルの両方で使用できます。 トランザクション最適化:トランザクション最適化ファイル共有は、Premium ファイル共有が提供する待機時間を必要としない、トランザクション負荷の高いワークロードを可能にします。 トランザクション最適化ファイル共有は、ハード ディスク ドライブ (HDD) によってサポートされている標準ストレージ ハードウェアで提供されます。 トランザクション最適化は、従来は "Standard" と呼ばれていましたが、これはサービス レベル自体ではなく、ストレージ メディアの種類を指しています (ホットおよびクールも、標準ストレージ ハードウェア上にあるため、"Standard" サービス レベルです)。 Hot:ホット ファイル共有は、チーム共有などの汎用ファイル共有シナリオに最適化されたストレージを提供します。 ホット ファイル共有は、HDD によってサポートされている標準ストレージ ハードウェアで提供されます。 Cool:クール ファイル共有は、オンライン アーカイブ ストレージのシナリオ向けに最適化された、コスト効率に優れたストレージを提供します。 クール ファイル共有は、HDD によってサポートされている標準ストレージ ハードウェアで提供されます。https://docs.microsoft.com/ja-jp/azure/storage/files/storage-files-planning', '', ARRAY['resource-locks','azure-storage','blob-storage'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ファイル共有をホストする Azure ストレージ アカウントを作成する予定です。共有には、トランザクション集中型のオンプレミス アプリケーションからアクセスします。 ファイル共有にアクセスする際の遅延を最小限に抑えるソリューションを推奨する必要があります。ソリューションは、選択したストレージ層に最高レベルの復元力を提供する必要があります。 推奨事項には何を含めるべきですか。 冗長性:', '["ローカル冗長ストレージ (LRS)", "Geo 冗長ストレージ (GRS)", "ゾーン冗長ストレージ (ZRS)"]'::jsonb, '2'::jsonb, 'ローカル冗長ストレージ (LRS) : LRS では、すべてのファイルが Azure ストレージ クラスター内に 3 回保存されます。 これにより、不良ディスク ドライブなどのハードウェア障害によるデータ損失を防ぐことができます。 ただし、データ センター内で火災や洪水などの災害が発生した場合は、LRS を使用しているストレージ アカウントのすべてのレプリカが失われたり、回復不能になったりする可能性があります。ゾーン冗長ストレージ (ZRS): ZRS では、各ファイルのコピーが 3 つ格納されます。 ただし、これらのコピーは物理的に異なる Azure 可用性ゾーン にある 3 つの異なるストレージ クラスターに分離されます。 可用性ゾーンは、Azure リージョン内の一意の物理的な場所です。 それぞれのゾーンは、独立した電源、冷却手段、ネットワークを備えた 1 つまたは複数のデータ センターで構成されています。 3 つの可用性ゾーンすべてのストレージ クラスターに書き込まれるまで、ストレージに書き込むことはできません。Geo 冗長ストレージ (GRS): GRS では、プライマリ リージョンとセカンダリ リージョンの 2 つのリージョンがあります。 ファイルは、プライマリ リージョンの Azure ストレージ クラスター内に 3 回保存されます。 書き込みは、Microsoft によって定義されたセカンダリ リージョンに非同期的にレプリケートされます。 GRS では、データの 6 つのコピーが 2 つの Azure リージョン間で分散して作成されます。 自然災害や他の同様の事象により Azure リージョンが完全に失われる場合など、重大な災害が発生した場合は、Microsoft によってフェールオーバーが実行されます。 この場合は、セカンダリがプライマリになり、すべての操作が行われます。 プライマリ リージョンとセカンダリ リージョンの間のレプリケーションは非同期であるため、重大な災害が発生した場合、セカンダリ リージョンにまだレプリケートされていないデータは失われます。 geo 冗長ストレージ アカウントのフェールオーバーは、手動で実行することもできます。https://docs.microsoft.com/ja-jp/azure/storage/files/storage-files-planning', '', ARRAY['entra-connect','azure-storage','bcdr-fundamentals','availability-zones','site-recovery','storage-redundancy'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '10 個のオンプレミス SQL Server データベースを宛先として使用するように構成された 100 個の Microsoft SQL Server Integration Services (SSIS) パッケージがあります。 10 個のオンプレミス データベースを Azure SQL Database に移行することを計画しています。 Azure-SQL Server Integration Services (SSIS) パッケージを作成するためのソリューションを推奨する必要があります。ソリューションでは、パッケージが以下をターゲットにできることを保証する必要があります。 SQL Database インスタンスを宛先として使用します。 推奨事項には何を含めるべきですか。', '["SQL Server Migration Assistant (SSMA)", "Data Migration Assistant (DMA)", "Azure Data Catalog", "Azure Data Factory"]'::jsonb, '3'::jsonb, 'データベース ワークロードをオンプレミスの SQL Server から Azure データベース サービス (つまり Azure SQL Database または Azure SQL Database Managed Instance) に移行する場合、主要な付加価値サービスの 1 つとして SQL Server Integration Services (SSIS) の ETL ワークロードも同様に移行する必要があります。 Azure Data Factory (ADF) またはシナプス パイプラインの Azure-SSIS Integration Runtime (IR) では、SSIS パッケージの実行をサポートしています。 Azure-SSIS IR がプロビジョニングされると、SQL Server Data Tools (SSDT)/SQL Server Management Studio (SSMS) などの使い慣れたツールや dtinstall/dtutil/dtexec などのコマンドライン ユーティリティを使用して、Azure でパッケージをデプロイして実行できます。 https://learn.microsoft.com/ja-jp/azure/data-factory/scenario-ssis-migration-overview', '', ARRAY['sql-database','data-analytics','data-migration','db-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、複数の Azure クラウド サービスを含み、トランザクションのさまざまなコンポーネントを処理する販売アプリケーションを開発しています。さまざまなクラウド サービスが顧客の注文、請求、支払い、在庫、発送を処理します。 XML メッセージを使用してクラウド サービスがトランザクション情報を非同期に通信できるようにするソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["Azure Data Lake", "Azure Service Fabric", "Azure Traffic Manager", "Azure Service Bus"]'::jsonb, '3'::jsonb, 'Azure Service Bus は、メッセージ キューとパブリッシュとサブスクライブ トピックを (名前空間内に) 備えたフル マネージド エンタープライズ統合メッセージ ブローカーです。 Service Bus は、アプリケーションとサービスを相互に分離するために使用され、次のような利点があります。 競合する worker 間での作業の負荷分散 サービスやアプリケーションの境界を越えたデータと制御の安全なルーティングおよび転送 高い信頼性を必要とするトランザクション作業の調整 https://learn.microsoft.com/ja-jp/azure/service-bus-messaging/service-bus-messaging-overview', '', ARRAY['entra-connect','data-analytics','load-balancers','containers','messaging'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '米国西部 Azure リージョンに KeyVault1 という名前の Azure Key Vault を使用する Azure Web アプリがあります。 あなたは、KeyVault1 の災害復旧計画を設計しています。 KeyVault1 にキーをバックアップする予定です。 バックアップをどこに復元できるかを特定する必要があります。 次のうちどれを選択する必要がありますか。', '["同じリージョンのみ", "KeyVault1のみ", "世界中全てのリージョン", "同じ地域のみ"]'::jsonb, '3'::jsonb, 'キー コンテナー オブジェクト (シークレット、キー、証明書など) をバックアップすると、そのオブジェクトは、バックアップ操作によって、暗号化された BLOB としてダウンロードされます。 Azure の外部でこの BLOB の暗号化を解除することはできません。 この BLOB から有効なデータを取得するには、同じ Azure サブスクリプションと Azure 地域内のキー コンテナーに BLOB を復元する必要があります。https://learn.microsoft.com/ja-jp/azure/key-vault/general/backup?tabs=azure-cli', '', ARRAY['subscription-design','key-vault','bcdr-fundamentals','azure-backup','site-recovery','app-service','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '複数の Azure リージョンにわたって複数のインスタンスを持つ Azure App Service Web アプリをデプロイすることを計画しています。 計画された展開に対して負荷分散サービスを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。・ 地域的な停電が発生した場合でも、アプリへのアクセスを維持する。・ Azure Web アプリケーション ファイアウォール (WAF) をサポートする。・ Cookie ベースのアフィニティをサポートする。・ URL ルーティングをサポートする。', '["Azure Front Door", "Azure Load Balancer", "Azure Traffic Manager", "Azure Application Gateway"]'::jsonb, '0'::jsonb, 'Azure Application Gateway はリージョン内のトラフィックを分散するリージョン サービスであるのに対し、Azure Front Door はリージョン間でトラフィックを分散するグローバル サービスです。Azure Application Gateway と Azure Front Door は両方ともほとんどの要件を満たしていますが、重要な要件はクロスリージョンのサポートです。https://learn.microsoft.com/ja-jp/azure/frontdoor/front-door-faq#what-is-the-difference-between-azure-front-door-and-azure-application-gateway', '', ARRAY['load-balancers','app-service','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'DB1 という名前の Azure SQL データベースに接続する、Webapp1 という名前の Azure App Service Web アプリがあります。 Webapp1 と DB1 は米国東部の Azure リージョンにデプロイされます。 Webapp1 と DB1 間のすべてのトラフィックがプライベート接続経由で送信されるようにする必要があります。 あなたは何をするべきですか。 少なくとも[選択肢]のサブネットを含む仮想ネットワークを作成します。', '["1", "2", "3"]'::jsonb, '1'::jsonb, '少なくとも 2 つのサブネットを含む仮想ネットワークを作成する必要があります。 1 つは Azure App Service VNet 統合用で、もう 1 つは Azure Private Link 用です。仮想ネットワーク統合は、専用サブネットに依存します。 サブネットを作成すると、Azure サブネットは先頭から 5 つの IP を使います。 App Service プラン インスタンスごとに、統合サブネットから 1 つのアドレスが使用されます。 アプリを 4 つのインスタンスにスケールする場合は、4 つのアドレスが使用されます。https://learn.microsoft.com/ja-jp/azure/app-service/overview-vnet-integration#subnet-requirements', '', ARRAY['sql-database','app-service','vnet','private-link'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'DB1 という名前の Azure SQL データベースに接続する、Webapp1 という名前の Azure App Service Web アプリがあります。 Webapp1 と DB1 は米国東部の Azure リージョンにデプロイされます。 Webapp1 と DB1 間のすべてのトラフィックがプライベート接続経由で送信されるようにする必要があります。 あなたは何をするべきですか。 仮想ネットワークから、[選択肢]を使用する名前解決を構成します。', '["Azure DNS Private Resolver", "プライベートDNSゾーン", "パブリックDNSゾーン"]'::jsonb, '1'::jsonb, 'プライベート DNS ゾーンを使用するように名前解決を構成します。これは、Web Apps が Azure DNS プライベート ゾーンと連携するために必要です。', '', ARRAY['sql-database','app-service','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは機密データ用の Azure Storage ソリューションを計画しています。データは毎日アクセスされます。データセットは 10 GB 未満です。 次の要件を満たすストレージ ソリューションを推奨する必要があります。 何を勧めるべきですか。 ストレージ アカウントの種類:・ ストレージに書き込まれたすべてのデータは 5 年間保持する必要がある。・ データが書き込まれた後は、データの読み取りのみが可能になる。変更と削除は防止する必要がある。・ 5 年が経過すると、データは削除できるが、変更することはできない。・ データアクセス料金は最小限に抑える必要がある。', '["BLOB のクール アクセス層を備えた汎用 v2", "Premium ブロック BLOB", "BLOB のホット アクセス層を備えた汎用 v2"]'::jsonb, '2'::jsonb, 'ホット アクセス層は、クール アクセス層に比べてデータ アクセス コストが低いため、毎日データにアクセスする場合の料金を最小限に抑えるのに適しています。クール層はストレージ コストが低くなりますが、データ アクセス料金が高くなるため、お客様のシナリオには理想的ではありません。 Premium ブロック BLOB は高パフォーマンスのシナリオ向けであり、10 GB 未満の小さなデータセットには必要ありません。https://azure.microsoft.com/ja-jp/pricing/details/storage/blobs/', '', ARRAY['resource-locks','azure-storage','blob-storage'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは機密データ用の Azure Storage ソリューションを計画しています。データは毎日アクセスされます。データセットは 10 GB 未満です。 次の要件を満たすストレージ ソリューションを推奨する必要があります。 何を勧めるべきですか。 変更と削除を防ぐための構成:・ ストレージに書き込まれたすべてのデータは 5 年間保持する必要がある。・ データが書き込まれた後は、データの読み取りのみが可能になる。変更と削除は防止する必要がある。・ 5 年が経過すると、データは削除できるが、変更することはできない。・ データアクセス料金は最小限に抑える必要がある。', '["ストレージ アカウントのリソース ロック", "不変ポリシー", "コンテナーのアクセス レベル"]'::jsonb, '1'::jsonb, '特定のアクセス許可 (この場合は読み取り専用) を持つ不変ポリシーを作成し、5 年の有効期限を設定できます。このポリシーは、データの読み取りを許可しながら、変更や削除を防ぎます。 5 年後にポリシーは期限切れになり、データは削除できますが、変更することはできません。ストレージ アカウントのリソース ロックとコンテナーのアクセス レベル設定では、コンテナー アクセス ポリシーと同じ粒度でデータを制御できません。https://learn.microsoft.com/ja-jp/azure/storage/blobs/immutable-storage-overview', '', ARRAY['resource-locks','azure-storage','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '※1の表に示す Azure サブスクリプションがあります。 Contoso.onmicrosft.com には、User1 という名前のユーザーが含まれています。 ランサムウェア攻撃から保護するソリューションを展開する必要があります。ソリューションは※2の要件を満たす必要があります。 各サブスクリプションで何を作成する必要がありますか。 Sub1:※1名前 | ロケーション | Microsoft Entra テナント--------------------------------------------------Sub1 | 米国東部 | contoso.onmicrosoft.comSub2 | 米国東部 | contoso-recovery.onmicrosoft.com※2・ Sub1 のすべてのリソースが Azure Backup を使用してバックアップされていることを確認する。・ ユーザーがバックアップ構成に大きな変更を加える前に、まず User1 に Sub2 のロールを割り当てる必要がある。', '["Azure Site Recovery ジョブ", "Microsoft Azure Backup Server (MABS)", "Recovery Services コンテナー", "Microsoft Azure Recovery Services (MARS) エージェント", "Resource Guard"]'::jsonb, '2'::jsonb, '※1名前 | ロケーション | Microsoft Entra テナント--------------------------------------------------Sub1 | 米国東部 | contoso.onmicrosoft.comSub2 | 米国東部 | contoso-recovery.onmicrosoft.com※2・ Sub1 のすべてのリソースが Azure Backup を使用してバックアップされていることを確認する。・ ユーザーがバックアップ構成に大きな変更を加える前に、まず User1 に Sub2 のロールを割り当てる必要がある。', '', ARRAY['entra-id','rbac','subscription-design','bcdr-fundamentals','azure-backup','site-recovery','containers'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '※1の表に示す Azure サブスクリプションがあります。 Contoso.onmicrosft.com には、User1 という名前のユーザーが含まれています。 ランサムウェア攻撃から保護するソリューションを展開する必要があります。ソリューションは※2の要件を満たす必要があります。 各サブスクリプションで何を作成する必要がありますか。 Sub2:※1名前 | ロケーション | Microsoft Entra テナント--------------------------------------------------Sub1 | 米国東部 | contoso.onmicrosoft.comSub2 | 米国東部 | contoso-recovery.onmicrosoft.com※2・ Sub1 のすべてのリソースが Azure Backup を使用してバックアップされていることを確認する。・ ユーザーがバックアップ構成に大きな変更を加える前に、まず User1 に Sub2 のロールを割り当てる必要がある。', '["Azure Site Recovery ジョブ", "Microsoft Azure Backup Server (MABS)", "Recovery Services コンテナー", "Microsoft Azure Recovery Services (MARS) エージェント", "Resource Guard"]'::jsonb, '4'::jsonb, 'この記事では、Azure Backup のマルチユーザー承認 (MUA) を構成して、Recovery Services コンテナーに対する重要な操作に保護レイヤーを追加する方法について説明します。 この記事では、最大限の保護を提供する別のテナントでの Resource Guard の作成について説明します。 Resource Guard を収容するテナントで Microsoft Entra Privileged Identity Management を使用して、重要な操作を実行するための要求を行う方法と、その要求を承認する方法についても説明します。 必要に応じて、他のメカニズムを使用して、設定に従って Resource Guard に対する JIT アクセス許可を管理できます。https://learn.microsoft.com/ja-jp/azure/backup/multi-user-authorization?tabs=azure-portal&pivots=vaults-recovery-services-vault', '', ARRAY['entra-id','rbac','pim','subscription-design','bcdr-fundamentals','azure-backup','site-recovery','containers'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミスのストレージ ソリューションがあります。 ソリューションを Azure に移行する必要があります。ソリューションは Hadoop 分散ファイル システム (HDFS) をサポートする必要があります。 何を使えばよいですか。', '["Azure Data Share", "Azure Data Lake Storage Gen2", "Azure Table Storage", "Azure NetApp Files"]'::jsonb, '1'::jsonb, 'オンプレミスのストレージ ソリューションがあります。 ソリューションを Azure に移行する必要があります。ソリューションは Hadoop 分散ファイル システム (HDFS) をサポートする必要があります。 何を使えばよいですか。', '', ARRAY['data-analytics','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Web アプリケーションをサポートするマイクロサービス アーキテクチャを設計しています。 ソリューションは次の要件を満たす必要があります。 テクノロジーを推奨する必要があります。 何を勧めるべきですか。・ ソリューションをオンプレミスと Azure にデプロイする。・ 低遅延およびハイパースケールの操作をサポートする。・ 各マイクロサービスへの独立したアップグレードを許可する。・ マイクロサービスの自動修復を実行するためのポリシーを設定する。', '["Azure Service Fabric", "Azure Container Instance", "Azure Logic App", "Azure Virtual Machine Scale Sets"]'::jsonb, '0'::jsonb, 'Azure Service Fabric を使用すると、オンプレミスまたは他のクラウドに Service Fabric クラスターを作成できます。Azure Service Fabric は待機時間が短く、数千台のマシンまでスケールアップできます。https://azure.microsoft.com/ja-jp/products/service-fabric/', '', ARRAY['sql-database','vmss','virtual-machines','app-service','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、社内のオンプレミス データ センターで販売、財務、およびレポート アプリケーションをホストする仮想マシンのビジネス継続性とディザスタ リカバリの次の目標を特定しています。 ビジネス継続性と災害復旧の目標を満たすサービスを推奨する必要があります。 ソリューションではコストを最小限に抑える必要があります。 それぞれのアプリケーションに何を推奨する必要がありますか。 販売アプリケーション:・ 販売アプリケーションは、2 番目のオンプレミス データ センターにフェイルオーバーできる必要があります。・ レポート アプリケーションは、毎日の粒度でポイントインタイム データを回復できなければなりません。 RTO は 8 時間です。・ 財務アプリケーションでは、データを 7 年間保持する必要があります。災害が発生した場合、アプリケーションは Azure から実行できる必要があります。目標復旧時間 (RTO) は 10 分です。', '["Azure Site Recovery のみ", "Azure Backupのみ", "Azure Site Recovery と Azure Backup"]'::jsonb, '0'::jsonb, 'Azure Site Recovery 仮想マシンと物理サーバーのレプリケーション、フェイルオーバー、フルバックを調整します。 DR ソリューションの目標復旧時点は低いです。 DR コピーは数秒/数分遅れる可能性があります。 DR には運用上のリカバリ データのみが必要ですが、これには数時間から 1 日かかる場合があります。きめ細かいデータキャプチャが行われるため、DR データを長期保存に使用することはお勧めできません。 災害復旧ソリューションは、ソースとの同期がより高いため、目標復旧時間は短くなります。 マシンの状態をリモート監視し、カスタマイズ可能な復旧計画を作成します。https://learn.microsoft.com/ja-jp/azure/site-recovery/site-recovery-overview', '', ARRAY['entra-connect','azure-monitor','bcdr-fundamentals','azure-backup','site-recovery','virtual-machines'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、社内のオンプレミス データ センターで販売、財務、およびレポート アプリケーションをホストする仮想マシンのビジネス継続性とディザスタ リカバリの次の目標を特定しています。 ビジネス継続性と災害復旧の目標を満たすサービスを推奨する必要があります。 ソリューションではコストを最小限に抑える必要があります。 それぞれのアプリケーションに何を推奨する必要がありますか。 レポートアプリケーション:・ 販売アプリケーションは、2 番目のオンプレミス データ センターにフェイルオーバーできる必要があります。・ レポート アプリケーションは、毎日の粒度でポイントインタイム データを回復できなければなりません。 RTO は 8 時間です。・ 財務アプリケーションでは、データを 7 年間保持する必要があります。災害が発生した場合、アプリケーションは Azure から実行できる必要があります。目標復旧時間 (RTO) は 10 分です。', '["Azure Site Recovery のみ", "Azure Backupのみ", "Azure Site Recovery と Azure Backup"]'::jsonb, '1'::jsonb, 'Azure Backup は、オンプレミスとクラウドのデータをバックアップします。許容可能な目標復旧時点には大きなばらつきがあります。 VM のバックアップは通常 1 日ですが、データベースのバックアップは最短 15 分です。バックアップ データは通常 30 日以内に保持されます。コンプライアンスの観点から、データは何年にもわたって保存する必要がある場合があります。このような場合のアーカイブには、バックアップ データが最適です。目標復旧時点が大きいため、バックアップ ソリューションで処理する必要があるデータの量は通常より多くなり、目標復旧時間も長くなります。', '', ARRAY['purview','blob-storage','bcdr-fundamentals','azure-backup','site-recovery','virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社は、社内のオンプレミス データ センターで販売、財務、およびレポート アプリケーションをホストする仮想マシンのビジネス継続性とディザスタ リカバリの次の目標を特定しています。 ビジネス継続性と災害復旧の目標を満たすサービスを推奨する必要があります。 ソリューションではコストを最小限に抑える必要があります。 それぞれのアプリケーションに何を推奨する必要がありますか。 財務アプリケーション:・ 販売アプリケーションは、2 番目のオンプレミス データ センターにフェイルオーバーできる必要があります。・ レポート アプリケーションは、毎日の粒度でポイントインタイム データを回復できなければなりません。 RTO は 8 時間です。・ 財務アプリケーションでは、データを 7 年間保持する必要があります。災害が発生した場合、アプリケーションは Azure から実行できる必要があります。目標復旧時間 (RTO) は 10 分です。', '["Azure Site Recovery のみ", "Azure Backupのみ", "Azure Site Recovery と Azure Backup"]'::jsonb, '2'::jsonb, 'Azure Site Recovery と Azure BackupAzure Backupにより、データの安全性と回復可能性が確保され、Site Recovery により、停止が発生した場合でもワークロードを利用できる状態が維持されます。', '', ARRAY['bcdr-fundamentals','azure-backup','site-recovery','virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure Cosmos DB を使用して複数の国からの売上を照合するアプリを設計しています。 アプリの API を推奨する必要があります。ソリューションは次の要件を満たす必要があります。 どの API をお勧めしますか。・ SQL クエリをサポートする。・ geo レプリケーションをサポートする。・ データをリレーショナルに保存し、アクセスする。', '["MongoDB", "Apache Cassandra", "PostgreSQL", "NoSQL"]'::jsonb, '2'::jsonb, 'Azure Cosmos DB の PostgreSQL 用 API は、SQL クエリ、geo レプリケーションを完全にサポートし、データをリレーショナルに保存してアクセスできるようにします。これは、自動かつ即時のスケーラビリティ、グローバル分散、Azure リージョン間でのデータの簡単なレプリケーションを提供するため、要件をすべて満たします。Apache Cassandra は、SQL クエリをネイティブにサポートしない NoSQL データベースです。 SQL に似た機能をいくつか提供していますが、完全なリレーショナル データベースではありません。MongoDB は NoSQL データベースであり、SQL に似たクエリ言語を提供しますが、リレーショナル データ モデルをサポートしません。NoSQL はデータを保存および取得できるデータベース設計の一種ですが、特定の API ではありません。また、すべての NoSQL データベースが SQL クエリとリレーショナル データ ストレージをサポートしているわけではありません。https://learn.microsoft.com/ja-jp/azure/cosmos-db/choose-api', '', ARRAY['data-fundamentals','sql-database','cosmosdb','bcdr-fundamentals','sql-ha'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の表に示すリソースがあります。 CDB1 は、継続的に更新される運用データを保存するコンテナをホストします。 あなたは、AS1 を使用して運用データを毎日分析するソリューションを設計しています。 運用データ ストアのパフォーマンスに影響を与えずにデータを分析するソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。名前 | タイプ------------------AS1 | Azure Synapse Analytics インスタンスCDB1 | NoSQL アカウント用の Azure Cosmos DB', '["Azure Synapse Link for Azure Cosmos DB", "Azure Cosmos DB および Azure Synapse Analytics コネクタを備えた Azure Data Factory", "Azure Cosmos DB 変更フィード", "PolyBase データ読み込みを使用した Azure Synapse Analytics"]'::jsonb, '0'::jsonb, 'Azure Synapse Link for Azure Cosmos DB は、Azure Cosmos DB と Azure Synapse Analytics の間に緊密な統合を作成し、Azure Cosmos DB の運用データに対してほぼリアルタイムの分析を実行できるようにします。これにより、トランザクション ワークロードのパフォーマンスに影響を与えることなくデータを直接分析できる「非 ETL(抽出、変換、読込」 環境が作成されます。Azure Cosmos DB および Azure Synapse Analytics コネクタを備えた Azure Data Factory には ETL 操作が必要となり、運用データ ストアのパフォーマンスに影響を与える可能性があります。PolyBase データ読み込みを備えた Azure Synapse Analytics は、Azure Blob Storage や Azure Data Lake Storage などの外部データ ソースからのデータの読み込みに適しています。Azure Cosmos DB 変更フィードは、運用データ ストアのパフォーマンスに影響を与えることなく、分析のニーズに直接対処するものではありません。https://learn.microsoft.com/ja-jp/azure/cosmos-db/synapse-link', '', ARRAY['data-fundamentals','blob-storage','cosmosdb','data-analytics','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure BlueprintsとARMテンプレートの違いについて正しい記述はどれですか？', '["A. ARMテンプレートはデプロイ後もリソースとの接続を維持する", "B. Azure Blueprintsはデプロイ後もリソースとの接続を維持する", "C. ARMテンプレートのみがAzure Policyをデプロイできる", "D. Azure BlueprintsのみがAzure Policyをデプロイできる"]'::jsonb, '1'::jsonb, 'Azure Blueprintsはデプロイ後もリソースとの接続（リレーションシップ）を維持します。これにより、ブループリントの更新がデプロイ済みリソースにも反映されます。一方、ARMテンプレートはデプロイ後にリソースとの接続を持たず、テンプレートを更新してもデプロイ済みリソースには影響しません。ARMテンプレートもAzure Policyのデプロイが可能なため、選択肢CとDは不正確です。', 'governance', ARRAY['azure-policy','blueprints'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'SQL Server（SQL1）上の50個のデータベースをAzureにオフラインで移行する必要があります。管理の労力を最小化するサービスはどれですか？', '["A. Data Migration Assistant (DMA)", "B. Azure Migrate", "C. SQL Server Migration Assistant (SSMA)", "D. Azure Database Migration Service (DMS)"]'::jsonb, '3'::jsonb, 'Azure Database Migration Service（DMS）は、大規模なデータベース移行を管理するためのフルマネージドサービスです。50個のデータベースのオフライン移行を効率的に実行でき、管理の労力を最小化できます。DMAは移行前の評価ツールであり、大規模な移行の実行には適していません。Azure Migrateはサーバーやアプリケーション全体の移行評価・実行ツールですが、データベース固有の移行にはDMSの方が適切です。SSMAはOracle、MySQL等の非SQL ServerデータベースからSQL Serverへの移行ツールであり、SQL Server間の移行には使用しません。', 'migration', ARRAY['data-migration','db-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '3Dジオメトリの計算を実行する必要があります。大規模な並列コンピューティングを実現するために使用すべき2つの機能/サービスはどれですか？（2つ選択）', '["A. 並列タスクの有効化", "B. Azure Batch", "C. 並列ファイルシステム", "D. Virtual Machine Scale Sets (VMSS)", "E. 仮想マシン"]'::jsonb, '[0, 1]'::jsonb, 'Azure Batchは大規模な並列コンピューティングとHPCワークロードを実行するためのサービスです。並列タスクの有効化と組み合わせることで、3Dジオメトリの計算を複数のノードで並列処理できます。VMSSはスケーラブルなVM群を提供しますが、バッチジョブの管理機能はありません。並列ファイルシステムはストレージの観点ですが、計算の並列化には直接関係しません。単一のVMでは大規模な並列計算には不十分です。', 'compute', ARRAY['vmss','virtual-machines','batch'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Batchで最初のジョブ（Linux、開発/テスト用）を実行する必要があります。コストを最小化する構成はどれですか？', '["A. ユーザーサブスクリプションモード + 低優先度VM", "B. Batchサービスモード + 専用VM", "C. ユーザーサブスクリプションモード + 専用VM"]'::jsonb, '0'::jsonb, '開発/テスト用途でコストを最小化するには、低優先度VMを使用するのが最適です。低優先度VMはAzureの余剰キャパシティを利用するため、通常のVMと比較して最大80%のコスト削減が可能です。ユーザーサブスクリプションモードでは低優先度VMが利用可能です。専用VMは高い可用性を提供しますが、開発/テストではその必要性は低く、コストが高くなります。LinuxではAzure Hybrid Benefitは適用されないため、その観点でのコスト削減はありません。', 'compute', ARRAY['subscription-design','batch'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Batchで2番目のジョブ（本番環境、MPI対応の長時間実行タスク）を実行する必要があります。適切な構成はどれですか？', '["A. ユーザーサブスクリプションモード + 低優先度VM", "B. Batchサービスモード + 専用VM", "C. ユーザーサブスクリプションモード + 専用VM"]'::jsonb, '2'::jsonb, '本番環境のMPI（Message Passing Interface）対応の長時間実行タスクには、専用VMが必要です。低優先度VMは突然の中断の可能性があり、長時間実行タスクや本番ワークロードには適していません。ユーザーサブスクリプションモードを使用することで、VNetへのデプロイやカスタムイメージの使用が可能になり、MPI通信に必要なネットワーク構成を柔軟に設定できます。', 'compute', ARRAY['subscription-design','batch','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '.NETで開発されたWebサービスをホストする必要があります。要件は一時ファイルの書き込み、イベントログの記録、コストの最小化です。どのサービスを使用すべきですか？', '["A. Azure Functions", "B. Virtual Machine Scale Sets (VMSS)", "C. App Service Environment (ASE)", "D. App Service Web Apps"]'::jsonb, '3'::jsonb, 'App Service Web Appsは.NET Webサービスのホスティングに最適で、一時ファイルの書き込み（一時ストレージ提供）やイベントログの記録に対応しています。コストもVMSSやASEと比較して低く抑えられます。Azure Functionsはイベント駆動のサーバーレスサービスで、Webサービスの常時ホスティングには最適ではありません。VMSSは高いスケーラビリティを提供しますが、管理コストが高くなります。ASEは専用環境を提供しますが、最もコストが高いオプションです。', 'compute', ARRAY['vmss','virtual-machines','app-service','azure-functions','event-driven'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Functionsで5〜20分かかる処理を実行する必要があります。イベント駆動のスケーリングも必要です。どのホスティングプランを使用すべきですか？', '["A. 従量課金プラン", "B. 専用（App Service）プラン", "C. Premiumプラン", "D. App Serviceプラン"]'::jsonb, '2'::jsonb, 'Premiumプランは、実行時間の制限が事実上なく（デフォルト30分、最大60分に設定可能）、イベント駆動のスケーリングもサポートしています。従量課金プランは実行時間が最大10分（デフォルト5分）に制限されており、20分の処理には対応できません。専用（App Service）プランは実行時間の制限はありませんが、イベント駆動のスケーリングはサポートしておらず、手動またはスケジュールベースのスケーリングとなります。', 'compute', ARRAY['app-service','azure-functions','event-driven'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Blob Storageのデータを変換してAzure Data Lake Storageに格納する必要があります。マッピングデータフローを使用したい場合、どのサービスを使用すべきですか？', '["A. Azure Storage Sync", "B. Azure Data Factory", "C. Azure Databricks", "D. Azure Data Box Gateway"]'::jsonb, '1'::jsonb, 'Azure Data Factoryは、マッピングデータフロー機能を提供しており、コードを書かずにデータ変換をビジュアルに設計できます。Blob StorageからData Lake Storageへのデータの移動と変換を効率的に実行できます。Azure Storage Syncはオンプレミスとクラウド間のファイル同期サービスです。Azure Databricksはコードベースのデータ処理プラットフォームであり、マッピングデータフローは提供していません。Data Box Gatewayはオンプレミスからクラウドへのデータ転送デバイスです。', 'data', ARRAY['entra-connect','blob-storage','data-analytics','file-sync','data-migration'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'データベース内の電話番号の下4桁のみを表示し、残りをマスクする必要があります。どの機能を使用すべきですか？', '["A. 列の暗号化", "B. 透過的データ暗号化（TDE）", "C. 動的データマスキング", "D. Always Encrypted"]'::jsonb, '2'::jsonb, '動的データマスキングは、クエリ結果でデータの一部をマスクして表示する機能です。電話番号の下4桁のみ表示するようなカスタムマスキングルールを設定できます。データ自体は暗号化されず、表示時にのみマスクが適用されます。列の暗号化はデータを暗号化しますが、部分的な表示の制御はできません。TDEはデータベース全体の保存時暗号化であり、表示の制御とは無関係です。Always Encryptedはクライアント側の暗号化であり、部分的なデータ表示の制御には使用しません。', 'security', ARRAY['sql-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'データベース内のSSN（社会保障番号）を、データベース管理者を含め誰にも閲覧できないようにする必要があります。どの機能を使用すべきですか？', '["A. 列の暗号化", "B. 透過的データ暗号化（TDE）", "C. 動的データマスキング", "D. Always Encrypted"]'::jsonb, '3'::jsonb, 'Always Encryptedは、データをクライアント側で暗号化し、データベースエンジン側では暗号化されたままの状態で保持する機能です。暗号化キーはクライアントアプリケーション側に保管されるため、データベース管理者でもデータを復号して閲覧することができません。列の暗号化やTDEはサーバー側でデータを暗号化しますが、管理者はデータにアクセスできます。動的データマスキングは表示をマスクしますが、管理者はマスクを解除できるため、「管理者を含め閲覧不可」の要件を満たしません。', 'security', ARRAY['sql-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Logic Appsからオンプレミスに配置されたSQL Serverに接続する必要があります。VPN接続はありません。オンプレミス側に必要なコンポーネントはどれですか？', '["A. Azure AD アプリケーション プロキシ コネクタ", "B. オンプレミス データ ゲートウェイ", "C. Hybrid Connection Manager (HCM)", "D. Web Application Proxy"]'::jsonb, '1'::jsonb, 'オンプレミスデータゲートウェイは、Logic AppsなどのAzureサービスからオンプレミスのデータソース（SQL Serverなど）に安全に接続するためのブリッジとして機能します。VPN接続なしでHTTPS経由でAzure Service Busリレーを通じて通信します。Azure ADアプリケーションプロキシコネクタはWebアプリケーションの公開に使用され、データベース接続には使用しません。HCMはApp Serviceのハイブリッド接続用であり、Logic Appsでは使用しません。Web Application ProxyはAD FS関連のサービスです。', 'data', ARRAY['entra-id','app-proxy','data-sources','app-service','messaging','api-management'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '同じシナリオで、Azure側に必要なコンポーネントはどれですか？', '["A. Application Gateway", "B. データ ゲートウェイ リソース", "C. Azure Event Grid", "D. エンタープライズ アプリケーション"]'::jsonb, '1'::jsonb, 'Azure側にはデータゲートウェイリソースを作成する必要があります。これはオンプレミスにインストールされたデータゲートウェイとAzureサービス（Logic Apps）を関連付けるためのAzureリソースです。Application GatewayはL7ロードバランサーであり、オンプレミス接続には使用しません。Event Gridはイベントルーティングサービスです。エンタープライズアプリケーションはAzure ADでのアプリケーション登録に使用されます。', 'data', ARRAY['entra-id','app-registration','load-balancers','event-driven','api-management','on-premises-connectivity'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '北ヨーロッパリージョンを優先的に使用し、障害時にフェールオーバーするルーティングを構成する必要があります。どのサービスを使用すべきですか？', '["A. Azure Load Balancer", "B. Application Gateway", "C. Azure Traffic Manager"]'::jsonb, '2'::jsonb, 'Azure Traffic ManagerはDNSベースのグローバルトラフィック分散サービスであり、複数リージョン間でのトラフィックルーティングが可能です。Azure Load BalancerはL4ロードバランサーでリージョン内の分散のみに対応しています。Application GatewayもL7ロードバランサーですが、単一リージョン内のサービスであり、リージョン間のフェールオーバーには使用できません。', 'network', ARRAY['site-recovery','storage-redundancy','load-balancers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '北ヨーロッパを優先リージョンとして構成するために、Traffic Managerで使用すべきルーティング方法はどれですか？', '["A. Cookieベースのアフィニティ", "B. 加重ルーティング", "C. パフォーマンスルーティング", "D. 優先順位ルーティング"]'::jsonb, '3'::jsonb, '優先順位ルーティングを使用すると、プライマリエンドポイント（北ヨーロッパ）に最高の優先順位を設定し、障害時にセカンダリエンドポイントに自動的にフェールオーバーできます。加重ルーティングはトラフィックを重み付けで分散しますが、特定のリージョンを優先する設定はできません。パフォーマンスルーティングはユーザーに最も近いエンドポイントにルーティングしますが、特定リージョンの優先は保証できません。Cookieベースのアフィニティはセッション維持のための機能であり、リージョン優先のルーティングとは無関係です。', 'network', ARRAY['site-recovery','storage-redundancy','load-balancers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Front Doorは、レート制限、負荷分散、および地域障害からの保護を提供しますか？', '["A. はい", "B. いいえ"]'::jsonb, '0'::jsonb, 'はい、Azure Front Doorはこれらすべての機能を提供します。WAF（Web Application Firewall）ポリシーによるレート制限、グローバルなL7負荷分散、複数リージョンのバックエンドへの自動フェールオーバーによる地域障害からの保護が可能です。Front Doorはグローバルサービスとして設計されており、これらの機能を統合的に提供しています。', 'network', ARRAY['site-recovery','storage-redundancy','load-balancers','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '400GBのデータベースがあり、月に1日だけ使用されます。コストを最小化するAzure SQLのサービスティアとモデルはどれですか？', '["A. Business Critical vCoreモデル", "B. General Purpose vCoreモデル", "C. Basic DTUモデル", "D. Standard DTUモデル"]'::jsonb, '1'::jsonb, 'General Purpose vCoreモデルでは、サーバーレスコンピューティングティアを使用できます。サーバーレスでは、使用していない時間は自動的に一時停止し、コンピューティング課金が発生しません（ストレージのみ課金）。月1日の使用であれば、大幅なコスト削減が可能です。Business CriticalはGPより高コストです。Basic DTUは最大2GBのデータベースサイズ制限があり、400GBには対応できません。Standard DTUも250GB制限があるため不適切です。', 'data', ARRAY['sql-database','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Front Doorが提供する機能はどれですか？', '["A. IPフィルタリング", "B. Azure AD B2C JWT検証", "C. OWASP保護"]'::jsonb, '2'::jsonb, 'Azure Front DoorはWAF（Web Application Firewall）を統合しており、OWASPコアルールセットに基づく保護を提供します。これにより、SQLインジェクション、クロスサイトスクリプティング（XSS）などの一般的なWeb攻撃から保護されます。IPフィルタリングはFront Door WAFでもカスタムルールとして設定可能ですが、この問題ではOWASP保護が最も適切な回答です。B2C JWT検証はAPI Managementの機能であり、Front Doorでは提供されていません。', 'security', ARRAY['entra-id','external-users','load-balancers','api-management','network-security'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure API Managementが提供する機能はどれですか？', '["A. IPフィルタリング", "B. Azure AD B2C JWT検証", "C. OWASP保護"]'::jsonb, '1'::jsonb, 'Azure API Managementは、ポリシーを使用してJWTトークン（Azure AD B2C発行を含む）の検証を行う機能を提供しています。validate-jwtポリシーにより、APIへのアクセス時にトークンの有効性、クレーム、発行者などを検証できます。IPフィルタリングもAPI Managementで可能ですが、この問題ではB2C JWT検証が最も特徴的な機能です。OWASP保護はWAF（Front DoorやApplication Gateway）の機能であり、API Managementの標準機能ではありません。', 'security', ARRAY['entra-id','external-users','load-balancers','api-management','network-security'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKSを2つのリージョンにデプロイしています。SSL終端を含むグローバルなルーティングソリューションを選択してください。', '["A. Azure Load Balancer", "B. Azure Front Door", "C. イングレスコントローラー", "D. Azure Traffic Manager"]'::jsonb, '1'::jsonb, 'Azure Front Doorは、複数リージョンへのグローバルL7ロードバランシングとSSL終端（TLSオフロード）を提供します。2つのリージョンのAKSクラスターへのトラフィック分散と障害時のフェールオーバーが可能です。Azure Load BalancerはL4でリージョン内のみです。イングレスコントローラーはクラスター内の機能であり、リージョン間のルーティングはできません。Traffic ManagerはDNSベースのルーティングですが、SSL終端機能は提供しません。', 'network', ARRAY['site-recovery','storage-redundancy','load-balancers','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Database for MySQLでペアリージョンへのフェールオーバーを実現する必要があります。どの機能を使用すべきですか？', '["A. Premiumファイル共有", "B. 読み取りレプリカ", "C. ネイティブレプリケーション", "D. Geoバックアップ復元"]'::jsonb, '1'::jsonb, 'Azure Database for MySQLの読み取りレプリカは、ペアリージョンに非同期レプリカを作成でき、障害時にレプリカをスタンドアロンサーバーに昇格させてフェールオーバーできます。Premiumファイル共有はAzure Filesの機能であり、MySQLには関係ありません。ネイティブレプリケーションはマネージドサービスではサポートされていない場合があります。Geoバックアップ復元も可能ですが、読み取りレプリカの方がRPO（Recovery Point Objective）が短く、フェールオーバー時間も短縮されます。', 'business-continuity', ARRAY['entra-connect','bcdr-fundamentals','azure-backup','site-recovery','storage-redundancy'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'OracleデータベースからAzure Databricksで処理し、Azure Synapse Analyticsに格納するデータパイプラインを構築する必要があります。使用すべき2つのサービスはどれですか？（2つ選択）', '["A. Azure Data Lake Storage (ADLS)", "B. Azure Data Box Gateway", "C. Azure Data Box Edge", "D. Azure Import/Export", "E. Azure Data Factory"]'::jsonb, '[0, 4]'::jsonb, 'Azure Data Factoryは、Oracleからのデータ抽出とパイプラインのオーケストレーションを提供します。Azure Data Lake Storage（ADLS）は、Databricksとの統合に最適な中間ストレージとして機能し、大量のデータを効率的に格納・処理できます。OracleからADLSにData Factoryでデータを取り込み、DatabricksでADLS上のデータを処理し、結果をSynapseに格納するアーキテクチャとなります。Data Box GatewayとData Box Edgeはオンプレミスからのデータ転送デバイスであり、このパイプラインには不要です。Import/Exportは物理ディスクによるデータ転送サービスです。', 'data', ARRAY['data-analytics','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AKSでWindowsコンテナを使用しています。負荷に応じてノード数を自動的にスケールアウトし、リソースの未使用を最小化する機能はどれですか？', '["A. 水平ポッドオートスケーラー", "B. Kubernetes 1.20.2へのアップグレード", "C. クラスターオートスケーラー", "D. 仮想ノード（ACI）"]'::jsonb, '2'::jsonb, 'クラスターオートスケーラーは、ポッドのリソース要求に基づいてノード数を自動的にスケールアウト/スケールインします。未使用リソースの最小化にも貢献します。水平ポッドオートスケーラーはポッド数のスケーリングであり、ノード数は変更しません。Kubernetesのバージョンアップグレードはスケーリング機能とは無関係です。仮想ノード（ACI）はLinuxコンテナのみをサポートしており、Windowsコンテナでは使用できません。', 'compute', ARRAY['containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure VMでSQL Serverを実行しています。トランザクションログディスクのホストキャッシュ設定はどれが適切ですか？', '["A. Read/Write", "B. None", "C. Read-only"]'::jsonb, '1'::jsonb, 'SQL Serverのトランザクションログディスクには、ホストキャッシュをNone（なし）に設定すべきです。トランザクションログは順次書き込みが主であり、書き込みの整合性が最も重要です。キャッシュを使用すると、障害時にキャッシュ内のデータが失われ、トランザクションの整合性が損なわれる可能性があります。Read/Writeキャッシュは書き込みキャッシュを含むため、ログの整合性リスクがあります。Read-onlyキャッシュはログの読み取りパターン（順次書き込み）には効果がありません。', 'compute', ARRAY['caching'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '同じSQL Server VMのデータディスクのホストキャッシュ設定はどれが適切ですか？', '["A. Read/Write", "B. None", "C. Read-only"]'::jsonb, '2'::jsonb, 'SQL Serverのデータディスクには、Read-only（読み取り専用）キャッシュが推奨されます。データファイルは読み取りが多いワークロードであり、キャッシュにより読み取りパフォーマンスが向上します。Read-onlyキャッシュでは書き込みはキャッシュを経由せず直接ディスクに書き込まれるため、データの整合性も維持されます。Read/Writeキャッシュは書き込みキャッシュによるデータ損失リスクがあります。Noneはキャッシュの恩恵を受けられず、パフォーマンスが低下します。', 'compute', ARRAY['caching'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '2つのリージョンにVMをデプロイし、Azure Traffic Managerで負荷分散する構成は実現可能ですか？', '["A. はい", "B. いいえ"]'::jsonb, '0'::jsonb, 'はい、実現可能です。Azure Traffic ManagerはDNSベースのグローバルトラフィック分散サービスであり、複数のリージョンに配置されたVMやサービスに対してトラフィックをルーティングできます。パフォーマンス、優先順位、加重などのルーティング方法を使用して、リージョン間の負荷分散やフェールオーバーを実現できます。', 'network', ARRAY['site-recovery','storage-redundancy','load-balancers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '2つのリージョンにVMをデプロイし、Application Gatewayで負荷分散する構成は実現可能ですか？', '["A. はい", "B. いいえ"]'::jsonb, '1'::jsonb, 'いいえ、Application Gatewayは単一リージョン内のサービスであり、複数リージョンにまたがる負荷分散はできません。Application Gatewayは特定のリージョンのVNet内にデプロイされ、そのリージョン内のバックエンドにのみトラフィックを分散します。リージョン間の負荷分散にはTraffic ManagerやAzure Front Doorを使用する必要があります。', 'network', ARRAY['load-balancers','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '2つのリージョンにそれぞれ2つの可用性ゾーンを使用してVMをデプロイする場合、必要なVNetの数はいくつですか？', '["A. 1", "B. 2", "C. 3", "D. 4"]'::jsonb, '1'::jsonb, 'VNet（仮想ネットワーク）はリージョンスコープのリソースであり、1つのVNetは1つのリージョンにのみ存在できます。ただし、VNet内のサブネットは同一リージョン内の複数の可用性ゾーンにまたがることができます。したがって、2つのリージョンには2つのVNetが必要です。各VNet内で可用性ゾーンにVMを分散させるため、VNetの数は可用性ゾーンの数に影響されません。', 'network', ARRAY['availability-zones','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'CPUクレジットモデルを使用するAzure VMシリーズはどれですか？', '["A. Aシリーズ", "B. Bシリーズ", "C. Dシリーズ", "D. Mシリーズ"]'::jsonb, '1'::jsonb, 'Bシリーズ（バースト可能）VMは、CPUクレジットモデルを使用します。ベースラインのCPU使用率を下回っている間はクレジットを蓄積し、負荷が高い時にクレジットを消費してベースラインを超えるパフォーマンスを発揮できます。コスト効率が高く、開発/テスト環境やCPU使用率が変動するワークロードに適しています。Aシリーズは基本的な開発/テスト向け、Dシリーズは汎用、Mシリーズはメモリ最適化であり、いずれもクレジットモデルは使用しません。', 'compute', ARRAY['virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'SQLインジェクション攻撃からの保護とL7ロードバランシングを実現するために使用すべきサービスはどれですか？', '["A. Azure Load Balancer", "B. WAF", "C. Application Gateway", "D. URLベースルーティング", "E. Traffic Manager", "F. SSLオフロード"]'::jsonb, '2'::jsonb, 'Application GatewayはL7（アプリケーション層）ロードバランサーであり、この問題のサービス選択としてはApplication Gatewayが正解です。Application GatewayにはWAF機能を統合でき、SQLインジェクション保護とL7ロードバランシングの両方を提供します。Azure Load BalancerはL4ロードバランサーであり、L7の機能は持ちません。Traffic ManagerはDNSベースのルーティングです。WAF、URLベースルーティング、SSLオフロードはApplication Gatewayの機能の一部です。', 'network', ARRAY['load-balancers','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '前問のシナリオで、SQLインジェクション保護を提供する具体的な機能はどれですか？', '["A. Azure Load Balancer", "B. WAF", "C. Application Gateway", "D. URLベースルーティング", "E. Traffic Manager", "F. SSLオフロード"]'::jsonb, '1'::jsonb, 'WAF（Web Application Firewall）は、OWASPコアルールセットに基づいてSQLインジェクション、クロスサイトスクリプティング（XSS）などのWeb攻撃から保護する機能です。Application GatewayやFront DoorにWAFを統合して使用します。Application Gateway自体はL7ロードバランサーですが、SQLインジェクション保護の具体的な機能はWAFが担います。その他の選択肢（Load Balancer、URLルーティング、Traffic Manager、SSLオフロード）はセキュリティ保護の機能ではありません。', 'security', ARRAY['load-balancers','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Basic Virtual WANにExpressRoute接続を追加する必要があります。どの操作が必要ですか？', '["A. Hub1にExpressRouteゲートウェイを追加する", "B. ハブVNetを作成する", "C. Virtual WANをStandardにアップグレードする", "D. ExpressRoute Premiumにアップグレードする"]'::jsonb, '2'::jsonb, 'Basic Virtual WANはサイト間（S2S）VPN接続のみをサポートしています。ExpressRoute接続を使用するには、Virtual WANをStandardティアにアップグレードする必要があります。Standard Virtual WANは、S2S VPN、ExpressRoute、ポイント対サイトVPN、VNet間接続など、すべての接続タイプをサポートしています。ゲートウェイの追加はStandardへのアップグレード後に行う操作です。ExpressRoute Premiumは異なるリージョンへの接続に必要ですが、Virtual WANのティアとは別の問題です。', 'network', ARRAY['vnet','on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'VMのデプロイ先リージョンとVMサイズを制限する必要があります。どのサービスを使用すべきですか？', '["A. Azure Policy", "B. 条件付きアクセス", "C. 属性ベースのアクセス制御 (ABAC)", "D. ロールベースのアクセス制御 (RBAC)"]'::jsonb, '0'::jsonb, 'Azure Policyは、リソースのプロパティに基づいてルールを強制するサービスです。「許可されたリージョン」や「許可されたVMサイズ」などの組み込みポリシーを使用して、特定のリージョンやVMサイズへのデプロイを制限できます。条件付きアクセスはユーザーのサインイン条件を制御するAzure ADの機能であり、リソースデプロイの制限には使用しません。ABACはデータプレーンのアクセス制御です。RBACはユーザーの操作権限を管理しますが、リソースのプロパティ（リージョンやサイズ）の制限には適していません。', 'governance', ARRAY['entra-id','rbac','conditional-access','azure-policy','storage-rbac'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'VM上のデータをAzure Data Factoryを使用してAzure Data Lake Storageに転送する必要があります。VM上に必要なコンポーネントはどれですか？', '["A. Azure Pipelines エージェント", "B. オンプレミス データ ゲートウェイ", "C. Azure File Sync エージェント", "D. セルフホステッド統合ランタイム"]'::jsonb, '3'::jsonb, 'セルフホステッド統合ランタイムは、Azure Data FactoryがVM上やオンプレミスのデータソースにアクセスするために必要なコンポーネントです。VMにインストールすることで、Data FactoryがVM上のデータを読み取り、ADLSに転送できます。Azure Pipelinesエージェントは CI/CD用であり、Data Factoryとは関係ありません。オンプレミスデータゲートウェイはLogic AppsやPower BI向けです。File SyncエージェントはAzure Filesとの同期用であり、Data Factoryとは連携しません。', 'data', ARRAY['entra-connect','data-sources','data-analytics','file-sync','api-management'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App Serviceのデプロイ先リージョンをリソースロックで制限できますか？', '["A. はい", "B. いいえ"]'::jsonb, '1'::jsonb, 'いいえ、リソースロックはデプロイ先リージョンを制限する機能ではありません。リソースロックは既存のリソースに対して削除ロック（CanNotDelete）や読み取り専用ロック（ReadOnly）を設定し、誤った変更や削除を防ぐ機能です。新しいリソースのデプロイ先を制限するには、Azure Policyを使用する必要があります。', 'governance', ARRAY['azure-policy','resource-locks','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App Serviceのデプロイ先リージョンをMicrosoft Defender for Cloudで制限できますか？', '["A. はい", "B. いいえ"]'::jsonb, '1'::jsonb, 'いいえ、Microsoft Defender for Cloudはセキュリティ体制管理と脅威保護のサービスであり、リソースのデプロイ先リージョンを制限する機能は提供していません。Defender for Cloudはセキュリティの推奨事項の提示、脅威の検出・アラート、セキュリティスコアの評価などを行います。デプロイ先の制限にはAzure Policyを使用します。', 'governance', ARRAY['azure-policy','alerts','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App Serviceのデプロイ先リージョンをAzure Policyで制限できますか？', '["A. はい", "B. いいえ"]'::jsonb, '0'::jsonb, 'はい、Azure Policyの「許可されたリージョン」（Allowed locations）組み込みポリシーを使用することで、App Serviceを含むすべてのAzureリソースのデプロイ先リージョンを制限できます。ポリシーに違反するリージョンへのデプロイは自動的に拒否されます。Azure Policyはリソースのプロパティに基づくルールの強制に最適なサービスです。', 'governance', ARRAY['azure-policy','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure VM上のSQL ServerでHAを実装する必要があります。コストを最小化し、フェールオーバー時間を最小化する構成はどれですか？', '["A. VNN + Standard ファイル共有", "B. Premium ファイル共有 + DNN AG（Always On 可用性グループ）", "C. Premium ファイル共有 + VNN AG（Always On 可用性グループ）", "D. VNN + Premium ファイル共有"]'::jsonb, '1'::jsonb, 'Premium ファイル共有 + DNN（Distributed Network Name）を使用したAlways On可用性グループが最適です。Always On可用性グループはフェールオーバー時間が最小化されます。DNNはAzure Load Balancerを必要としないため、構成が簡素化されコストが削減されます。Premium ファイル共有は高いIOPSと低レイテンシを提供します。VNNはAzure Load Balancerが必要でコストが増加します。Standard ファイル共有はパフォーマンスが低くなります。', 'business-continuity', ARRAY['site-recovery','storage-redundancy','sql-ha','load-balancers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Key Vaultはフェールオーバー時にどこにフェールオーバーされますか？', '["A. 同一障害ドメイン", "B. ペアリージョン", "C. 同一可用性セット"]'::jsonb, '1'::jsonb, 'Azure Key Vaultは、リージョン障害が発生した場合、ペアリージョンに自動的にフェールオーバーされます。これはMicrosoftが管理する自動フェールオーバーであり、ユーザーの操作は不要です。Key Vaultのコンテンツはプライマリリージョンとペアリージョンの両方にレプリケートされています。障害ドメインや可用性セットは同一リージョン内の概念であり、リージョン障害からの保護には対応していません。', 'business-continuity', ARRAY['key-vault','availability-zones','site-recovery','storage-redundancy'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Key Vaultのフェールオーバー中に利用できない操作はどれですか？（該当するものを選択）', '["A. List", "B. Backup", "C. Get", "D. Unwrap", "E. Delete", "F. Wrap"]'::jsonb, '4'::jsonb, 'Key Vaultのフェールオーバー中は読み取り専用モードとなり、書き込み操作（Create、Update、Delete）は利用できません。選択肢の中でDeleteは書き込み操作に該当するため、フェールオーバー中は利用できません。List、Get、Unwrap、Wrapは読み取りまたは暗号化操作であり、フェールオーバー中も利用可能です。Backupも読み取り操作として利用可能です。フェールオーバーが完了すると、すべての操作が再び利用可能になります。', 'security', ARRAY['key-vault','site-recovery','storage-redundancy'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ネットワーク仮想アプライアンス（NVA）への受信トラフィックを分散するために使用すべきサービスはどれですか？', '["A. Azure Front Door", "B. Azure Gateway Load Balancer", "C. Application Gateway", "D. Azure Traffic Manager"]'::jsonb, '1'::jsonb, 'Azure Gateway Load Balancerは、NVA（ネットワーク仮想アプライアンス）へのトラフィックを透過的にチェーンするために設計されたサービスです。ファイアウォール、IDS/IPS、DPIなどのNVAにトラフィックを分散し、既存のネットワークパスに透過的に挿入できます。Front DoorはグローバルL7ルーティングでありNVAへの直接的なトラフィック分散には適していません。Application GatewayはWebアプリケーション向けのL7ロードバランサーです。Traffic ManagerはDNSベースのルーティングであり、NVAへのインライントラフィック分散には使用しません。', 'network', ARRAY['load-balancers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、5 つの Azure Kubernetes Service (AKS) クラスターでホストされるコンテナー化された Web アプリをデプロイすることを計画しています。各クラスターは異なる Azure リージョンでホストされます。 インターネットからアプリへのアクセスを提供する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 グローバル負荷分散:・ 受信 HTTPS 要求は、ネットワーク遅延が最も短いクラスターにルーティングされる必要がある。・ 個々の Pod への HTTPS トラフィックは、イングレス コントローラー経由でルーティングされる必要がある。・ AKS クラスターが停止した場合、フェールオーバー時間を最小限に抑える必要がある。', '["Azure Traffic Manager", "Standard Load Balancer", "Azure Front Door", "Azure のリージョン間 (グローバル) ロード バランサー"]'::jsonb, '2'::jsonb, 'Azure Front Door と Traffic Manager はどちらもグローバル ロード バランサーです。ただし、Azure Front Door の推奨トラフィックは HTTP(S) であり、Traffic Manager の推奨トラフィックは非 HTTP(S) です。https://learn.microsoft.com/ja-jp/azure/architecture/guide/technology-choices/load-balancing-overview', '', ARRAY['site-recovery','storage-redundancy','load-balancers','app-service','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、5 つの Azure Kubernetes Service (AKS) クラスターでホストされるコンテナー化された Web アプリをデプロイすることを計画しています。各クラスターは異なる Azure リージョンでホストされます。 インターネットからアプリへのアクセスを提供する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 イングレスコントローラー:・ 受信 HTTPS 要求は、ネットワーク遅延が最も短いクラスターにルーティングされる必要がある。・ 個々の Pod への HTTPS トラフィックは、イングレス コントローラー経由でルーティングされる必要がある。・ AKS クラスターが停止した場合、フェールオーバー時間を最小限に抑える必要がある。', '["Azure Application Gateway", "Basic Azure Load Balancer", "Azure Standard Load Balancer"]'::jsonb, '0'::jsonb, 'Application Gateway イングレス コントローラー (AGIC) は Kubernetes アプリケーションであり、これにより、Azure Kubernetes Service (AKS) のお客様が、Azure のネイティブ Application Gateway L7 ロード バランサーを活用してクラウド ソフトウェアをインターネットに公開できるようにします。 AGIC では、ホストされている Kubernetes クラスターを監視し、Application Gateway を継続的に更新して、選択されたサービスがインターネットに公開されるようにします。 イングレス コントローラーは、お客様の AKS の独自のポッドで実行されます。 AGIC では、Kubernetes リソースのサブセットに変更がないかを監視します。 AKS クラスターの状態は Application Gateway の特定の構成に変換され、Azure Resource Manager (ARM) に適用されます。AGIC を使用すると、AKS クラスターの前に別のロード バランサー/パブリック IP アドレスを設定する必要がなくなり、要求が AKS クラスターに到達する前にデータパス内の複数のホップを回避できます。https://learn.microsoft.com/ja-jp/azure/application-gateway/ingress-controller-overview', '', ARRAY['azure-monitor','site-recovery','storage-redundancy','load-balancers','app-service','containers'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたの会社には、次の表に示すインフラストラクチャがあります。 オンプレミスの Active Directory ドメインは、Microsoft Entra ID と同期します。 Server1 は、LDAP クエリを使用してオンプレミスの Active Directory ドメイン内のユーザー ID を確認する App1 という名前のアプリケーションを実行します。 Server1 を Subscription1 の仮想マシンに移行する予定です。 会社のセキュリティ ポリシーでは、Subscription1 にデプロイされた仮想マシンとサービスがオンプレミス ネットワークにアクセスできないようにする必要があると規定されています。 移行後も App1 が機能し続けることを保証するソリューションを推奨する必要があります。ソリューションはセキュリティ ポリシーを満たしている必要があります。 推奨事項には何を含めるべきですか。ロケーション | リソース--------------------------------Azure | ①Subscription1 という名前の Azure サブスクリプション ②20 個の Azure Web アプリオンプレミス データセンター | ①Active Directory ドメイン ②Microsoft Entra Connec を実行しているサーバー ③Server1 という名前の Linux コンピューター', '["Microsoft Entra Domain Services", "Azure VPN gateway", "仮想マシン上の Active Directory Domain Services ロール", "Microsoft Entra アプリケーション プロキシ"]'::jsonb, '0'::jsonb, 'Microsoft Entra Domain Services には、ドメイン参加、グループ ポリシー、Lightweight Directory Access Protocol (LDAP)、Kerberos および NTLM 認証などのマネージド ドメイン サービスが用意されています。 クラウドでドメイン コントローラー (DC) のデプロイ、管理、修正プログラムの適用を行わなくても、これらのドメイン サービスを使用することができます。https://learn.microsoft.com/ja-jp/entra/identity/domain-services/overview', '', ARRAY['entra-family','entra-id','entra-connect','rbac','subscription-design','virtual-machines','app-service','data-migration'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、50,000 台の IoT デバイスを含む Azure IoT Hub ソリューションを計画しています。 各デバイスは、温度、デバイス ID、時間データなどのデータをストリーミングします。毎秒約 50,000 レコードが書き込まれます。データはほぼリアルタイムで視覚化されます。 データを保存およびクエリするためのサービスを推奨する必要があります。 このとき、利用すべきサービスを 2 つ答えてください。', '["NoSQL 用 Azure Cosmos DB", "Azure Table Storage", "Azure Event Grid", "Azure Time Series Insights"]'::jsonb, '3'::jsonb, 'Azure Cosmos DB for NoSQL は、低待機時間と高スループットで大量のデータを処理できる、グローバルに分散されたマルチモデル データベース サービスです。さまざまな整合性レベルとパーティショニング戦略をサポートしているため、大規模な IoT データの処理に適しています。Azure Time Series Insights は、IoT デバイスによって生成された時系列データ向けに特別に設計された、フルマネージドのリアルタイム分析サービスです。時系列データのストレージ、視覚化、高度なクエリ機能を提供するため、多数の IoT デバイスからのデータを処理し、ほぼリアルタイムで視覚化するのに理想的な選択肢となります。https://learn.microsoft.com/ja-jp/azure/architecture/solution-ideas/articles/iot-using-cosmos-db', '', ARRAY['data-fundamentals','cosmosdb','cosmosdb-params','event-driven'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、ユーザー向けのコンテンツを集約するアプリケーションを設計しています。 アプリケーションにデータベース ソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。・ SQL コマンドをサポートする。・ マルチマスター書き込みをサポートする。・ 低遅延の読み取り操作を保証する。', '["Azure SQL データベース ハイパースケール", "アクティブ geo レプリケーションを使用する Azure SQL データベース", "PostgreSQL 用 Azure Cosmos DB", "NoSQL 用 Azure Cosmos DB"]'::jsonb, '3'::jsonb, 'Azure Cosmos DB は、SQL コマンド、マルチマスター書き込みをサポートし、低待機時間の読み取り操作を保証する、グローバルに分散されたマルチモデル データベース サービスです。ドキュメント、キーと値、グラフ、列ファミリーなどのさまざまな NoSQL データ モデルをサポートします。 Azure Cosmos DB は、複数の Azure リージョン間でデータをレプリケートおよび同期することにより、自動かつ即時のスケーラビリティ、高可用性、低待機時間をグローバルに提供します。 一方、Azure SQL Database と Azure SQL Database Hyperscale は、マルチマスター書き込みをネイティブにサポートしていない従来のリレーショナル データベース サービスです。', '', ARRAY['entra-connect','data-fundamentals','sql-database','cosmosdb','bcdr-fundamentals','sql-ha'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、複数の場所にデプロイされ、Standard レベルの Azure Databricks ワークスペースを使用する販売時点管理 (POS) ソリューションを設計しています。このソリューションには、各場所のオンプレミス ネットワークにデプロイされた複数のアプリが含まれます。 アプリがワークスペースにアクセスするために使用する認証方法を構成する必要があります。このソリューションでは、スタッフの離職と資格情報の管理に関連する管理労力を最小限に抑える必要があります。 何を設定すればよいでしょうか。', '["個人のアクセストークン", "サービスプリンシパル", "管理されたアイデンティティ"]'::jsonb, '1'::jsonb, 'マネージド ID は Azure リソースの認証を提供できますが、オンプレミス リソースの認証は提供できません。オンプレミス ネットワークの場合は、通常、認証にサービス プリンシパルまたは個人アクセス トークンを使用します。https://learn.microsoft.com/ja-jp/azure/databricks/administration-guide/users-groups/#identity-model', '', ARRAY['log-analytics','app-registration','managed-identity','data-analytics'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App1 という名前のオンプレミス アプリがあります。 お客様は App1 を使用してデジタル画像を管理します。 App1 を Azure に移行する予定です。 App1 用のデータ ストレージ ソリューションを推奨する必要があります。ソリューションは、※1の画像ストレージ要件を満たしている必要があります。 ソリューションは、※2の顧客アカウント要件を満たす必要があります。 データの種類ごとにどのサービスを推奨事項に含めるべきですか。 画像ストレージ:※1・ 保存中のイメージを暗号化する。・ 最大 50 MB のファイルを許可する。・ Azure Front Door 上の Azure Web アプリケーション ファイアウォール (WAF) を使用して、イメージへのアクセスを管理する。※2・ ストレージの自動スケールアウトをサポートする。・ データセンターに障害が発生した場合でも、App1 の可用性を維持する。・ 複数の Azure リージョンからのデータの読み取りと書き込みをサポートする。', '["Azure Table Storage", "Azure Blob Storage", "Azure SQL Database", "Azure Cosmos DB"]'::jsonb, '1'::jsonb, 'WAF 経由でアクセスできるという要件により、Blob Storage へのオプションが制限されます。Azure Blob Storage は、保存時の暗号化をサポートし、大きなファイル サイズ (最大 50 MB 以上) を処理し、Azure Front Door 上の Azure Web アプリケーション ファイアウォール (WAF) と組み合わせて使用できるため、デジタル イメージの保存に適しています。https://learn.microsoft.com/ja-jp/azure/frontdoor/scenario-storage-blobs', '', ARRAY['blob-storage','sql-database','cosmosdb','load-balancers','app-service','network-security','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App1 という名前のオンプレミス アプリがあります。 お客様は App1 を使用してデジタル画像を管理します。 App1 を Azure に移行する予定です。 App1 用のデータ ストレージ ソリューションを推奨する必要があります。ソリューションは、※1の画像ストレージ要件を満たしている必要があります。 ソリューションは、※2の顧客アカウント要件を満たす必要があります。 データの種類ごとにどのサービスを推奨事項に含めるべきですか。 顧客アカウント:※1・ 保存中のイメージを暗号化する。・ 最大 50 MB のファイルを許可する。・ Azure Front Door 上の Azure Web アプリケーション ファイアウォール (WAF) を使用して、イメージへのアクセスを管理する。※2・ ストレージの自動スケールアウトをサポートする。・ データセンターに障害が発生した場合でも、App1 の可用性を維持する。・ 複数の Azure リージョンからのデータの読み取りと書き込みをサポートする。', '["Azure SQL Database", "Azure Cosmos DB", "Azure Blob Storage", "Azure Table Storage"]'::jsonb, '1'::jsonb, '複数のリージョンからの同時書き込みには、唯一 Azure Cosmos DB が対応しています。Azure Cosmos DB は、自動スケールアウトをサポートし、データセンターに障害が発生した場合でも高可用性を確保し、複数の Azure リージョンからのデータの読み取りと書き込みを可能にする、スケーラビリティの高い、グローバルに分散されたマルチモデル データベース サービスです。https://learn.microsoft.com/ja-jp/azure/cosmos-db/introduction#guaranteed-speed-at-any-scale', '', ARRAY['blob-storage','sql-database','cosmosdb','load-balancers','app-service','network-security','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure 仮想マシン上に SQL Server があります。データベースはバッチ プロセスの一部として毎晩書き込まれます。 データの災害復旧ソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。・ 地域的な停止が発生した場合に回復する機能を提供する。・ 15 分の目標復旧時間 (RTO) をサポートする。・ 24 時間の目標復旧時点 (RPO) をサポートする。・ 自動リカバリをサポートする。・ コストを最小限に抑える。', '["Azure Virtual Machines 可用性セット", "Always On 可用性グループ", "Azure Site Recovery", "Azure ディスク バックアップ"]'::jsonb, '2'::jsonb, 'Azure Site Recovery を使用したレプリケーション・ RTO は通常 15 分未満です。・ アプリケーション整合性では 1 時間、クラッシュ整合性では 5 分です。 より低い RPO を求めている場合は、別の BCDR テクノロジを使用してください。https://learn.microsoft.com/ja-jp/azure/site-recovery/site-recovery-sqlAzure ディスク バックアップは遅すぎます。Always On 可用性グループの場合は、セカンダリ レプリカへのレプリケーションは非同期であるため、ある程度のデータ損失が発生します。', '', ARRAY['entra-connect','bcdr-fundamentals','availability-zones','azure-backup','site-recovery','sql-ha','virtual-machines'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは 2 つのコンポーネントを含むアプリを設計しています。コンポーネントは、キューを介してメッセージを送信することによって通信します。 先入れ先出し (FIFO) パターンを使用してメッセージを処理するソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["パーティショニングが有効になっている Service Bus キュー", "セッションが有効になっている Service Bus キュー", "カスタムメタデータ設定を使用した Storage キュー", "保存されたアクセス ポリシーを使用した Storage キュー"]'::jsonb, '1'::jsonb, 'Azure Service Bus は、セッションの使用を通じて FIFO パターンをサポートします。セッションは、順序付けられたメッセージのシーケンスです。セッション内のすべてのメッセージは到着順に処理されます。これにより、メッセージがキューに追加された順序で処理されるようになります。Azure Storage キューは先入れ先出し (FIFO) パターンをネイティブにサポートしていません。Azure Service Bus でのパーティション分割は、複数のメッセージ ブローカーとストアに負荷を分散することでパフォーマンスを向上させることができますが、パーティション間で FIFO 順序付けが強制されるわけではありません。 FIFO の順序はパーティション内では維持されますが、パーティション間では維持されません。https://learn.microsoft.com/ja-jp/azure/service-bus-messaging/message-sessions', '', ARRAY['messaging'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ルート管理グループと 10 個の子管理グループを含む Azure 環境を作成する予定です。各子管理グループには 5 つの Azure サブスクリプションが含まれます。各サブスクリプションに 10 ～ 30 のリソース グループを含める予定です。 Azure ガバナンス ソリューションを設計する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 ブループリントを定義するレベル:・ Azure Blueprints を使用して、すべてのサブスクリプションとリソース グループにわたるガバナンスを制御する。・ ブループリント ベースの構成がすべてのサブスクリプションとリソース グループにわたって一貫していることを確認する。・ ブループリントの定義と割り当ての数を最小限に抑える。', '["ルート管理グループ", "子管理グループ", "サブスクリプション"]'::jsonb, '0'::jsonb, 'ルート管理グループブループリント定義を作成するときは、ブループリントの保存場所を定義します。ブループリントは、所有している管理グループまたはサブスクリプションに保存できます。寄稿者のアクセス権。場所が管理グループの場合、ブループリントをその管理グループの子サブスクリプションに割り当てることができます。ルート管理グループは階層に組み込まれており、すべての管理グループとサブスクリプションがそれに組み込まれます。このルート管理グループにより、グローバル ポリシーと Azure ロールの割り当てをディレクトリ レベルで適用できます。https://learn.microsoft.com/ja-jp/azure/governance/management-groups/overview', '', ARRAY['rbac','resource-hierarchy','management-groups','subscription-design','blueprints'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ルート管理グループと 10 個の子管理グループを含む Azure 環境を作成する予定です。各子管理グループには 5 つの Azure サブスクリプションが含まれます。各サブスクリプションに 10 ～ 30 のリソース グループを含める予定です。 Azure ガバナンス ソリューションを設計する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。 ブループリント割り当てを作成するレベル:・ Azure Blueprints を使用して、すべてのサブスクリプションとリソース グループにわたるガバナンスを制御する。・ ブループリント ベースの構成がすべてのサブスクリプションとリソース グループにわたって一貫していることを確認する。・ ブループリントの定義と割り当ての数を最小限に抑える。', '["ルート管理グループ", "子管理グループ", "サブスクリプション"]'::jsonb, '2'::jsonb, 'ブループリントの個々の発行済みバージョンを既存の管理グループまたはサブスクリプションに割り当てることができます (名前の最大長は 90 文字)。 ポータルにおいて、ブループリントの既定のバージョンは、直近の発行済みになったバージョンになります。 アーティファクトのパラメーターまたはブループリントのパラメーターがある場合、そのパラメーターは割り当て処理時に定義されます。https://learn.microsoft.com/ja-jp/azure/governance/blueprints/overview#blueprint-assignment', '', ARRAY['resource-hierarchy','management-groups','subscription-design','blueprints'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure サブスクリプションでステートレス Web アプリをホストするには、リソースをデプロイする必要があります。ソリューションは次の要件を満たす必要があります。 解決策: 自動スケーリングを使用する Virtual Machine Scale Setsをデプロイします。 これは目標を達成していますか。・ 完全な .NET Frameworkへのアクセスを提供する。・ Azure リージョンに障害が発生した場合に冗長性を提供する。・ カスタム アプリケーションの依存関係をインストールするためのオペレーティング システムへのアクセスを管理者に許可する。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, 'この解決策では目標を達成することはできません。代わりに、2 つの Azure 仮想マシンを 2 つの Azure リージョンにデプロイし、Traffic Manager プロファイルを作成する必要があります。Azure Traffic Manager は、DNS ベースのトラフィック ロード バランサーです。 このサービスを使用すると、パブリックに公開されているアプリケーションへのトラフィックを世界各国の Azure リージョン全体に分散することができます。 また、Traffic Manager によって、パブリック エンドポイントには高可用性と高い応答速度が確保されます。https://docs.microsoft.com/ja-jp/azure/traffic-manager/traffic-manager-overview', '', ARRAY['subscription-design','azure-storage','vmss','load-balancers','virtual-machines','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Cosmos DB と Azure Synapse を統合するソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。 Azure Synapse ワークスペースをプロビジョニングするとき:・ Azure Synapse ワークスペースから Azure Cosmos DB アカウントへのトラフィックは、Microsoft バックボーン ネットワーク経由で送信される必要がある。・ Azure Synapse ワークスペースから Azure Cosmos DB アカウントへのトラフィックは、インターネット経由でルーティングしてはならない。・ 導入の労力は最小限に抑える必要がある。', '["Microsoft Entra ID 認証の使用を有効にする。", "ワークスペース エンドポイントへのパブリック ネットワーク アクセスを無効にする。", "専用の仮想ネットワークを構成する。"]'::jsonb, '2'::jsonb, '専用のマネージド仮想ネットワークを構成するマネージド プライベート エンドポイントは、マネージド ワークスペース仮想ネットワークを使用した Azure Synapse ワークスペースでのみサポートされます。https://learn.microsoft.com/ja-jp/azure/synapse-analytics/security/synapse-workspace-managed-private-endpoints#managed-private-endpoints', '', ARRAY['entra-id','log-analytics','cosmosdb','data-analytics','vnet','private-link'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Cosmos DB と Azure Synapse を統合するソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。 Azure Cosmos DB アカウントを構成するときに、次を有効にする:・ Azure Synapse ワークスペースから Azure Cosmos DB アカウントへのトラフィックは、Microsoft バックボーン ネットワーク経由で送信される必要がある。・ Azure Synapse ワークスペースから Azure Cosmos DB アカウントへのトラフィックは、インターネット経由でルーティングしてはならない。・ 導入の労力は最小限に抑える必要がある。', '["マネージド プライベート エンドポイント", "サービス エンドポイント ポリシー", "サーバーレベルのファイアウォール規則"]'::jsonb, '0'::jsonb, 'マネージドプライベートエンドポイントマネージド プライベート エンドポイントを使用すると、Azure Synapse ワークスペースと他の Azure リソース間のトラフィックは、完全に Microsoft バックボーン ネットワーク上を通過します。https://learn.microsoft.com/ja-jp/azure/synapse-analytics/security/synapse-workspace-managed-vnet', '', ARRAY['log-analytics','cosmosdb','data-analytics','private-link'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミス ネットワークには、500 GB のデータを保存する Server1 という名前のファイル サーバーが含まれています。 Azure Data Factory を使用して、Server1 から Azure Storage にデータをコピーする必要があります。 新しいデータ ファクトリを追加します。 次に何をすべきでしょうか。 Server1:', '["セルフホステッド統合ランタイムをインストールする。", "Azure File Sync エージェントをインストールする。", "ファイル サーバー リソース マネージャーの役​​割サービスをインストールする。"]'::jsonb, '0'::jsonb, 'セルフホステッド統合ランタイムをインストールします。データ ストアがオンプレミス ネットワーク、Azure 仮想ネットワーク、または Amazon Virtual Private Cloud 内にある場合は、それに接続するようにセルフホステッド統合ランタイムを構成する必要があります。データ ストアに接続するために使用される統合ランタイム。 Azure Integration Runtime またはセルフホステッド Integration Runtime (データ ストアがプライベート ネットワークにある場合) を使用できます。指定しない場合は、デフォルトの Azure 統合ランタイムが使用されます。https://learn.microsoft.com/ja-jp/azure/data-factory/connector-file-system?tabs=data-factory', '', ARRAY['data-analytics','file-sync','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'オンプレミス ネットワークには、500 GB のデータを保存する Server1 という名前のファイル サーバーが含まれています。 Azure Data Factory を使用して、Server1 から Azure Storage にデータをコピーする必要があります。 新しいデータ ファクトリーを追加します。 次に何をすべきでしょうか。 データ ファクトリー:', '["Azure Import/Export ジョブを作成する。", "Azure-SQL Server Integration Services (SSIS) 統合ランタイム (IR) をプロビジョニングする。", "パイプラインを作成する。"]'::jsonb, '2'::jsonb, 'パイプラインを作成します。パイプラインを使用してコピー アクティビティを実行します。パイプラインでコピー アクティビティを実行するには、次のいずれかのツールまたは SDK を使用します。・データ コピー ツール・Azure ポータル・.NET SDK・Python SDK・Azure PowerShell・REST API・Azure Resource Manager テンプレートhttps://learn.microsoft.com/ja-jp/azure/data-factory/connector-file-system?tabs=data-factory', '', ARRAY['data-analytics','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure SQL をデータベース プラットフォームとして使用する予定です。 次の要件を満たす Azure SQL 製品とサービス レベルを推奨する必要があります。 ・ ワークロードの需要に基づいてコンピューティング リソースを自動的にスケーリングする ・ 秒単位の課金を提供する このとき、何を勧めるべきですか。 Azure SQL 製品:', '["Azure SQL Database の単一データベース", "Azure SQL Managed Instance", "An Azure SQL Database elastic pool"]'::jsonb, '0'::jsonb, 'サーバーレスは、ワークロードの需要に基づいてコンピューティングが自動的にスケーリングされ、1 秒あたりのコンピューティング使用量に対して請求される、Azure SQL Database の単一データベース用のコンピューティング レベルです。 またサーバーレス コンピューティング レベルでは、アイドル期間にデータベースを自動的に一時停止します。このときはストレージのみに課金され、再びアクティブになると自動的にデータベースが再開されます。 サーバーレス コンピューティング レベルは、General Purpose サービス レベルで提供されており、現在 Hyperscale サービス レベルがプレビュー段階です。https://learn.microsoft.com/ja-jp/azure/azure-sql/database/serverless-tier-overview?view=azuresql&tabs=general-purpose', '', ARRAY['sql-database','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure SQL をデータベース プラットフォームとして使用する予定です。 次の要件を満たす Azure SQL 製品とサービス レベルを推奨する必要があります。 このとき、何を勧めるべきですか。 サービスレベル:・ ワークロードの需要に基づいてコンピューティング リソースを自動的にスケーリングする・ 秒単位の課金を提供する', '["Business Critical", "General Purpose", "Basic", "Standard", "Hyperscale"]'::jsonb, '1'::jsonb, 'サーバーレスは、ワークロードの需要に基づいてコンピューティングが自動的にスケーリングされ、1 秒あたりのコンピューティング使用量に対して請求される、Azure SQL Database の単一データベース用のコンピューティング レベルです。 またサーバーレス コンピューティング レベルでは、アイドル期間にデータベースを自動的に一時停止します。このときはストレージのみに課金され、再びアクティブになると自動的にデータベースが再開されます。 サーバーレス コンピューティング レベルは、General Purpose サービス レベルで提供されており、現在 Hyperscale サービス レベルがプレビュー段階です。https://learn.microsoft.com/ja-jp/azure/azure-sql/database/serverless-tier-overview?view=azuresql&tabs=general-purpose', '', ARRAY['sql-database','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'パフォーマンス データを Azure Blob Storage に書き込むデバイスが 100 台あります。 パフォーマンス データを Azure SQL データベースに保存して分析することを計画しています。 パフォーマンス データを Azure SQL データベースに継続的にコピーするソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["Azure Database Migration Service", "Azure Data Factory", "Data Migration Assistant (DMA)", "Azure Data Box"]'::jsonb, '1'::jsonb, 'Azure Data Factory は、データ パイプラインの作成、スケジュール、管理を可能にするクラウドベースのデータ統合サービスです。これを使用すると、Azure Blob Storage などのさまざまなソースから Azure SQL Database などの複数の宛先にデータを継続的にコピーできます。他の選択肢は、説明したシナリオでの継続的なデータ コピーには適していません。https://learn.microsoft.com/ja-jp/azure/data-factory/introduction', '', ARRAY['blob-storage','sql-database','data-analytics','data-migration','db-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、従業員の個人識別情報 (PII) を保存する Azure Web アプリを構築しています。 Azure SQL を推奨する必要があります。 Web アプリ用のデータベース ソリューション。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。 サービス階層とコンピューティング レベル:・ 単一のデータセンターが停止した場合でも可用性を維持する。・ PII を含む特定の列の暗号化をサポートする。・ 給与計算業務中に自動的にスケールアップする。・ コストを最小限に抑える。', '["Business Critical サービス レベルとサーバーレス コンピューティング レベル", "Hyperscale サービス レベルとプロビジョニング済みコンピューティング レベル", "General Purpose サービス レベルとサーバーレス コンピューティング レベル"]'::jsonb, '2'::jsonb, 'General Purpose サービス レベルは、一般的なワークロード向けに設計されています。 予算重視のバランスの取れたコンピューティングおよびストレージ オプションが提供されます。サーバーレス コンピューティング レベル: ワークロード アクティビティに基づいてコンピューティング リソースを自動的にスケーリングし、1 秒あたりのコンピューティング使用量に対して請求します。 サーバーレス コンピューティング レベルは、General Purpose サービス レベルで一般提供されており、現在 Hyperscale サービス レベルがプレビュー段階です。https://learn.microsoft.com/ja-jp/azure/azure-sql/database/sql-database-paas-overview?view=azuresql#service-tiers', '', ARRAY['cost-management','sql-database','app-service','azure-functions'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、従業員の個人識別情報 (PII) を保存する Azure Web アプリを構築しています。 Azure SQL を推奨する必要があります。 Web アプリ用のデータベース ソリューション。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。 暗号化方式:・ 単一のデータセンターが停止した場合でも可用性を維持する。・ PII を含む特定の列の暗号化をサポートする。・ 給与計算業務中に自動的にスケールアップする。・ コストを最小限に抑える。', '["透過的なデータ暗号化 (TDE)", "Always Encrypted", "Microsoft SQLサービスとデータベース暗号化キー"]'::jsonb, '1'::jsonb, 'Always Encrypted は、Azure SQL Database、Azure SQL Managed Instance や SQL Server データベースに格納された、クレジット カード番号や国民識別番号 (米国の社会保障番号など) のような機微なデータを保護することを目的とした機能です。 Always Encrypted では、クライアント内部で機密データが暗号化されるため、暗号化キーがデータベース エンジンに公開されることはありません。 これにより、データを所有し、それを表示できるユーザーと、データを管理するがアクセス権を持たないユーザー (オンプレミスのデータベース管理者、クラウド データベース オペレーター、またはその他の高い特権を持つ未承認のユーザー) が分離されます。 結果として、Always Encrypted を使用すると、顧客は自信を持って機密データをクラウドに格納し、悪意のある内部関係者によるデータ盗難の可能性を減らすことができます。https://learn.microsoft.com/ja-jp/sql/relational-databases/security/encryption/always-encrypted-database-engine?view=sql-server-ver16', '', ARRAY['pim','sql-database','sql-security','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Microsoft Entra テナントがあります。 SQL API を使用する Azure Cosmos DB データベースをデプロイする予定です。 特定の Microsoft Entra ID ユーザー アカウントに Cosmos DB データベースへの読み取りアクセスを提供するソリューションを推奨する必要があります。 推奨事項には何を含めるべきですか。', '["証明書と Azure Key Vault", "共有アクセス署名 (SAS) と条件付きアクセス ポリシー", "リソース トークンとアクセス制御 (IAM) ロールの割り当て", "マスター キーと Azure Information Protection ポリシー"]'::jsonb, '2'::jsonb, 'Azure Cosmos DB の SQL API は、マスター キー トークンとリソース トークンという 2 種類の承認を提供します。マスター キー トークンは、すべてのデータとすべての権限へのアクセスを提供します。リソース トークンは、特定のコンテナーとアクセス許可へのアクセスを提供し、Microsoft Entra ID ユーザーの ID を使用してこれらのトークンを作成できます。Microsoft Entra ID ユーザーに Azure Cosmos DB へのアクセスを提供するには、ユーザーに特定の IAM ロールを割り当てます。 Azure Cosmos DB は、特定のアクセスを提供するために Azure ロールベースのアクセス制御 (Azure RBAC) を使用します。 Azure RBAC は、Azure Resource Manager 上に構築された認証システムで、Azure 内のリソースに対するきめ細かいアクセス管理を提供します。リソース トークンと IAM ロールの割り当てを組み合わせることで、Microsoft Entra ID ユーザー アカウントが Cosmos DB データベースへの読み取りアクセスを持つために必要なアクセス制御が提供されます。https://docs.microsoft.com/ja-jp/azure/cosmos-db/role-based-access-control', '', ARRAY['entra-id','rbac','conditional-access','sas','key-vault','cosmosdb','containers'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App1 という名前の多層アプリと SQL1 という名前の Azure SQL データベースがあります。 App1 のバックエンド サービスは、データを SQL1 に書き込みます。ユーザーは App1 クライアントを使用して SQL1 からデータを読み取ります。 使用率が高い期間中、ユーザーはデータの取得に遅れを経験します。 データ要求にかかる時間を最小限に抑える必要があります。 ソリューションには何を含めるべきでしょうか。', '["Azure コンテンツ配信ネットワーク (CDN)", "Azure Cache for Redis", "Azure Synapse Analytics", "Azure Data Factory"]'::jsonb, '1'::jsonb, 'Azure Cache for Redis は、Redis ソフトウェアを基にしたインメモリ データ ストアを提供します。 Redis は、バックエンドでデータ ストアを酷使するアプリケーションのパフォーマンスとスケーラビリティを高めます。 高速に読み書きできるサーバーのメモリ内にアクセス頻度の高いデータを維持することで、大量のアプリケーション要求を処理することができます。 Redis によって、きわめて低遅延かつ高スループットのデータ ストレージ ソリューションがモダン アプリケーションにもたらされます。Azure コンテンツ配信ネットワーク (CDN): ネットワークに問題はありませんAzure Data Factory: このツールはオーケストレーション用であり、既存のものを強化するためのものではありませんAzure Synapse Analytics: 追加のデータ ウェアハウス機能を備えたオーケストレーション ツールでもありますが、この場合は関係ありませんhttps://learn.microsoft.com/ja-jp/azure/azure-cache-for-redis/cache-overview', '', ARRAY['sql-database','data-analytics','caching'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Event Grid にルーティングされたイベントに応答してカスタム C# コードを実行するソリューションを設計する必要があります。ソリューションは次の要件を満たす必要があります。 ソリューションには何を含めるべきでしょうか。・ 実行されるコードは、Azure 仮想マシン上で実行される Microsoft SQL Server インスタンスのプライベート IP アドレスにアクセスできる必要がある。・ コストは最小限に抑える必要がある。', '["Azure Logic Apps の統合サービス環境 (ISE)", "Azure Logic Apps の 従量課金プラン", "Azure Functions の 従量課金プラン", "Azure Functions の Premium プラン"]'::jsonb, '3'::jsonb, 'プレミアム プランでは仮想ネットワーク接続が可能です。従量課金プランでは仮想ネットワーク統合機能にアクセスできません。https://learn.microsoft.com/ja-jp/azure/azure-functions/functions-scale#networking-features', '', ARRAY['virtual-machines','azure-functions','event-driven','api-management','vnet'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '従量課金プランでホストされている App1 という名前の Azure Functions マイクロサービス アプリがあります。 App1 は Azure Queue Storage トリガーを使用します。 App1 を Azure Kubernetes Service (AKS) クラスターに移行することを計画しています。 App1 をサポートするには、AKS クラスターを準備する必要があります。ソリューションは次の要件を満たす必要があります。 どの 2 つのアクションを実行する必要がありますか。・ 現在のデプロイメントと同じスケーリング メカニズムを使用する。・ kubenet および Azure Container Networking Interface (CNI) ネットワーキングをサポートする。', '["Kubernetes Event-driven Autoscaling (KEDA をインストールする。", "ポッドの水平オートスケーラーを構成する。", "AKS クラスター オートスケーラーを構成する。", "仮想 Kubelet をインストールする。", "仮想ノード アドオンを構成する。"]'::jsonb, '1'::jsonb, 'Kubernetes は、ポッドの水平オートスケーラー (HPA) を使用して、リソース需要を監視し、ポッドの数を自動的にスケーリングします。 既定では、HPA は、必要なレプリカ数の変更についてメトリック API を 15 秒ごとに確認します。メトリック API は、Kubelet からデータを 60 秒ごとに取得します。 つまり、HPA は 60 秒ごとに更新されます。 変更が必要な場合、それに応じてレプリカの数が増減されます。 HPA は、Kubernetes 1.8 以降用のメトリック サーバーをデプロイした AKS クラスターで動作します。https://learn.microsoft.com/ja-jp/azure/aks/concepts-scale#horizo%E2%80%8B%E2%80%8Bntal-pod-autoscalerKubernetes Event-driven Autoscaling (KEDA) は、アプリケーションの自動スケーリングをシンプルにすることを目指す単一目的の軽量コンポーネントであり、CNCF Graduated プロジェクトです。 イベント駆動型自動スケーリングを適用して、scale-to-zero で持続可能でコスト効率の高い方法で需要を満たすようにアプリケーションをスケーリングします。https://learn.microsoft.com/ja-jp/azure/aks/keda-about', '', ARRAY['azure-monitor','vmss','containers','azure-functions','messaging','event-driven','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Web アプリの複数のインスタンスを複数の Azure リージョンにデプロイすることを計画しています。 アプリのアクセス ソリューションを設計する必要があります。ソリューションは次のレプリケーション要件を満たしている必要があります。 解決策: Azure Traffic Manager を使用して、アプリへのアクセスを提供します。 これは目標を達成していますか。・ レート制限をサポートする。・ すべてのインスタンス間でリクエストのバランスをとる。・ 地域的に停電が発生した場合でも、ユーザーがアプリにアクセスできるようにする。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, 'Azure Traffic Manager は、DNS ベースのトラフィック ロード バランサーです。このサービスを使用すると、グローバル Azure リージョン全体でパブリック向けアプリケーションにトラフィックを分散できます。 Traffic Manager は、パブリック エンドポイントに高可用性と迅速な応答性も提供します。レート制限はありません。https://learn.microsoft.com/ja-jp/azure/app-service/web-sites-traffic-manager', '', ARRAY['bcdr-fundamentals','load-balancers','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Web アプリの複数のインスタンスを複数の Azure リージョンにデプロイすることを計画しています。 アプリのアクセス ソリューションを設計する必要があります。ソリューションは次のレプリケーション要件を満たしている必要があります。 解決策: Azure Load Balancer を使用して、アプリへのアクセスを提供します。 これは目標を達成していますか。・ レート制限をサポートする。・ すべてのインスタンス間でリクエストのバランスをとる。・ 地域的に停電が発生した場合でも、ユーザーがアプリにアクセスできるようにする。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, 'Azure Load Balancer はリージョン内でロード バランシングを行います (リージョンの停止はサポートされません)。一方で、Azure Load Balancer は、レートまたは接続の制限をサポートしていません。https://docs.microsoft.com/ja-jp/azure/architecture/guide/technology-choices/load-balancing-overview', '', ARRAY['bcdr-fundamentals','load-balancers','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'Azure Web アプリの複数のインスタンスを複数の Azure リージョンにデプロイすることを計画しています。 アプリのアクセス ソリューションを設計する必要があります。ソリューションは次のレプリケーション要件を満たしている必要があります。 解決策: Azure Application Gateway を使用して、アプリへのアクセスを提供します。 これは目標を達成していますか。・ レート制限をサポートする。・ すべてのインスタンス間でリクエストのバランスをとる。・ 地域的に停電が発生した場合でも、ユーザーがアプリにアクセスできるようにする。', '["はい", "いいえ"]'::jsonb, '1'::jsonb, 'Azure Application Gateway は、レートまたは接続の制限をサポートしていません。Azure Front Door は要件を満たします。 Azure Front Door の Azure Web アプリケーション ファイアウォール (WAF) レート制限ルールは、1 分間にクライアントから許可される要求の数を制御します。https://learn.microsoft.com/ja-jp/azure/application-gateway/overviewhttps://learn.microsoft.com/ja-jp/azure/web-application-firewall/afds/waf-front-door-rate-limit-configure?pivots=portal', '', ARRAY['bcdr-fundamentals','load-balancers','app-service','network-security'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'App1 という名前の Web アプリをオンプレミスのデータセンターから Azure に移動する予定です。 App1 は、ホスト サーバーにインストールされているカスタム COM コンポーネントに依存します。 Azure で App1 をホストするソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。・ Azure データセンターが利用できなくなった場合、ユーザーは App1 を利用できる必要がある。・ コストは最小限に抑える必要がある。', '["2 つの Azure リージョンに、ロード バランサーと仮想マシン スケール セットをデプロイする。", "2 つの Azure リージョンに、Azure Traffic Manager プロファイルと Web Appをデプロイする。", "2 つの Azure リージョンに、ロード バランサーと Web Appをデプロイする。", "ロード バランサーと仮想マシン スケール セットを 2 つの可用性ゾーンにデプロイする。"]'::jsonb, '3'::jsonb, 'Azure App Service では COM コンポーネントが許可されないため、仮想マシンを使用する必要があります。Azure データセンターの障害から保護するには 2 つの可用性ゾーンが必要です。Web Appは使用できません。Azure App Service では、プラットフォーム上で COM コンポーネントを登録することはできません。 アプリで COM コンポーネントを使用する場合は、それらのコンポーネントをマネージド コードで書き換えて、サイトまたはアプリケーショントと共にデプロイする必要があります。https://learn.microsoft.com/ja-jp/dotnet/azure/migration/app-service#com-and-com-components', '', ARRAY['availability-zones','load-balancers','virtual-machines','app-service'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ビジネスに重要なデータを保存する新しいアプリを開発する予定です。アプリは次の要件を満たす必要があります。 アプリにはどのようなストレージ ソリューションを推奨しますか。 ストレージ アカウントの種類:・ 1 年間は新しいデータが変更されないようにする。・ データの復元力を最大化する。・ 読み取り遅延を最小限に抑える。', '["Standard 汎用 v1", "Premium ブロックBLOB", "Standard 汎用 v2"]'::jsonb, '1'::jsonb, '読み取り遅延を最小限に抑えるには、Premium ブロック BLOB が正解です。Premium レベルでは、不変ストレージもサポートされています。https://docs.microsoft.com/ja-jp/azure/storage/blobs/immutable-storage-overview#supported-account-configurations', '', ARRAY['resource-locks','azure-storage','blob-storage'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'ビジネスに重要なデータを保存する新しいアプリを開発する予定です。アプリは次の要件を満たす必要があります。 アプリにはどのようなストレージ ソリューションを推奨しますか。 冗長性:・ 1 年間は新しいデータが変更されないようにする。・ データの復元力を最大化する。・ 読み取り遅延を最小限に抑える。', '["ローカル冗長ストレージ (LRS)", "ゾーン冗長ストレージ (ZRS)"]'::jsonb, '1'::jsonb, 'ローカル冗長ストレージ (LRS) は、プライマリ リージョンの 1 つの物理的な場所内で、データを同期的に 3 回コピーします。 LRS は最もコストのかからないレプリケーション オプションですが、高可用性または持続性を必要とするアプリケーションには推奨されません。 ゾーン冗長ストレージ (ZRS) は、プライマリ リージョンの 3 つの Azure 可用性ゾーン間でデータを同期的にコピーします。 高可用性を必要とするアプリケーションでは、プライマリ リージョンで ZRS を使用し、セカンダリ リージョンにもレプリケートすることをお勧めします。https://learn.microsoft.com/ja-jp/azure/storage/common/storage-redundancy', '', ARRAY['entra-connect','azure-storage','bcdr-fundamentals','availability-zones'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の表に示すリソースがあります。 Azure に RG2 という名前の新しいリソース グループを作成します。 仮想マシンを RG2 に移動する必要があります。 各仮想マシンを移動するには何を使用する必要がありますか。 VM1:名前 | タイプ | リソースグループ-----------------------------------------------VM1 | Azure 仮想マシン | RG1VM2 | オンプレミスの仮想マシン | 未適用', '["The Data Migration Assistant (DMA)", "Azure Migrate", "Azure Arc", "Azure Lighthouse", "Azure Resource Mover"]'::jsonb, '4'::jsonb, 'Azure Resource MoverAzure VM を別のリージョンに移動するには、Microsoft は Azure Resource Mover の使用を推奨しています。リージョン間でリソースを移動するには、移動するリソースを選択します。 Resource Mover はこれらのリソースを検証し、他のリソースに対する依存関係を解決します。https://docs.microsoft.com/ja-jp/azure/resource-mover/overview', '', ARRAY['lighthouse','virtual-machines','data-migration','db-migration'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', '次の表に示すリソースがあります。 Azure に RG2 という名前の新しいリソース グループを作成します。 仮想マシンを RG2 に移動する必要があります。 各仮想マシンを移動するには何を使用する必要がありますか。 VM2:名前 | タイプ | リソースグループ-----------------------------------------------VM1 | Azure 仮想マシン | RG1VM2 | オンプレミスの仮想マシン | 未適用', '["The Data Migration Assistant (DMA)", "Azure Migrate", "Azure Arc", "Azure Lighthouse", "Azure Resource Mover"]'::jsonb, '1'::jsonb, 'Azure MigrateAzure Migrate では、Azure に簡単な移行、最新化、最適化のサービスが提供されます。 インフラストラクチャ、データ、アプリケーションに対して、オンプレミス リソースの検出、評価、適切なサイズ設定など、移行前のすべての手順が含まれています。 Azure Migrate の拡張可能なフレームワークを使用すると、サード パーティ製ツールを統合できるため、サポートされるユース ケースの範囲が広がります。Azure Arc: Azure Migrate で十分です。 Azure Arc を使用する必要はありません。Data Migration Assistant: Data Migration Assistant は、SQL Server を評価するためのスタンドアロン ツールです。Azure Lighthouse: Azure Lighthouse では、スケーラビリティ、高度な自動化、およびリソース全体にわたる強化されたガバナンスを備えたマルチテナント管理が可能になります。https://learn.microsoft.com/ja-jp/azure/migrate/migrate-services-overview', '', ARRAY['entra-id','lighthouse','virtual-machines','automation-deploy','data-migration','db-migration'], true, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure Linux 仮想マシンを使用してビデオ ファイルを分析するアプリケーションを設計しています。 ファイルは、ExpressRoute を使用して Azure に接続する企業オフィスからアップロードされます。 ファイルをホストするために Azure ストレージ アカウントをプロビジョニングする予定です。 ストレージ アカウントが次の要件を満たしていることを確認する必要があります。 ストレージ アカウントはどのように構成すればよいでしょうか。 ストレージ アカウント タイプ:・ 最大 7 TB のビデオ ファイルをサポートする・ 可能な限り最高の可用性を提供する・ ストレージが大きなビデオ ファイル用に最適化されていることを確認する・ ExpressRoute を使用してオンプレミス ネットワークからのファイルが確実にアップロードされるようにする', '["Premium ページ BLOB", "Premium ファイル共有", "Standard 汎用 v2"]'::jsonb, '2'::jsonb, 'https://learn.microsoft.com/ja-jp/azure/storage/blobs/storage-blobs-introduction#blobs', '', ARRAY['azure-storage','virtual-machines','on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure Linux 仮想マシンを使用してビデオ ファイルを分析するアプリケーションを設計しています。 ファイルは、ExpressRoute を使用して Azure に接続する企業オフィスからアップロードされます。 ファイルをホストするために Azure ストレージ アカウントをプロビジョニングする予定です。 ストレージ アカウントが次の要件を満たしていることを確認する必要があります。 ストレージ アカウントはどのように構成すればよいでしょうか。 データの冗長性:・ 最大 7 TB のビデオ ファイルをサポートする・ 可能な限り最高の可用性を提供する・ ストレージが大きなビデオ ファイル用に最適化されていることを確認する・ ExpressRoute を使用してオンプレミス ネットワークからのファイルが確実にアップロードされるようにする', '["ローカル冗長ストレージ (LRS)", "Geo 冗長ストレージ (GRS)", "ゾーン冗長ストレージ (ZRS)"]'::jsonb, '1'::jsonb, 'GRS は、LRS または ZRS と比較して、データ ストレージに追加の冗長性を提供します。また、可能な限り最高の可用性を実現します。https://learn.microsoft.com/ja-jp/azure/storage/common/storage-redundancy', '', ARRAY['azure-storage','virtual-machines','on-premises-connectivity'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure Linux 仮想マシンを使用してビデオ ファイルを分析するアプリケーションを設計しています。 ファイルは、ExpressRoute を使用して Azure に接続する企業オフィスからアップロードされます。 ファイルをホストするために Azure ストレージ アカウントをプロビジョニングする予定です。 ストレージ アカウントが次の要件を満たしていることを確認する必要があります。 ストレージ アカウントはどのように構成すればよいでしょうか。 ネットワーキング:・ 最大 7 TB のビデオ ファイルをサポートする・ 可能な限り最高の可用性を提供する・ ストレージが大きなビデオ ファイル用に最適化されていることを確認する・ ExpressRoute を使用してオンプレミス ネットワークからのファイルが確実にアップロードされるようにする', '["サービスエンドポイント", "Azure Route Server", "プライベートエンドポイント"]'::jsonb, '2'::jsonb, 'ExpressRoute は、インターネットをバイパスして、Azure ネットワークに直接接続します。よって、プライベートエンドポイントが正答となります。Azure Private Link を使用すると、プライベート エンドポイントを使用して Azure PaaS サービスを仮想ネットワークに安全に接続できます。 多くのサービスでは、リソースごとにエンドポイントを設定するだけです。 つまり、オンプレミスまたはマルチクラウド サーバーを Azure Arc に接続し、パブリック ネットワークを使用する代わりに、Azure ExpressRoute またはサイト間 VPN 接続経由ですべてのトラフィックを送信できます。https://learn.microsoft.com/ja-jp/azure/azure-arc/servers/private-link-security', '', ARRAY['azure-storage','virtual-machines','vnet','on-premises-connectivity','private-link'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'あなたは、Azure サブスクリプションを持っています。 開発者に Azure 仮想マシンをプロビジョニングできる機能を提供するソリューションを推奨する必要があります。ソリューションは次の要件を満たす必要があります。 推奨事項には何を含めるべきですか。・ 特定のリージョンでのみ仮想マシンの作成を許可する。・ 特定のサイズの仮想マシンの作成のみを許可する。', '["Azure Policy", "Azure Resource Manager テンプレート", "ロールベースのアクセス制御 (RBAC)", "条件付きアクセス ポリシー"]'::jsonb, '0'::jsonb, 'Azure Policyを使用すると、許可される場所と許可される VM SKU を指定できます。https://learn.microsoft.com/ja-jp/azure/governance/policy/tutorials/create-and-manage', '', ARRAY['rbac','conditional-access','subscription-design','azure-policy','virtual-machines'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AG1 という名前の Always On 可用性グループをホストするオンプレミスの Microsoft SQL Server 2017 インスタンスが 2 つあります。 AG1 には、DB1 という名前の単一データベースが含まれています。 VM1 という名前の仮想マシンを含む Azure サブスクリプションがあります。 VM1 は Linux を実行し、SQL Server 2019 インスタンスが含まれています。 DB1 を VM1 に移行する必要があります。ソリューションでは、DB1 のダウンタイムを最小限に抑える必要があります。 マイグレーションの準備をするとき、あなたは次のうちどれを使用しますか。', '["オンプレミスの SQL Server インスタンスのアップグレード", "AG1 へのセカンダリ レプリカの追加", "VM1 での Always On 可用性グループの作成"]'::jsonb, '1'::jsonb, '次の手順で移行の準備をします。セカンダリ レプリカを AG1 に追加するオンプレミスの SQL Server インスタンスには可用性グループ (AG1) がすでに存在しているため、VM1 に Always On 可用性グループを作成する必要はありません。セカンダリ レプリカを AG1 に追加すると、移行に使用できる DB1 のコピーを提供できます。これにより、プライマリ レプリカを使用可能な状態のままでセカンダリ レプリカで移行を実行することにより、DB1 のダウンタイムを最小限に抑えることができます。', '', ARRAY['subscription-design','sql-ha','virtual-machines','data-migration'], false, 'website');
INSERT INTO public.questions (exam, question, choices, answer, explanation, category, tags, is_free, source) VALUES ('az-305', 'AG1 という名前の Always On 可用性グループをホストするオンプレミスの Microsoft SQL Server 2017 インスタンスが 2 つあります。 AG1 には、DB1 という名前の単一データベースが含まれています。 VM1 という名前の仮想マシンを含む Azure サブスクリプションがあります。 VM1 は Linux を実行し、SQL Server 2019 インスタンスが含まれています。 DB1 を VM1 に移行する必要があります。ソリューションでは、DB1 のダウンタイムを最小限に抑える必要があります。 マイクレーションを実行するとき、あなたは次のうちどれを使用しますか。', '["ログ 配布", "Azure Migrate", "分散型可用性グループ"]'::jsonb, '1'::jsonb, 'オンプレミス SQL サーバーをアップグレードし、Azure Migrate を使用します。', '', ARRAY['subscription-design','sql-ha','virtual-machines','data-migration'], false, 'website');